window.NATURO_DYS.qcmExtra = {"dys-hta":[{"q":"Pourquoi qualifie-t-on souvent l'HTA de « tueur silencieux » ?","options":["Parce qu'elle provoque une mort subite dès le diagnostic","Parce qu'elle est le plus souvent asymptomatique","Parce qu'elle ne se mesure pas","Parce qu'elle ne touche que les personnes âgées"],"explication":"L'HTA est le plus souvent asymptomatique, d'où l'image du « tueur silencieux » : elle progresse sans signe d'alerte tout en augmentant le risque cardiovasculaire.","niveau":1,"bonne":1,"mnemo":"Silencieuse = sans symptôme."},{"q":"Quel type d'HTA, sans cause précise identifiée, est le plus fréquent ?","options":["HTA secondaire","HTA gravidique","HTA essentielle","HTA maligne"],"explication":"L'HTA est le plus souvent essentielle, c'est-à-dire sans cause précise identifiée.","niveau":1,"bonne":2,"mnemo":"Essentielle = sans cause connue."},{"q":"Quel aliment est cité comme source de potassium favorable en cas d'HTA ?","options":["Le fromage","La banane","La charcuterie","Le pain blanc"],"explication":"La banane (comme le pruneau, l'avocat, la pomme de terre) est riche en potassium, recommandé dans l'HTA.","niveau":2,"bonne":1,"mnemo":"Banane = potassium."},{"q":"Quel rythme d'activité physique est conseillé en cas d'HTA ?","options":["Effort intense quotidien","Activité modérée, 30 min/j ou 4×/semaine","Aucune activité, repos strict","Sport de compétition"],"explication":"On recommande une activité physique modérée, environ 30 min par jour ou 4 fois par semaine.","niveau":2,"bonne":1,"mnemo":"Modéré, régulier."},{"q":"Un patient passe d'une systolique à 150 mm Hg vers 85 mm Hg avec vertiges au lever. Quelle attitude naturopathique correspond à ce nouvel état ?","options":["Continuer à drainer et relâcher","Stimuler les surrénales (cassis, réglisse, plantes à caféine)","Augmenter encore les diurétiques","Réduire le potassium"],"explication":"À 85 mm Hg de systolique on est en hypotension : on stimule les surrénales (cassis, réglisse, plantes à caféine), à l'inverse de l'HTA où l'on draine/relâche.","niveau":3,"bonne":1,"mnemo":"HTA on draine ; hypotension on stimule."}],"dys-hemorroides":[{"q":"Quelle est la différence entre hémorroïdes internes et externes ?","options":["Les internes saignent toujours, pas les externes","Les internes sont non visibles, les externes sont à l'orifice anal et plus sensibles","Les externes sont indolores","Les internes touchent l'intestin grêle"],"explication":"Les hémorroïdes internes ne sont pas visibles, les externes siègent à l'orifice anal et sont plus sensibles.","niveau":1,"bonne":1,"mnemo":"Externes = visibles et sensibles."},{"q":"Quelle complication peut survenir avec les hémorroïdes ?","options":["Thrombose hémorroïdaire","Infarctus du myocarde","Calcul rénal","Anémie pernicieuse"],"explication":"La thrombose hémorroïdaire est une complication citée des hémorroïdes.","niveau":1,"bonne":0,"mnemo":"Caillot dans l'hémorroïde = thrombose."},{"q":"Pourquoi conseille-t-on un rehausseur sous les pieds aux toilettes en cas d'hémorroïdes ?","options":["Pour forcer davantage","Pour adopter une position physiologique et ne pas forcer","Pour aller plus vite","Pour rester debout"],"explication":"Le rehausseur favorise une position physiologique de défécation, ce qui évite de forcer (recommandé avec « aller à la selle régulièrement, ne pas forcer »).","niveau":2,"bonne":1,"mnemo":"Pieds surélevés = position physio."},{"q":"Quel bourgeon de gemmothérapie est associé à la circulation veineuse et aux œdèmes dans les hémorroïdes ?","options":["Cassis","Châtaignier","Figuier","Bouleau"],"explication":"Le châtaignier est cité pour la circulation veineuse et les œdèmes.","niveau":2,"bonne":1,"mnemo":"Châtaignier = veines + œdèmes."},{"q":"Pourquoi les hémorroïdes récidivent-elles si l'on ne traite que localement ?","options":["Parce qu'elles sont génétiques et incurables","Parce qu'il faut drainer le foie et corriger la constipation en amont","Parce qu'il faut supprimer les fibres","Parce qu'elles sont d'origine artérielle"],"explication":"Les causes amont (foie engorgé via le système porte et constipation) doivent être corrigées, sinon les hémorroïdes récidivent.","niveau":3,"bonne":1,"mnemo":"Amont = foie + constipation."}],"dys-anemie":[{"q":"Que transporte mal le sang en cas d'anémie ?","options":["Le glucose","L'oxygène","Le sodium","Le cholestérol"],"explication":"L'anémie réduit la capacité des globules rouges à apporter suffisamment d'oxygène (baisse d'hémoglobine et/ou du nombre de globules rouges).","niveau":1,"bonne":1,"mnemo":"Anémie = O2 mal transporté."},{"q":"Quel signe est typique de l'anémie ?","options":["Rougeur du visage","Pâleur et essoufflement","Hypertension","Fièvre élevée"],"explication":"Pâleur, essoufflement, fatigue persistante et mains/pieds froids sont des signes typiques.","niveau":1,"bonne":1,"mnemo":"Pâle, essoufflé, mains froides."},{"q":"Quelle plante est citée pour sa richesse en fer dans l'anémie ?","options":["La canneberge","L'ortie (feuilles)","L'aubépine","Le pissenlit"],"explication":"Les feuilles d'ortie sont riches en fer.","niveau":2,"bonne":1,"mnemo":"Ortie = fer."},{"q":"Quelle anémie est liée à un déficit en érythropoïétine ?","options":["L'anémie thalassémique","L'anémie d'insuffisance rénale","L'anémie hémolytique","L'anémie mégaloblastique"],"explication":"L'insuffisance rénale entraîne un déficit en érythropoïétine, hormone stimulant la production de globules rouges.","niveau":2,"bonne":1,"mnemo":"Rein → érythropoïétine."},{"q":"Concernant les compléments dans l'anémie ferriprive, quelle association faut-il éviter selon la fiche ?","options":["Fer + acide lactique","Fer + vitamine C","Fer + B12","Fer + acide folique"],"explication":"La fiche précise « ne pas combiner fer + C » dans les micronutriments (argousier, acérola).","niveau":3,"bonne":1,"mnemo":"Pas fer + C ensemble (ici)."}],"dys-atherosclerose":[{"q":"Que désigne l'artériosclérose ?","options":["Un dépôt de plaque dans l'intima","Un épaississement et une perte d'élasticité de la paroi artérielle","Une dilatation des veines","Une infection de l'artère"],"explication":"L'artériosclérose est l'épaississement et la perte d'élasticité de la paroi artérielle.","niveau":1,"bonne":1,"mnemo":"Sclérose = paroi qui durcit."},{"q":"Dans quelle couche de l'artère se dépose la plaque d'athérome ?","options":["L'adventice","La média","L'intima","Le péricarde"],"explication":"La plaque d'athérome se dépose dans l'intima.","niveau":2,"bonne":2,"mnemo":"Athérome dans l'intima."},{"q":"Quel rôle est attribué aux antioxydants dans l'athérosclérose ?","options":["Augmenter le cholestérol","Protéger le LDL","Fluidifier les veines","Stimuler les surrénales"],"explication":"Les antioxydants protègent le LDL (de l'oxydation), d'où leur intérêt alimentaire.","niveau":2,"bonne":1,"mnemo":"Antioxydants protègent le LDL."},{"q":"Quel régime alimentaire est recommandé dans l'athérosclérose ?","options":["Régime hyperprotéiné","Régime méditerranéen/crétois","Régime sans fibres","Régime riche en oméga 6"],"explication":"Le régime méditerranéen/crétois est conseillé, avec oméga 3, antioxydants et fibres ; on réduit graisses saturées, trans et oméga 6.","niveau":1,"bonne":1,"mnemo":"Méditerranéen = protecteur."},{"q":"Un patient confond artériosclérose et athérosclérose. Quelle distinction est correcte ?","options":["Toutes deux désignent un dépôt de plaque","Artériosclérose = durcissement de la paroi ; athérosclérose = dépôt de plaque dans l'intima","Artériosclérose touche les veines, athérosclérose les artères","Athérosclérose = perte d'élasticité sans plaque"],"explication":"Deux mécanismes distincts : artériosclérose = durcissement/perte d'élasticité de la paroi ; athérosclérose = dépôt de plaque d'athérome dans l'intima.","niveau":3,"bonne":1,"mnemo":"Sclérose durcit ; athérome bouche."}],"dys-arterite":[{"q":"Quels vaisseaux sont touchés par l'artérite ?","options":["Les artères des membres inférieurs","Les veines des bras","Les capillaires du visage","Les artères coronaires uniquement"],"explication":"L'artérite est une obstruction des artères des membres inférieurs par athérosclérose.","niveau":1,"bonne":0,"mnemo":"Artérite = artères des jambes."},{"q":"Quel mécanisme provoque les douleurs dans l'artérite ?","options":["Une stase veineuse","Une ischémie par obstruction artérielle","Une infection bactérienne","Une carence en fer"],"explication":"L'obstruction des artères provoque une ischémie (manque d'apport sanguin) responsable des douleurs.","niveau":2,"bonne":1,"mnemo":"Artère bouchée = ischémie."},{"q":"Quel signe accompagne fréquemment l'artérite ?","options":["Diminution des pouls et refroidissement","Rougeur et chaleur des jambes","Fièvre élevée","Jet urinaire faible"],"explication":"Pâleur, refroidissement et diminution des pouls accompagnent l'artérite.","niveau":1,"bonne":0,"mnemo":"Pouls faibles, jambes froides."},{"q":"Que comportent les stades avancés de l'artérite ?","options":["Jambes lourdes le soir uniquement","Douleurs de décubitus et troubles trophiques (ulcères, gangrène)","Hémorroïdes","Hypotension postprandiale"],"explication":"Aux stades avancés apparaissent douleurs de décubitus et troubles trophiques (ulcères, gangrène).","niveau":2,"bonne":1,"mnemo":"Avancé = décubitus + nécrose."},{"q":"Comment distinguer une artérite d'une insuffisance veineuse ?","options":["L'artérite donne des jambes lourdes au repos, la veineuse une douleur à la marche","L'artérite = douleur à la marche soulagée par le repos (artère) ; la veineuse = jambes lourdes (retour veineux)","Ce sont deux noms de la même atteinte","La veineuse touche les artères, l'artérite les veines"],"explication":"Artérite : artères des membres inférieurs, douleur à la marche soulagée par le repos. Insuffisance veineuse : retour veineux, jambes lourdes. Artère bouchée ≠ veine engorgée.","niveau":3,"bonne":1,"mnemo":"Marche douloureuse = artère."}],"dys-hypotension":[{"q":"Quelle valeur de systolique définit l'hypotension ?","options":["<90-100 mm Hg","<140 mm Hg","<160 mm Hg","<120 mm Hg"],"explication":"L'hypotension correspond à une systolique <90-100 mm Hg (ou diastolique <50-60 mm Hg).","niveau":1,"bonne":0,"mnemo":"Systolique < 90-100."},{"q":"Quel symptôme est typique de l'hypotension au lever ?","options":["Maux de tête battants","Étourdissements et vertiges","Hypertension","Fièvre"],"explication":"Fatigue, faiblesse, étourdissements, vertiges, voire syncope sont typiques.","niveau":1,"bonne":1,"mnemo":"Je me lève, je tourne."},{"q":"Quel conseil alimentaire est adapté à l'hypotension ?","options":["Réduire le sodium","Alimentation légèrement plus riche en protéines et en sodium","Supprimer toute boisson","Régime hypocalorique strict"],"explication":"On conseille de boire suffisamment, d'éviter l'alcool et une alimentation légèrement plus riche en protéines et en sodium.","niveau":2,"bonne":1,"mnemo":"Hypotension = un peu plus de sel."},{"q":"Quelle catégorie de plantes est conseillée pour remonter la tension ?","options":["Diurétiques","Plantes à caféine (guarana, maté, thé vert)","Veinotoniques","Carminatives"],"explication":"Les plantes hypertensives à caféine (guarana, maté, thé vert, café, cacaoyer) sont conseillées.","niveau":2,"bonne":1,"mnemo":"Caféine remonte la tension."},{"q":"Une personne a des vertiges surtout après les repas, pas au changement de position. De quelle forme s'agit-il ?","options":["Hypotension orthostatique","Hypotension postprandiale","HTA essentielle","Hypotension maligne"],"explication":"Les déclencheurs diffèrent : orthostatique = changement de position, postprandiale = après le repas.","niveau":3,"bonne":1,"mnemo":"Postprandial = après le repas."}],"dys-insuffisance-veineuse":[{"q":"L'insuffisance veineuse correspond à un trouble de quoi ?","options":["Du retour veineux/lymphatique vers le cœur","De l'apport artériel aux jambes","De la filtration rénale","Du transit intestinal"],"explication":"C'est une insuffisance veino-lymphatique : trouble du retour veineux/lymphatique vers le cœur.","niveau":1,"bonne":0,"mnemo":"Retour vers le cœur défaillant."},{"q":"Quel symptôme évoque l'insuffisance veineuse ?","options":["Jambes lourdes et œdème de la cheville","Claudication à la marche","Jet urinaire faible","Douleur à l'épaule droite"],"explication":"Jambes lourdes, gonflées, fourmillements, crampes et œdème de la cheville sont caractéristiques.","niveau":1,"bonne":0,"mnemo":"Jambes lourdes = veines."},{"q":"Quelles plantes riches en silice sont citées dans l'insuffisance veineuse ?","options":["Ail et olivier","Ortie et prêle","Tilleul et sureau","Canneberge et busserole"],"explication":"L'ortie et la prêle sont citées comme plantes riches en silice.","niveau":2,"bonne":1,"mnemo":"Silice = ortie + prêle."},{"q":"Outre les veinotoniques, quel organe est conseillé de drainer dans l'insuffisance veineuse ?","options":["Le rein","Le foie","Le pancréas","La rate"],"explication":"La fiche recommande de drainer le foie (blocage hépatique parmi les causes).","niveau":2,"bonne":1,"mnemo":"Drainer le foie aussi."},{"q":"Quelle distinction de gravité la fiche souligne-t-elle ?","options":["Varice vs hémorroïde","Para-phlébite (caillot superficiel) vs phlébite (caillot profond → risque d'embolie)","Œdème vs eczéma","Saphène interne vs externe"],"explication":"Para-phlébite = caillot superficiel ; phlébite = caillot profond avec risque d'embolie : la profondeur change la gravité.","niveau":3,"bonne":1,"mnemo":"Profond = phlébite = embolie."}],"dys-palpitations":[{"q":"À partir de quelle fréquence parle-t-on de tachycardie ?","options":[">100/min",">60/min",">80/min",">200/min"],"explication":"Tachycardie = fréquence >100/min (bradycardie <60/min).","niveau":1,"bonne":0,"mnemo":"Tachy > 100."},{"q":"Que sont les extrasystoles ?","options":["Un ralentissement du cœur","Des battements supplémentaires","Un arrêt cardiaque","Une dilatation des veines"],"explication":"Les extrasystoles sont des battements supplémentaires.","niveau":1,"bonne":1,"mnemo":"Extra = en plus."},{"q":"Quelle plante est indiquée pour une tachycardie associée à une hypotension ?","options":["Aubépine","Romarin","Agripaume","Valériane"],"explication":"Le romarin est cité pour la tachycardie avec hypotension (l'aubépine étant plutôt pour les troubles du rythme avec HTA).","niveau":2,"bonne":1,"mnemo":"Romarin = tachy + hypotension."},{"q":"Quel micronutriment est cité comme complément dans les troubles du rythme ?","options":["Le fer","Le magnésium","Le zinc","La vitamine B12"],"explication":"Le magnésium est le micronutriment cité.","niveau":2,"bonne":1,"mnemo":"Rythme = magnésium."},{"q":"Quelle est la différence entre flutter et fibrillation ?","options":["Le flutter est désordonné, la fibrillation régulière","Le flutter est rapide mais régulier ; la fibrillation est désordonnée et inefficace","Le flutter est un ralentissement","Ils sont synonymes"],"explication":"Flutter = contractions rapides mais régulières (200-300/min) ; fibrillation = contractions désordonnées et inefficaces.","niveau":3,"bonne":1,"mnemo":"Flutter régulier ; fibrillation chaos."}],"dys-hbp":[{"q":"Quel mécanisme explique les troubles mictionnels de l'HBP ?","options":["Une infection de la vessie","La prostate hypertrophiée comprime l'urètre","Un calcul rénal","Une carence en fer"],"explication":"L'hypertrophie bénigne de la prostate comprime l'urètre, d'où les troubles mictionnels.","niveau":1,"bonne":1,"mnemo":"Prostate gonflée comprime l'urètre."},{"q":"Que signifie la nycturie, symptôme de l'HBP ?","options":["Besoin d'uriner la nuit","Présence de sang dans les urines","Absence d'urine","Brûlure mictionnelle"],"explication":"La nycturie (besoin d'uriner la nuit) fait partie des troubles mictionnels de l'HBP.","niveau":2,"bonne":0,"mnemo":"Nyct = nuit."},{"q":"Quelle plante est conseillée dans l'HBP ?","options":["Canneberge","Sabal serrulata","Aubépine","Tilleul"],"explication":"Le Sabal serrulata (comme Pygeum, épilobe, racines d'ortie, graines de courge) est conseillé dans l'HBP.","niveau":1,"bonne":1,"mnemo":"Sabal = prostate."},{"q":"Quelle classe de médicaments agit en inhibant la 5-alpha réductase dans l'HBP ?","options":["Les alpha-bloquants (tamsulosine)","Le finastéride","Les antibiotiques","Les diurétiques"],"explication":"Le finastéride est un inhibiteur de la 5-alpha réductase ; les alpha-bloquants (alfuzosine, tamsulosine) sont une autre classe.","niveau":2,"bonne":1,"mnemo":"Finastéride = 5-alpha réductase."},{"q":"À quoi l'hypertrophie bénigne de la prostate ne doit-elle PAS être confondue ?","options":["À une cystite de la femme","À une prostatite (infection) ou un cancer","À une lithiase biliaire","À une insuffisance veineuse"],"explication":"L'HBP est bénigne et à distinguer d'une prostatite (infection) ou d'un cancer.","niveau":3,"bonne":1,"mnemo":"Bénigne ≠ infection ≠ cancer."}],"dys-cystite":[{"q":"Quel organe est enflammé dans la cystite ?","options":["Le rein","La vessie","L'urètre seul","La prostate"],"explication":"La cystite est une inflammation de la vessie, avec ou sans bactérie.","niveau":1,"bonne":1,"mnemo":"Cystite = vessie."},{"q":"Quelle bactérie est le plus souvent en cause dans la cystite infectieuse ?","options":["E. coli","Le staphylocoque doré","Le streptocoque A","Helicobacter pylori"],"explication":"E. coli est la bactérie citée dans la cystite.","niveau":1,"bonne":0,"mnemo":"Cystite = E. coli."},{"q":"Pourquoi les femmes sont-elles plus sujettes à la cystite ?","options":["Urètre court","Vessie plus grande","Reins plus fragiles","Prostate enflammée"],"explication":"Le sexe féminin est un facteur car l'urètre est court (les bactéries atteignent plus vite la vessie).","niveau":2,"bonne":0,"mnemo":"Urètre court = plus de cystites."},{"q":"Dans une cystite de forme infectieuse, quel aliment supprimer en priorité car il nourrit E. coli ?","options":["Le sel","Le sucre","Les fibres","Les protéines"],"explication":"En forme infectieuse on supprime le sucre en priorité car il nourrit E. coli.","niveau":2,"bonne":1,"mnemo":"Sucre nourrit E. coli."},{"q":"Comment distinguer une cystite d'une pyélonéphrite ?","options":["La cystite donne une fièvre élevée, pas la pyélonéphrite","La cystite = vessie (avec ou sans bactérie) ; la pyélonéphrite = infection du rein avec fièvre élevée","Ce sont deux noms du même trouble","La cystite touche le rein"],"explication":"Cystite = inflammation de la vessie (50% à urine claire) ; pyélonéphrite = infection du rein avec fièvre élevée.","niveau":3,"bonne":1,"mnemo":"Fièvre élevée = rein (pyélonéphrite)."}],"dys-infection-urinaire":[{"q":"Comment le cours traite-t-il l'« infection urinaire » ?","options":["Comme une maladie distincte très détaillée","Comme un thème général recoupant cystite et pyélonéphrite","Comme une forme de lithiase","Comme un trouble cardiaque"],"explication":"Le document traite l'infection urinaire comme un thème général dont le contenu recoupe celui de la cystite et de la pyélonéphrite.","niveau":1,"bonne":1,"mnemo":"Thème parapluie."},{"q":"À quelles deux atteintes l'infection urinaire est-elle apparentée dans le cours ?","options":["Cystite et pyélonéphrite","HTA et hypotension","Lithiase et HBP","Anémie et fièvre"],"explication":"Le contenu est très similaire à la cystite (vessie) et à la pyélonéphrite (rein).","niveau":1,"bonne":0,"mnemo":"Vessie + rein."},{"q":"Selon la localisation, à quoi faut-il se rapporter pour une infection urinaire ?","options":["À la cystite (vessie) ou la pyélonéphrite (rein)","À l'HBP uniquement","À la lithiase biliaire","À l'artérite"],"explication":"C'est un terme générique : on se rapporte à la cystite (vessie) ou à la pyélonéphrite (rein) selon la localisation.","niveau":2,"bonne":0,"mnemo":"Localisation = vessie ou rein."},{"q":"Que peut-on dire du niveau de détail propre à la fiche « infection urinaire » ?","options":["Elle détaille une étiologie spécifique","Elle est mentionnée brièvement, sans symptômes ni étiologie propres","Elle liste de nombreuses plantes dédiées","Elle décrit un traitement chirurgical"],"explication":"La fiche est un thème général mentionné brièvement, sans symptômes, étiologie ni compléments propres.","niveau":2,"bonne":1,"mnemo":"Fiche brève, renvoie ailleurs."},{"q":"Un patient a une fièvre élevée avec atteinte urinaire. Vers quelle entité du « parapluie » infection urinaire s'oriente-t-on ?","options":["La cystite","La pyélonéphrite","L'HBP","La lithiase biliaire"],"explication":"Une fièvre élevée oriente vers le rein, donc la pyélonéphrite, au sein du thème général « infection urinaire ».","niveau":3,"bonne":1,"mnemo":"Fièvre = rein = pyélonéphrite."}],"dys-libido":[{"q":"Que désigne un trouble de la libido ?","options":["Une baisse du désir sexuel ou une panne","Une infection urinaire","Une hypertension","Un calcul biliaire"],"explication":"C'est une baisse du désir sexuel ou une panne, passagère ou prolongée.","niveau":1,"bonne":0,"mnemo":"Désir en panne."},{"q":"Quelle plante adaptogène est citée dans les troubles de la libido ?","options":["Maca","Canneberge","Aubépine","Busserole"],"explication":"La maca (comme le tribulus et le ginseng) est citée parmi les plantes pour la libido.","niveau":1,"bonne":0,"mnemo":"Maca = libido."},{"q":"Quel type d'exercice est conseillé pour la libido ?","options":["Course de fond intensive","Travail du périnée (Kegel, Pilates)","Aucun exercice","Musculation lourde uniquement"],"explication":"On conseille un exercice régulier ciblant le périnée (Kegel, Pilates) et l'image de soi.","niveau":2,"bonne":1,"mnemo":"Périnée = Kegel."},{"q":"Quelle contre-indication est associée au Viagra® dans la fiche ?","options":["Insuffisance rénale","Contre-indications cardiovasculaires, nitrés, AVC, insuffisance hépatique","Allergie au gluten","Diabète léger"],"explication":"Le Viagra® comporte des contre-indications cardiovasculaires, avec les nitrés, en cas d'AVC et d'insuffisance hépatique.","niveau":2,"bonne":1,"mnemo":"Viagra + nitrés = danger."},{"q":"Pourquoi la fiche insiste-t-elle sur l'iatrogénie dans les troubles de la libido ?","options":["Parce que c'est uniquement hormonal","Parce que des médicaments (antidépresseurs, statines, pilule) peuvent diminuer la libido","Parce que la cause est toujours psychologique","Parce que l'âge n'a aucun rôle"],"explication":"Le trouble est multifactoriel ; il faut penser à l'iatrogénie : antidépresseurs, neuroleptiques, antihypertenseurs, statines, pilule peuvent diminuer la libido.","niveau":3,"bonne":1,"mnemo":"Vérifier les médicaments."}],"dys-lithiase":[{"q":"De quoi sont composés les calculs biliaires ?","options":["Cholestérol, sels de bilirubine, calcium","Fer et potassium","Acide urique seul","Plaque d'athérome"],"explication":"Les calculs biliaires sont faits de cholestérol, de sels de bilirubine et de calcium.","niveau":1,"bonne":0,"mnemo":"Cholestérol + bilirubine + calcium."},{"q":"Vers quoi irradie typiquement la douleur d'une colique biliaire ?","options":["Vers l'épaule/omoplate droite","Vers le bras gauche","Vers les lombaires","Vers le bas-ventre"],"explication":"La douleur de l'hypochondre droit irradie vers l'épaule/omoplate droite.","niveau":1,"bonne":0,"mnemo":"Biliaire = épaule droite."},{"q":"Que traduit le signe de Murphy dans la lithiase biliaire ?","options":["Une douleur à l'inspiration forcée","Une absence d'urine","Une fièvre isolée","Un essoufflement"],"explication":"Le signe de Murphy est une douleur à l'inspiration forcée, orientant vers la lithiase biliaire.","niveau":2,"bonne":0,"mnemo":"Murphy = inspiration douloureuse."},{"q":"Quel facteur favorise la lithiase biliaire chez la femme ?","options":["Les œstrogènes","Le tabac","L'excès de potassium","La caféine"],"explication":"Le sexe féminin via les œstrogènes est un facteur de risque de lithiase biliaire.","niveau":2,"bonne":0,"mnemo":"Œstrogènes = risque biliaire."},{"q":"Quelle précaution s'impose en cas de blocage des voies biliaires ?","options":["Donner des cholagogues/cholérétiques","Contre-indiquer les plantes cholagogues/cholérétiques","Augmenter les graisses","Jeûner totalement plusieurs jours"],"explication":"En cas de blocage des voies biliaires, les plantes cholagogues/cholérétiques sont contre-indiquées (risque d'aggraver l'obstruction).","niveau":3,"bonne":1,"mnemo":"Blocage = pas de cholagogues."}],"dys-fievre":[{"q":"Comment la naturopathie considère-t-elle la fièvre modérée ?","options":["Comme une maladie à supprimer immédiatement","Comme une réaction de défense à accompagner","Comme un signe d'hypotension","Comme sans intérêt"],"explication":"La fièvre est un mécanisme de défense qui aide l'immunité ; on l'accompagne plutôt que de la casser systématiquement.","niveau":1,"bonne":1,"mnemo":"Fièvre = alliée de l'immunité."},{"q":"Quelle structure pilote l'élévation de la température lors de la fièvre ?","options":["L'hypothalamus","Le cœur","Le foie","Les reins"],"explication":"La fièvre est une élévation contrôlée de la température pilotée par l'hypothalamus.","niveau":2,"bonne":0,"mnemo":"Hypothalamus = thermostat."},{"q":"Quel est le premier conseil d'hygiène de vie en cas de fièvre ?","options":["Faire du sport","Hydratation abondante et repos","Manger copieusement","Prendre un bain froid"],"explication":"On recommande une hydratation abondante (eau, tisanes, bouillons), une alimentation légère et le repos.","niveau":1,"bonne":1,"mnemo":"Hydrater + repos."},{"q":"Quelles plantes favorisent la transpiration en cas de fièvre ?","options":["Tilleul, sureau, reine-des-prés","Ail, olivier, aubépine","Canneberge, busserole","Sabal, pygeum"],"explication":"Le tilleul, le sureau et la reine-des-prés sont sudorifiques/fébrifuges (favorisent la transpiration).","niveau":2,"bonne":0,"mnemo":"Tilleul + sureau = transpirer."},{"q":"Devant quel signe faut-il orienter vers un médecin malgré l'idée que la fièvre est utile ?","options":["Légères courbatures","Raideur de nuque ou fièvre chez le nourrisson","Sueurs modérées","Perte d'appétit passagère"],"explication":"Les signes d'alerte (fièvre élevée/prolongée, mauvaise tolérance, raideur de nuque, nourrisson) imposent une consultation médicale.","niveau":3,"bonne":1,"mnemo":"Raideur de nuque/nourrisson = médecin."}],"dys-acne":[{"q":"Dans l'acné, quel organe doit-on drainer en priorité avant de s'occuper de la peau ?","options":["Le foie","Le rein","La rate"],"explication":"Le foie est l'émonctoire principal : on le draine d'abord (la peau ne prend le relais que parce que le foie est saturé), puis on draine la peau.","niveau":1,"bonne":0,"mnemo":"FOIE d'abord, peau ensuite."},{"q":"Quelles plantes la fiche cite-t-elle spécifiquement pour drainer la PEAU dans l'acné ?","options":["Bardane et pensée sauvage","Radis noir et romarin","Cassis et onagre"],"explication":"La bardane et la pensée sauvage sont les plantes citées pour drainer la peau ; le radis noir et le romarin concernent le foie, le cassis l'inflammation.","niveau":2,"bonne":0,"mnemo":"Peau = Bardane + Pensée sauvage."},{"q":"Selon la fiche, quel est le 6e et dernier stade d'évolution de l'acné ?","options":["Les kystes","Les papules","Les comédons ouverts"],"explication":"Les 6 stades vont des comédons ouverts (points noirs) jusqu'aux kystes (stade 6), en passant par comédons fermés, papules, pustules et nodules.","niveau":2,"bonne":0,"mnemo":"Comédons → papules → pustules → nodules → KYSTES."},{"q":"Parmi ces aliments à supprimer dans l'acné, lesquels sont cités par la fiche ?","options":["Gluten, laitages et alcool","Caroténoïdes et oméga 3","Carotte, poivron et spiruline"],"explication":"La fiche recommande de supprimer gluten, laitages et alcool ; les caroténoïdes, oméga 3 et aliments colorés (carotte, poivron, spiruline) sont au contraire conseillés.","niveau":1,"bonne":0,"mnemo":"Supprimer : Gluten-Laitages-Alcool."},{"q":"Une cliente confond son acné avec une rosacée. D'après la fiche, qu'est-ce qui permet d'écarter la rosacée ?","options":["La rosacée est vasculaire et ne présente PAS de comédons","La rosacée est due à la levure Malassezia","La rosacée donne des plaques rouges squameuses"],"explication":"La rosacée est vasculaire et sans comédons ; les plaques rouges squameuses et la levure Malassezia caractérisent la dermite séborrhéique, à distinguer aussi de l'acné.","niveau":3,"bonne":0,"mnemo":"Rosacée = vasculaire, PAS de comédons."}],"dys-eczema":[{"q":"Selon la fiche, l'eczéma de contact relève de quel mécanisme ?","options":["Une hypersensibilité retardée à une substance","Une réaction IgE immédiate","Une infection fongique"],"explication":"L'eczéma de contact est une hypersensibilité retardée à une substance, à la différence de l'eczéma atopique qui met en jeu les IgE et l'histamine.","niveau":1,"bonne":0,"mnemo":"Contact = hypersensibilité RETARDÉE."},{"q":"Quelle est la triade naturopathique à travailler dans l'eczéma ?","options":["Foie + intestin perméable + peau","Rein + poumon + peau","Foie + estomac + lymphe"],"explication":"La fiche pose le trio foie + intestin perméable + drainage cutané comme axe central de prise en charge de l'eczéma.","niveau":1,"bonne":0,"mnemo":"Trio : FOIE + INTESTIN + PEAU."},{"q":"En gemmothérapie, quel bourgeon la fiche associe-t-elle à l'eczéma SEC, et lequel à l'eczéma HUMIDE ?","options":["Cèdre pour le sec, orme pour l'humide","Orme pour le sec, cèdre pour l'humide","Noyer pour le sec, cassis pour l'humide"],"explication":"La fiche indique le cèdre pour l'eczéma sec et l'orme pour l'eczéma humide ; le noyer est pour la défense du territoire, le cassis/aulne pour l'inflammation.","niveau":2,"bonne":0,"mnemo":"Cèdre = sec, Orme = humide."},{"q":"Parmi ces options de soin LOCAL de l'eczéma, lesquelles sont citées par la fiche ?","options":["Calendula, bain d'avoine, aloe vera, huile de millepertuis","Bardane et radis noir par voie orale","Glutamine et probiotiques"],"explication":"Localement la fiche cite calendula, avoine en bain, aloe vera, camomille allemande et huile de millepertuis ; bardane/radis noir et glutamine/probiotiques relèvent du drainage interne.","niveau":2,"bonne":0,"mnemo":"Local : calendula, avoine, aloe, millepertuis."},{"q":"Face à des lésions sèches bien limitées à squames épaisses argentées sur les coudes, vers quel diagnostic différentiel la fiche oriente-t-elle plutôt qu'un eczéma ?","options":["Le psoriasis","Une mycose","Une urticaire"],"explication":"Plaques sèches bien limitées à squames argentées (coudes, genoux, cuir chevelu), renouvellement cellulaire accéléré et terrain auto-immun caractérisent le psoriasis, tandis que l'eczéma démange, fait des vésicules dans les plis sur terrain allergique/IgE.","niveau":3,"bonne":0,"mnemo":"Squames argentées bien limitées = PSORIASIS, pas eczéma."}],"dys-alopecie":[{"q":"Selon la fiche, qu'arrive-t-il physiologiquement au follicule dans l'alopécie ?","options":["Le cycle du cheveu s'accélère anormalement et épuise le follicule","Le follicule est infecté par une bactérie","Le follicule se calcifie progressivement"],"explication":"Le cycle du cheveu s'emballe et s'accélère anormalement, ce qui épuise le follicule : production de duvet puis arrêt de la pousse.","niveau":1,"bonne":0,"mnemo":"Cycle qui s'emballe → follicule ÉPUISÉ."},{"q":"Le moyen mnémotechnique « PSO-Fer » de la fiche regroupe quelles plantes ?","options":["Prêle, Spiruline, Ortie + Fenugrec","Pensée, Sauge, Olivier + Fenouil","Pissenlit, Souci, Ortie + Fucus"],"explication":"PSO-Fer = Prêle, Spiruline, Ortie + Fenugrec, pour apporter silice et minéraux et renforcer la racine.","niveau":1,"bonne":0,"mnemo":"PSO-Fer : Prêle, Spiruline, Ortie, Fenugrec."},{"q":"Quelle plante la fiche cite-t-elle spécifiquement pour son apport en FER dans l'alopécie ?","options":["La spiruline","La prêle","L'ortie piquante"],"explication":"La spiruline est citée pour le fer ; la prêle et l'ortie sont associées surtout à la silice et aux minéraux.","niveau":2,"bonne":0,"mnemo":"Spiruline = FER."},{"q":"Parmi ces gestes, lesquels la fiche conseille-t-elle pour protéger les cheveux dans l'alopécie ?","options":["Éviter sèche-cheveux, colorations et élastiques serrés","Brossages énergiques quotidiens","Lavages fréquents à l'eau très chaude"],"explication":"La fiche recommande d'éviter sèche-cheveux, colorations et élastiques serrés, et d'utiliser shampoings doux et brosses souples.","niveau":2,"bonne":0,"mnemo":"Protéger : pas de sèche-cheveux, ni colos, ni élastiques serrés."},{"q":"Un patient présente des plaques de chute par zones avec un champignon identifié. D'après la fiche, comment cette cause se distingue-t-elle de la pelade ?","options":["Il s'agit d'une teigne (cause fongique, traitée par antifongiques), alors que la pelade est auto-immune","Il s'agit d'une pelade, traitée par antifongiques","Il s'agit d'une alopécie androgénique, d'origine hormonale"],"explication":"La teigne est d'origine fongique et se traite par antifongiques ; la pelade est auto-immune et l'alopécie androgénique est hormonale/héréditaire.","niveau":3,"bonne":0,"mnemo":"Champignon = teigne (antifongiques) ≠ pelade (auto-immune)."}],"dys-cellulite":[{"q":"Selon la fiche, pourquoi le drainage est-il inefficace dans la cellulite ?","options":["La compression des vaisseaux sanguins et lymphatiques l'entrave","Le foie ne produit plus de bile","Les reins filtrent trop vite"],"explication":"La modification des adipocytes comprime les vaisseaux sanguins et lymphatiques, rendant le drainage inefficace, d'où l'aspect peau d'orange.","niveau":1,"bonne":0,"mnemo":"Adipocytes qui compriment → drainage bloqué."},{"q":"Quel symptôme la fiche associe-t-elle à la cellulite, en plus de l'aspect peau d'orange ?","options":["Une hypersensibilité au toucher","Des vésicules à liquide translucide","Des squames argentées"],"explication":"La fiche cite l'aspect peau d'orange, la gêne esthétique et l'hypersensibilité au toucher.","niveau":1,"bonne":0,"mnemo":"Peau d'orange + sensibilité au toucher."},{"q":"D'après la fiche, par quel mécanisme le sucre aggrave-t-il la cellulite ?","options":["Glycation du collagène entraînant une fibrose","Stimulation directe des œstrogènes","Augmentation de la transpiration"],"explication":"La fiche indique que le sucre provoque une glycation du collagène conduisant à une fibrose, à éliminer côté alimentation.","niveau":2,"bonne":0,"mnemo":"Sucre → glycation → fibrose."},{"q":"Quelle plante la fiche cite-t-elle spécifiquement pour activer la lymphe dans la cellulite ?","options":["Le mélilot","Le pissenlit","Le chardon-marie"],"explication":"Le mélilot est cité pour activer la lymphe ; pissenlit, bouleau, radis noir et chardon-marie servent au drainage hépatorénal.","niveau":2,"bonne":0,"mnemo":"Lymphe = MÉLILOT."},{"q":"Selon la fiche, en quoi la cellulite ne se résume-t-elle pas à un simple amas graisseux ?","options":["Une inflammation chronique et un défaut de drainage lymphatique sont au cœur du mécanisme","Elle est uniquement d'origine génétique","Elle est causée par une infection fongique"],"explication":"La cellulite correspond à une modification des adipocytes liée à une inflammation chronique : la composante inflammatoire et le défaut de drainage lymphatique sont centraux.","niveau":3,"bonne":0,"mnemo":"Pas qu'un gras : inflammation + drainage défaillant."}],"dys-herpes":[{"q":"Quel type de virus est responsable de l'herpès selon la fiche ?","options":["Le virus HSV","Le virus VZV","Le Papillomavirus humain"],"explication":"L'herpès est dû au virus HSV (HSV1 buccal ou HSV2 génital) ; le VZV donne varicelle/zona et le HPV les verrues.","niveau":1,"bonne":0,"mnemo":"Herpès = HSV."},{"q":"Selon la fiche, quelles sont les trois phases de l'évolution de l'herpès ?","options":["Primo-infection / latence / récurrence","Incubation / éruption / guérison définitive","Aiguë / subaiguë / chronique fibrosante"],"explication":"La fiche décrit une évolution en primo-infection, latence puis récurrence, le virus restant dormant entre les poussées.","niveau":1,"bonne":0,"mnemo":"Primo → latence → récurrence."},{"q":"Parmi ces facteurs, lesquels peuvent réactiver l'herpès d'après la fiche ?","options":["Fièvre, stress, soleil, règles, corticoïdes","Excès de zinc et de lysine","Alimentation riche en fruits et légumes"],"explication":"La réactivation survient lors d'une baisse d'immunité : infection, fièvre, stress, soleil, règles, corticoïdes, lèvres sèches. Zinc et lysine sont au contraire des compléments conseillés.","niveau":2,"bonne":0,"mnemo":"Réactivation = baisse d'immunité (fièvre, stress, soleil...)."},{"q":"Quel bourgeon de gemmothérapie la fiche cite-t-elle pour soutenir les surrénales dans l'herpès ?","options":["Le cassis","L'églantier","Le noyer"],"explication":"Le cassis est cité pour les surrénales ; l'églantier pour l'immunité, le noyer pour la défense du territoire et l'aulne glutineux comme anti-infectieux.","niveau":2,"bonne":0,"mnemo":"Surrénales = CASSIS."},{"q":"Un patient demande la différence entre HSV1 et HSV2. Que répond la fiche ?","options":["HSV1 est buccal, HSV2 génital, mais tous deux dorment dans les ganglions nerveux et se réactivent quand l'immunité baisse","HSV1 est génital et ne récidive jamais","HSV2 est le virus de la varicelle"],"explication":"HSV1 est buccal et HSV2 génital ; les deux restent dormants dans les ganglions nerveux et se réactivent lors d'une baisse d'immunité.","niveau":3,"bonne":0,"mnemo":"HSV1 buccal, HSV2 génital — tous deux dans le ganglion."}],"dys-mycose":[{"q":"Selon la fiche, quel type de milieu favorise le développement des mycoses ?","options":["Un milieu chaud, humide et acide","Un milieu froid, sec et alcalin","Un milieu chaud et alcalin uniquement"],"explication":"Le champignon profite d'un terrain chaud, humide et acide, que l'on corrige en asséchant la peau et en alcalinisant l'alimentation.","niveau":1,"bonne":0,"mnemo":"Chaud-Humide-Acide nourrit le champignon."},{"q":"Quels sont les trois types d'agents responsables des mycoses cités par la fiche ?","options":["Levures, dermatophytes et moisissures","Bactéries, virus et parasites","Levures, bactéries et acariens"],"explication":"La fiche liste comme agents les levures, les dermatophytes et les moisissures.","niveau":1,"bonne":0,"mnemo":"Levures, dermatophytes, moisissures."},{"q":"Comment la fiche nomme-t-elle la mycose de la commissure des lèvres ?","options":["La perlèche","Le pied d'athlète","L'onychomycose"],"explication":"La perlèche atteint la commissure des lèvres ; le pied d'athlète touche entre les orteils et l'onychomycose les ongles.","niveau":2,"bonne":0,"mnemo":"Commissure des lèvres = perlèche."},{"q":"Parmi ces compléments, lesquels la fiche recommande-t-elle pour soutenir l'intestin dans la mycose/candidose ?","options":["Glutamine et pré/probiotiques (L. acidophilus, rhamnosus)","Caroténoïdes et silice","Lysine et argent colloïdal"],"explication":"Pour soutenir l'intestin, la fiche cite la glutamine et les pré/probiotiques (L. acidophilus, rhamnosus).","niveau":2,"bonne":0,"mnemo":"Intestin : glutamine + probiotiques."},{"q":"Au début d'un traitement antifongique, un patient voit ses symptômes s'aggraver transitoirement. À quoi correspond ce phénomène selon la fiche ?","options":["À la réaction de Jarish-Herxheimer","À une réinfection par dermatophytes","À un œdème de Quincke"],"explication":"La fiche signale une possible réaction de Jarish-Herxheimer (aggravation transitoire), le traitement étant chronique sur plusieurs mois.","niveau":3,"bonne":0,"mnemo":"Aggravation transitoire = Jarish-Herxheimer."}],"dys-psoriasis":[{"q":"Quelle pathologie la source développe-t-elle réellement dans la section consacrée au psoriasis ?","options":["Le rhumatisme psoriasique","Le psoriasis cutané en détail","La dermite séborrhéique"],"explication":"La fiche précise que le psoriasis cutané n'est pas détaillé : c'est le rhumatisme psoriasique (atteinte articulaire) qui est développé.","niveau":1,"bonne":0,"mnemo":"Section psoriasis = rhumatisme psoriasique."},{"q":"Quelle est la nature de l'atteinte dans le rhumatisme psoriasique selon la fiche ?","options":["Une inflammation chronique immunitaire des articulations, tendons et muscles","Une infection bactérienne articulaire","Une dégénérescence purement mécanique du cartilage"],"explication":"Il s'agit d'une inflammation chronique à composante immunitaire touchant articulations, tendons et muscles, évoluant par poussées.","niveau":1,"bonne":0,"mnemo":"Inflammation immunitaire chronique articulaire."},{"q":"Selon la fiche, quels organes ou fonctions peuvent aussi être atteints dans le rhumatisme psoriasique ?","options":["Les yeux, l'intestin et le rythme cardiaque","Le foie et les reins","Les poumons et la rate"],"explication":"La fiche cite une atteinte possible des yeux, de l'intestin et du rythme cardiaque.","niveau":2,"bonne":0,"mnemo":"Au-delà des articulations : yeux, intestin, cœur."},{"q":"Parmi ces traitements médicaux du rhumatisme psoriasique, lesquels sont cités par la fiche ?","options":["AINS, méthotrexate, ciclosporine, sulfasalazine, anti-TNF-alpha","Antifongiques et probiotiques","Antihistaminiques et corticoïdes locaux uniquement"],"explication":"La fiche liste comme traitements médicaux : AINS, méthotrexate, ciclosporine, sulfasalazine et anti-TNF-alpha.","niveau":2,"bonne":0,"mnemo":"AINS, méthotrexate, ciclosporine, sulfasalazine, anti-TNF-α."},{"q":"Comment la fiche distingue-t-elle le psoriasis de l'eczéma ?","options":["Psoriasis = renouvellement cutané accéléré, plaques sèches squameuses, auto-immun ; eczéma = plutôt allergique/atopique et suintant","Psoriasis = allergique et suintant ; eczéma = sec et auto-immun","Les deux sont d'origine virale"],"explication":"Le psoriasis se caractérise par un renouvellement cutané accéléré, des plaques sèches squameuses et une composante auto-immune, alors que l'eczéma est plutôt allergique/atopique et suintant.","niveau":3,"bonne":0,"mnemo":"Psoriasis = sec/auto-immun ; eczéma = suintant/allergique."}],"dys-urticaire":[{"q":"D'où vient le nom « urticaire » selon la fiche ?","options":["De urtica, l'ortie en latin, car l'éruption ressemble à des piqûres d'ortie","Du nom du médecin qui l'a décrite","Du grec ouron, l'urine"],"explication":"Urtica signifie ortie en latin : l'éruption ressemble à des piqûres d'ortie, liée à une libération d'histamine.","niveau":1,"bonne":0,"mnemo":"Urtica = ortie."},{"q":"Quelle est la caractéristique d'évolution typique de l'éruption d'urticaire selon la fiche ?","options":["Elle est fugace (de quelques minutes à plusieurs jours)","Elle persiste toujours plus de six mois","Elle laisse systématiquement des cicatrices"],"explication":"L'éruption est typiquement fugace, durant de quelques minutes à plusieurs jours.","niveau":1,"bonne":0,"mnemo":"Urticaire = éruption FUGACE."},{"q":"Parmi ces plantes, laquelle la fiche cite-t-elle pour son effet antihistaminique dans l'urticaire ?","options":["Le thé vert","La bardane","Le radis noir"],"explication":"Le thé vert est cité comme antihistaminique ; la bardane et la pensée sauvage drainent la peau, le radis noir draine le foie.","niveau":2,"bonne":0,"mnemo":"Thé vert = antihistaminique naturel."},{"q":"Parmi ces causes, lesquelles la fiche associe-t-elle à l'urticaire ?","options":["Aliments riches en histamine, médicaments, exposition solaire, froid et chaleur","Excès de silice et de zinc","Carence en vitamine D uniquement"],"explication":"La fiche cite parmi les causes les allergènes (médicaments, aliments riches en histamine, cosmétiques, piqûres), l'exposition solaire, le froid, la chaleur, les infections et le stress.","niveau":2,"bonne":0,"mnemo":"Histamine + allergènes + soleil/froid/chaleur."},{"q":"Quel signe d'alerte de gravité la fiche associe-t-elle à l'urticaire, et que nécessite-t-il ?","options":["L'œdème de Quincke, une urgence (adrénaline)","Une simple desquamation à surveiller","Une perte de cheveux progressive"],"explication":"La fiche signale l'œdème de Quincke comme aggravation et signe d'alerte de gravité, constituant une urgence (adrénaline).","niveau":3,"bonne":0,"mnemo":"Œdème de Quincke = urgence (adrénaline)."}],"dys-verrues":[{"q":"Quel virus est responsable des verrues selon la fiche ?","options":["Le Papillomavirus humain (HPV)","Le virus HSV","Le virus VZV"],"explication":"Les verrues sont dues au Papillomavirus humain (HPV) ; le HSV donne l'herpès et le VZV le zona.","niveau":1,"bonne":0,"mnemo":"Verrue = HPV."},{"q":"Au niveau de quelle couche de la peau la fiche situe-t-elle les verrues ?","options":["L'épiderme","Le derme profond","L'hypoderme"],"explication":"Les verrues sont des excroissances cornées rugueuses bien délimitées au niveau de l'épiderme.","niveau":1,"bonne":0,"mnemo":"Verrue = excroissance cornée de l'épiderme."},{"q":"Quelle plante la fiche cite-t-elle en usage local contre les verrues pour renforcer aussi l'immunité ?","options":["L'extrait de pépins de pamplemousse","La bardane","Le mélilot"],"explication":"L'extrait de pépins de pamplemousse est cité pour renforcer l'immunité ; chélidoine, écorce de bouleau, saule et ail sont les usages locaux directs.","niveau":2,"bonne":0,"mnemo":"Pépins de pamplemousse = immunité."},{"q":"Selon la fiche, quelles personnes sont les plus à risque de verrues ?","options":["Immunodéprimés, transpiration excessive, peau crevassée, enfants/adolescents","Personnes âgées uniquement","Femmes enceintes uniquement"],"explication":"La fiche cite comme à risque les immunodéprimés, les personnes à transpiration excessive, à peau crevassée, ainsi que les enfants et adolescents.","niveau":2,"bonne":0,"mnemo":"Risque : immunodéprimés, transpiration, peau crevassée, jeunes."},{"q":"Quelle est l'évolution possible d'une verrue d'après la fiche ?","options":["Disparition spontanée ou passage à la chronicité","Toujours une transformation en kyste","Toujours une surinfection bactérienne obligatoire"],"explication":"La fiche indique que la verrue peut disparaître spontanément ou devenir chronique.","niveau":3,"bonne":0,"mnemo":"Verrue : peut partir seule ou durer."}],"dys-zona":[{"q":"Le zona correspond à la réactivation de quel virus selon la fiche ?","options":["Le virus VZV (varicelle-zona), après une varicelle","Le virus HSV2","Le Papillomavirus humain"],"explication":"Le zona est une réactivation du virus VZV (varicelle-zona) resté dormant dans les ganglions nerveux après une varicelle.","niveau":1,"bonne":0,"mnemo":"Zona = VZV réactivé (post-varicelle)."},{"q":"Comment se présente l'éruption du zona selon la fiche ?","options":["Des vésicules en grappes d'un seul côté, le long d'un trajet nerveux","Une éruption généralisée des deux côtés du corps","Des plaques sèches squameuses bien limitées"],"explication":"Le zona donne des vésicules en grappes d'un seul côté, le long d'un trajet nerveux, après des douleurs/brûlures unilatérales.","niveau":1,"bonne":0,"mnemo":"Un seul côté + 1 nerf = zona."},{"q":"Quelle huile essentielle la fiche cite-t-elle spécifiquement pour la névralgie du zona ?","options":["La menthe poivrée","Le ravintsara","Le géranium"],"explication":"La menthe poivrée est citée pour la névralgie ; la lavande est antalgique/cicatrisante, et ravintsara, niaouli, géranium font partie des HE externes.","niveau":2,"bonne":0,"mnemo":"Névralgie = menthe poivrée."},{"q":"Parmi ces compléments, lesquels la fiche cite-t-elle pour stimuler l'immunité dans le zona ?","options":["Extrait de pépins de pamplemousse, gelée royale, propolis, vitamine C","Lysine et caroténoïdes","Silice et fenugrec"],"explication":"Pour stimuler l'immunité, la fiche cite l'extrait de pépins de pamplemousse, la gelée royale, la propolis, la vitamine C et Cu-Au-Ag.","niveau":2,"bonne":0,"mnemo":"Immunité : pamplemousse, gelée royale, propolis, vit C."},{"q":"Une patiente garde une douleur brûlante sur le trajet nerveux plus de six mois après son zona. Comment la fiche nomme-t-elle cette complication ?","options":["Les algies post-zostériennes","Un zona ophtalmique","Un œdème de Quincke"],"explication":"La fiche cite les algies post-zostériennes (>6 mois) comme complication, distincte du zona ophtalmique ou péri-auriculaire.","niveau":3,"bonne":0,"mnemo":"Douleur >6 mois = algies post-zostériennes."}],"dys-rgo":[{"q":"Quel symptôme principal caractérise le RGO ?","options":["Des brûlures rétrosternales (pyrosis)","Des selles grasses et malodorantes","Un prurit anal nocturne","Une fièvre élevée"],"explication":"Le RGO se manifeste typiquement par des brûlures rétrosternales (pyrosis), surtout après les repas et en position allongée.","niveau":1,"bonne":0,"mnemo":"Pyrosis = ça brûle derrière le sternum."},{"q":"Quel sphincter fonctionne mal dans le RGO ?","options":["Le sphincter d'Oddi","Le sphincter inférieur de l'œsophage (cardia)","Le sphincter anal","Le pylore"],"explication":"Le RGO est dû au mauvais fonctionnement du sphincter inférieur de l'œsophage (cardia), qui laisse remonter l'acide.","niveau":1,"bonne":1,"mnemo":"Le cardia fuit → l'acide remonte."},{"q":"Quelles plantes mucilagineuses sont conseillées pour tapisser et protéger la muqueuse œsophagienne ?","options":["Séné, bourdaine, rhubarbe","Gentiane, quinquina, pissenlit","Mauve, guimauve, plantain","Myrtille, busserole, chêne"],"explication":"Les adoucissants/mucilages mauve, guimauve et plantain tapissent et protègent la muqueuse œsophagienne.","niveau":2,"bonne":2,"mnemo":"MAUVE/GUIMAUVE/PLANTAIN tapissent."},{"q":"Parmi ces facteurs étiologiques, lequel est cité comme cause du RGO ?","options":["La hernie hiatale et l'hyperpression abdominale","Le déficit en lactase","Le scotch test positif","L'insuffisance pancréatique"],"explication":"La hernie hiatale et l'hypertension abdominale (grossesse, obésité, toux) figurent parmi les causes du RGO.","niveau":2,"bonne":0,"mnemo":"Hernie hiatale + pression abdo = reflux."},{"q":"Une personne souffrant à la fois de RGO et d'HTA demande conseil. Quelle plante éviter malgré son intérêt pour la muqueuse ?","options":["La mauve","La réglisse","La passiflore","Le plantain"],"explication":"La réglisse favorise le mucus protecteur mais est contre-indiquée en cas d'HTA en raison de son effet hypertenseur.","niveau":3,"bonne":1,"mnemo":"Réglisse = ⚠️ HTA."}],"dys-constipation":[{"q":"À partir de combien de selles hebdomadaires parle-t-on de constipation ?","options":["Moins de 3 selles par semaine","Moins de 7 selles par semaine","Moins de 5 selles par semaine","Moins de 1 selle par jour"],"explication":"La constipation est définie par moins de 3 selles par semaine, avec des selles dures et une exonération difficile.","niveau":1,"bonne":0,"mnemo":"Moins de 3/semaine = constipation."},{"q":"Quels piliers d'hygiène de vie sont mis en avant contre la constipation ?","options":["Jeûne et repos strict","Hydratation, fibres et activité physique","Antibiotiques et repos","Réduction de l'eau et des fibres"],"explication":"On insiste sur l'hydratation +++, les fibres et l'activité physique qui mobilise le côlon.","niveau":1,"bonne":1,"mnemo":"EAU + FIBRES + BOUGER."},{"q":"Dans la constipation spasmodique (côlon contracté), de quoi a-t-on besoin ?","options":["De fibres irritantes en grande quantité","De laxatifs stimulants au long cours","D'antispasmodiques et de détente","De plantes astringentes"],"explication":"La forme spasmodique craint les fibres irritantes ; elle a besoin d'antispasmodiques (camomille, lavande, cumin, carvi) et de détente.","niveau":2,"bonne":2,"mnemo":"Spasmodique = antispasmodiques + calme."},{"q":"Quel minéral est cité comme laxatif osmotique ?","options":["Le fer","Le zinc","Les sels de magnésium","Le cuivre"],"explication":"Les sels de magnésium agissent comme laxatif osmotique.","niveau":2,"bonne":2,"mnemo":"Magnésium = laxatif osmotique."},{"q":"Pourquoi déconseille-t-on les laxatifs séné et bourdaine au long cours ?","options":["Ils provoquent une dépendance et sont contre-indiqués en cas d'affection cardiaque","Ils augmentent la tension artérielle","Ils détruisent les entérocytes","Ils provoquent une stéatorrhée"],"explication":"Le séné et la bourdaine sont des laxatifs stimulants à n'utiliser qu'en courte durée : risque de dépendance et contre-indication en cas d'affection cardiaque.","niveau":3,"bonne":0,"mnemo":"SÉNÉ = dépendance, courte durée."}],"dys-ballonnements":[{"q":"À quoi correspond l'aérophagie dans les ballonnements ?","options":["À de l'air avalé présent dans l'estomac","À une inflammation du foie","À une fermentation des protéines","À une carence en magnésium"],"explication":"L'aérophagie correspond à de l'air présent dans l'estomac, l'une des causes de la sensation d'abdomen gonflé.","niveau":1,"bonne":0,"mnemo":"Aérophagie = air avalé."},{"q":"Quel conseil alimentaire de base est recommandé contre les ballonnements ?","options":["Boire beaucoup de boissons gazeuses","Manger lentement et bien mastiquer","Multiplier les légumineuses","Manger très vite"],"explication":"On conseille de manger lentement, bien mastiquer et d'éviter les boissons gazeuses et les aliments très fermentescibles.","niveau":1,"bonne":1,"mnemo":"Mâcher + ralentir."},{"q":"Quels aliments sont identifiés comme fermentescibles favorisant les ballonnements ?","options":["Le riz et la banane","Les FODMAPs, légumineuses et choux","Les carottes cuites","Les coings"],"explication":"Les aliments fermentescibles (FODMAPs), les légumineuses et les choux favorisent les ballonnements par fermentation.","niveau":2,"bonne":1,"mnemo":"FODMAPs + légumineuses + choux = gaz."},{"q":"Quel agent peut être utilisé pour capter les gaz (à distance des médicaments) ?","options":["La réglisse","Le charbon végétal activé","La gentiane","Le psyllium"],"explication":"Le charbon végétal activé (et l'argile) captent les gaz, à prendre à distance des médicaments.","niveau":2,"bonne":1,"mnemo":"Charbon = éponge à gaz."},{"q":"Des gaz malodorants orientent plutôt vers quel mécanisme ?","options":["Une fermentation des glucides","Une putréfaction des protéines","Une aérophagie pure","Une carence en fibres"],"explication":"La putréfaction se fait sur les protéines et donne des gaz malodorants ; la fermentation porte sur les glucides/fibres et donne des gaz inodores.","niveau":3,"bonne":1,"mnemo":"Malodorant = putréfaction (protéines)."}],"dys-aphtes":[{"q":"Comment se présente typiquement un aphte ?","options":["Un cratère blanchâtre entouré d'un halo rouge vif","Une plaque noire indolore","Une vésicule remplie de liquide clair","Une croûte jaune sur la lèvre"],"explication":"L'aphte est une ulcération de la muqueuse buccale en forme de cratère blanchâtre à bords nets, entouré d'un halo rouge vif.","niveau":1,"bonne":0,"mnemo":"Cratère blanc + halo rouge."},{"q":"Quelle orientation alimentaire est conseillée en cas d'aphtes ?","options":["Une alimentation très acide","Une alimentation basifiante","Une alimentation riche en aliments durs","Une alimentation épicée"],"explication":"On conseille une alimentation basifiante et d'éviter les aliments irritants, acides, durs ou épicés.","niveau":1,"bonne":1,"mnemo":"Aphtes = basifier, éviter l'acide."},{"q":"Quelles carences nutritionnelles sont citées dans l'étiologie des aphtes ?","options":["Carence en B12, acide folique, zinc, fer","Carence en lipase","Excès de magnésium","Excès de vitamine C"],"explication":"Les carences en B12, acide folique, zinc et fer figurent parmi les causes des aphtes.","niveau":2,"bonne":0,"mnemo":"B12, folates, zinc, fer."},{"q":"Quels soins locaux sont proposés pour un aphte ?","options":["Rinçage au bicarbonate et propolis en local","Application de séné","Bain de bouche au jus d'orange","Cataplasme de chocolat"],"explication":"On propose le rinçage au bicarbonate et la propolis en local, ainsi que le bain de bouche à la camomille ou l'aloe vera.","niveau":2,"bonne":0,"mnemo":"Bicarbonate + propolis en local."},{"q":"Quel signe doit conduire à un avis médical face à des aphtes ?","options":["Un aphte qui guérit en 10 jours","Une légère douleur à la mastication","Des aphtes >1 cm, persistants, nombreux ou avec fièvre","Un seul aphte sur la lèvre"],"explication":"Les aphtes >1 cm, persistants, très récurrents, nombreux ou accompagnés de fièvre imposent un avis médical (maladie sous-jacente possible).","niveau":3,"bonne":2,"mnemo":">1 cm, fièvre, nombreux = médecin."}],"dys-colon-irritable":[{"q":"Sur le plan tissulaire, qu'est-ce qui caractérise la colopathie fonctionnelle ?","options":["Une altération marquée des tissus","L'absence d'altération tissulaire","Une ulcération profonde du côlon","Des diverticules enflammés"],"explication":"Le côlon irritable est un trouble fonctionnel : les symptômes surviennent sans altération tissulaire.","niveau":1,"bonne":1,"mnemo":"Fonctionnel = sans lésion."},{"q":"Quelle population est davantage touchée par le côlon irritable ?","options":["Les hommes","Les femmes (ratio 2:1)","Uniquement les enfants","Les personnes âgées exclusivement"],"explication":"Le côlon irritable touche davantage les femmes, avec un ratio de 2:1.","niveau":1,"bonne":1,"mnemo":"Femmes 2:1."},{"q":"Quel axe physiologique est central dans le côlon irritable ?","options":["L'axe cerveau-intestin (SNC-entérique)","L'axe rénine-angiotensine","L'axe hypophyso-surrénalien seul","L'axe foie-vésicule"],"explication":"Le côlon irritable est lié à la communication entre le système nerveux central et le système entérique (axe cerveau-intestin).","niveau":2,"bonne":0,"mnemo":"Cerveau ↔ intestin."},{"q":"Quelle plante adoucissante en gel est conseillée dans le côlon irritable ?","options":["Le séné","Le psyllium","La gentiane","La bourdaine"],"explication":"Le psyllium (gel adoucissant), le son d'avoine et les graines de lin sont conseillés, de même que les mucilages mauve/guimauve/plantain.","niveau":2,"bonne":1,"mnemo":"Psyllium = gel doux."},{"q":"Qu'est-ce qui distingue la colopathie fonctionnelle des colites inflammatoires (Crohn, RCH) ?","options":["La colopathie présente une atteinte des tissus, pas les colites","Les colites inflammatoires présentent une atteinte des tissus, contrairement à la colopathie fonctionnelle","Les deux présentent les mêmes lésions","Aucune n'entraîne de symptômes digestifs"],"explication":"La colopathie est fonctionnelle (sans altération tissulaire) alors que les colites inflammatoires (Crohn, RCH) présentent une atteinte des tissus.","niveau":3,"bonne":1,"mnemo":"Colites = lésions ; colopathie = pas de lésion."}],"dys-diarrhee":[{"q":"Comment définit-on une diarrhée chronique ?","options":["Plus de 3 selles liquides par jour depuis plus de 3 semaines","Une selle dure par semaine","Des gaz après les repas","Une selle liquide isolée"],"explication":"La diarrhée chronique correspond à plus de 3 selles liquides et non moulées par jour, persistant depuis plus de 3 semaines.","niveau":1,"bonne":0,"mnemo":">3 selles liquides/jour, >3 semaines."},{"q":"Quel risque majeur faut-il prévenir en cas de diarrhée ?","options":["L'hypertension","La déshydratation","L'hyperglycémie","La constipation"],"explication":"La déshydratation est une conséquence à prévenir ; il faut boire suffisamment.","niveau":1,"bonne":1,"mnemo":"Diarrhée → hydrater."},{"q":"Quels aliments sont conseillés en cas de diarrhée chronique ?","options":["Fruits et légumes crus, café","Riz, carottes cuites, pommes râpées, bananes, coings","Produits laitiers et gluten","Aliments gras"],"explication":"On conseille riz/eau de riz, tapioca, carottes cuites, pommes râpées, coings et bananes ; éviter gras, gluten, laitages, crudités et café.","niveau":2,"bonne":1,"mnemo":"Riz-banane-pomme-carotte cuite."},{"q":"Quelle famille de plantes aide à resserrer les selles ?","options":["Les plantes astringentes (myrtille, busserole, chêne)","Les plantes carminatives","Les plantes apéritives","Les plantes cholagogues"],"explication":"Les plantes astringentes comme la myrtille, la busserole et l'écorce de chêne resserrent les selles.","niveau":2,"bonne":0,"mnemo":"Astringents = resserrent (myrtille, chêne)."},{"q":"Pourquoi le caractère chronique d'une diarrhée impose-t-il une recherche de cause ?","options":["Parce qu'elle peut révéler une cause inflammatoire, cœliaque, pancréatique, thyroïdienne ou tumorale","Parce qu'elle guérit toujours seule en 24h","Parce qu'elle est toujours bénigne","Parce qu'elle est due uniquement au stress"],"explication":"Au-delà de 3 semaines, il faut rechercher une cause : colite inflammatoire, maladie cœliaque, atteinte pancréatique ou thyroïdienne, tumeur (sang).","niveau":3,"bonne":0,"mnemo":"Chronique = chercher la cause."}],"dys-diverticulite":[{"q":"Qu'est-ce qu'un diverticule ?","options":["Une hernie de la muqueuse intestinale dans le côlon","Une plaie de l'estomac","Un vers intestinal","Une inflammation du foie"],"explication":"La diverticulose est la présence de diverticules, c'est-à-dire de hernies de la muqueuse intestinale dans le côlon.","niveau":1,"bonne":0,"mnemo":"Diverticule = petit sac (hernie) du côlon."},{"q":"Quel facteur alimentaire favorise la diverticulose ?","options":["Un régime pauvre en fibres","Un excès de fibres","Un excès d'eau","Un excès de légumes verts"],"explication":"Le régime pauvre en fibres, riche en viande rouge/graisses, ainsi que la constipation chronique, favorisent la diverticulose.","niveau":1,"bonne":0,"mnemo":"Manque de fibres = diverticules."},{"q":"Quelles complications peut entraîner une diverticulite ?","options":["Abcès, péritonite, fistule, occlusion","Œdème de Quincke","Stéatorrhée isolée","Prurit anal"],"explication":"La diverticulite peut se compliquer d'abcès, péritonite, fistule ou occlusion.","niveau":2,"bonne":0,"mnemo":"Diverticulite grave = abcès/péritonite."},{"q":"Que conseille-t-on pendant une crise de diverticulite ?","options":["Une diète liquide 2-3 jours puis sans résidus 10-15 jours","Beaucoup de petites graines","Un régime très riche en son","De l'alcool"],"explication":"Pendant les crises, on recommande une diète liquide 2-3 jours puis sans résidus 10-15 jours, et d'éviter les petites graines.","niveau":2,"bonne":0,"mnemo":"En crise : liquide puis sans résidus."},{"q":"Quelle distinction faut-il faire entre diverticulose et diverticulite ?","options":["La diverticulose est l'inflammation, la diverticulite la simple présence de sacs","La diverticulose est la présence de diverticules (souvent asymptomatique), la diverticulite leur inflammation/infection douloureuse et fébrile","Ce sont deux mots pour la même chose","La diverticulite touche l'estomac, la diverticulose le côlon"],"explication":"La diverticulose est la simple présence de diverticules (souvent asymptomatique) ; la diverticulite est l'inflammation/infection d'un diverticule, douloureuse et fébrile.","niveau":3,"bonne":1,"mnemo":"Diverticulose = les sacs ; diverticulite = le sac qui s'enflamme."}],"dys-dysbiose":[{"q":"Qu'est-ce que la dysbiose ?","options":["Un déséquilibre chronique du microbiote intestinal","Une inflammation du foie","Une plaie de l'estomac","Un déficit en enzymes pancréatiques"],"explication":"La dysbiose est un déséquilibre chronique du microbiote intestinal.","niveau":1,"bonne":0,"mnemo":"Dysbiose = flore déséquilibrée."},{"q":"Quelle conséquence majeure la dysbiose entraîne-t-elle sur la paroi intestinale ?","options":["Une augmentation de la perméabilité intestinale (leaky gut)","Une stéatorrhée","Une hypertension","Une lithiase biliaire"],"explication":"La dysbiose augmente la perméabilité intestinale (leaky gut), laissant passer des substances inhabituelles et entretenant une inflammation chronique.","niveau":1,"bonne":0,"mnemo":"Dysbiose → leaky gut → inflammation."},{"q":"Quels aliments faut-il en priorité supprimer en cas de dysbiose ?","options":["Les légumes bio et lacto-fermentés","Le sucre raffiné, le gluten et les laitages","Le curcuma et le gingembre","Les protéines végétales"],"explication":"On supprime en priorité le sucre raffiné, le gluten, les laitages et autres intolérances.","niveau":2,"bonne":1,"mnemo":"Retirer sucre/gluten/laitages."},{"q":"Quel acide aminé sert de carburant aux entérocytes pour réparer la muqueuse ?","options":["La L-glutamine","La lactoferrine","La tyramine","L'histamine"],"explication":"La L-glutamine est le carburant des entérocytes (et du cerveau), utile pour réparer la muqueuse.","niveau":2,"bonne":0,"mnemo":"L-glutamine nourrit les entérocytes."},{"q":"Selon le segment du côlon, comment distingue-t-on fermentation et putréfaction ?","options":["Fermentation à gauche sur les protéines, putréfaction à droite sur les sucres","Fermentation à droite liée aux sucres, putréfaction à gauche liée aux protéines","Les deux à droite sur les graisses","Les deux à gauche sur les fibres"],"explication":"La fermentation siège au côlon droit et est liée aux sucres ; la putréfaction siège au côlon gauche et est liée aux protéines.","niveau":3,"bonne":1,"mnemo":"Droit/sucres = fermentation ; gauche/protéines = putréfaction."}],"dys-intestin-permeable":[{"q":"Comment appelle-t-on en anglais l'hyperperméabilité intestinale ?","options":["Leaky gut","Brain fog","Heartburn","Bloating"],"explication":"L'hyperperméabilité intestinale est aussi appelée leaky gut (intestin qui fuit).","niveau":1,"bonne":0,"mnemo":"Leaky gut = intestin poreux."},{"q":"L'hyperperméabilité intestinale est principalement la conséquence de quoi ?","options":["D'une dysbiose (déséquilibre du microbiote)","D'un excès de fibres","D'une carence en fer isolée","D'une infection virale du foie"],"explication":"Le leaky gut est la conséquence d'un déséquilibre du microbiote (dysbiose) qui dégrade la barrière intestinale.","niveau":1,"bonne":0,"mnemo":"Dysbiose d'abord → puis leaky gut."},{"q":"Quelles sont les cellules de la muqueuse intestinale nourries par la L-glutamine ?","options":["Les entérocytes","Les hépatocytes","Les neurones","Les ostéocytes"],"explication":"La L-glutamine est le carburant des entérocytes, les cellules de la muqueuse intestinale.","niveau":2,"bonne":0,"mnemo":"Entérocytes = cellules de l'intestin."},{"q":"Quelle association de compléments est centrale pour réparer la muqueuse dans l'intestin perméable ?","options":["Séné et bourdaine","L-glutamine, probiotiques et anti-inflammatoires (curcuma)","Réglisse et canneberge","Charbon et argile seuls"],"explication":"On répare la muqueuse avec la L-glutamine, les probiotiques et des anti-inflammatoires comme le curcuma, en retirant sucre/gluten/laitages.","niveau":2,"bonne":1,"mnemo":"L-glutamine + probiotiques + curcuma."},{"q":"Pourquoi l'hyperperméabilité intestinale n'est-elle pas considérée comme une maladie isolée ?","options":["Parce qu'elle est la conséquence de la dysbiose sur la muqueuse","Parce qu'elle est sans aucun symptôme","Parce qu'elle ne touche que le foie","Parce qu'elle est toujours bénigne et passagère"],"explication":"Le leaky gut est la conséquence de la dysbiose sur la barrière intestinale, pas une maladie isolée : la dysbiose dégrade la barrière qui devient perméable.","niveau":3,"bonne":0,"mnemo":"Leaky gut = conséquence, pas cause."}],"dys-dyspepsie":[{"q":"Quel symptôme accompagne typiquement la dyspepsie après les repas ?","options":["Une faim intense","Une somnolence postprandiale","Une soif extrême","Une montée de température"],"explication":"La fiche cite une digestion lente, une pesanteur, des nausées et une somnolence postprandiale parmi les symptômes.","niveau":1,"bonne":1,"mnemo":"Repas lourd → on tombe de sommeil après."},{"q":"Quelle erreur d'hygiène alimentaire est conseillée de supprimer dans la dyspepsie ?","options":["Le petit-déjeuner","Les grignotages","Les fibres","L'hydratation"],"explication":"Le pilier alimentation recommande de corriger les erreurs alimentaires et de supprimer les grignotages.","niveau":1,"bonne":1,"mnemo":"Pas de grignotage : on laisse l'estomac se reposer."},{"q":"Quelle famille de plantes citée dans la dyspepsie facilite la libération de la bile ?","options":["Les apéritives","Les carminatives","Les cholérétiques/cholagogues","Les astringentes"],"explication":"La fiche cite les cholérétiques/cholagogues (fumeterre, artichaut, radis noir).","niveau":2,"bonne":2,"mnemo":"Cholé = bile (fumeterre, artichaut, radis noir)."},{"q":"À quoi est liée l'hypochlorhydrie évoquée dans l'étiologie de la dyspepsie ?","options":["À une hyperparasympathicotonie","À une déshydratation","À un excès de sport","À une carence en fer"],"explication":"L'étiologie cite l'hyperparasympathicotonie (hypochlorhydrie) entraînant un décalage des sécrétions et des fermentations.","niveau":2,"bonne":0,"mnemo":"Trop de parasympathique → pas assez d'acide (hypochlorhydrie)."},{"q":"On confond parfois dyspepsie et dysbiose. Selon la fiche, quel est leur lien ?","options":["La dyspepsie cause toujours la dysbiose","La dysbiose est une cause possible de la dyspepsie","Ce sont deux noms du même trouble","Aucun lien entre les deux"],"explication":"La fiche précise que la dysbiose et la perméabilité intestinale sont des causes possibles de la dyspepsie, fonctionnelle.","niveau":3,"bonne":1,"mnemo":"Dysbiose = cause ; dyspepsie = inconfort qui en résulte."}],"dys-gastrite":[{"q":"Sur quel organe porte l'inflammation dans la gastrite ?","options":["L'œsophage","La muqueuse de l'estomac","Le duodénum","Le côlon"],"explication":"La gastrite est l'inflammation de la muqueuse de l'estomac.","niveau":1,"bonne":1,"mnemo":"Gastr- = estomac."},{"q":"Comment réalise-t-on le test au bicarbonate dans la gastrite ?","options":["1/4 de càc de bicarbonate dans 25 cl d'eau","Une cuillère à soupe à jeun sans eau","Du bicarbonate appliqué sur la langue","Un verre de bicarbonate après le repas"],"explication":"La fiche décrit le test : 1/4 de càc de bicarbonate dans 25 cl d'eau.","niveau":2,"bonne":0,"mnemo":"1/4 de càc dans 25 cl d'eau, on attend 3 min."},{"q":"En cas d'hypochlorhydrie, quel conseil alimentaire est mis en avant ?","options":["Multiplier les grignotages","Ne pas grignoter et fractionner les repas","Augmenter les laitages","Manger très épicé"],"explication":"Le pilier alimentation insiste sur l'absence de grignotage (surtout en hypochlorhydrie) et le fractionnement des repas.","niveau":2,"bonne":1,"mnemo":"Hypochlorhydrie : pas de grignotage, repas fractionnés."},{"q":"Quel aliment/épice est conseillé dans la gastrite pour son intérêt digestif ?","options":["Le café","Le curcuma","Le cacao","L'alcool"],"explication":"La fiche conseille curcuma, gingembre, brocolis, fibres solubles, antioxydants, oméga 3 et vitamine A.","niveau":1,"bonne":1,"mnemo":"Curcuma + gingembre = amis de l'estomac."},{"q":"Quel bourgeon (gemmothérapie) est cité dans la gastrite ?","options":["Cassis et tilleul","Figuier et aulne glutineux","Vigne et noisetier","Bouleau et romarin"],"explication":"La fiche cite en gemmothérapie le figuier et l'aulne glutineux.","niveau":3,"bonne":1,"mnemo":"Estomac stressé → figuier (+ aulne)."}],"dys-hepatite":[{"q":"Quelle est la cause d'une hépatite virale selon la fiche ?","options":["Un virus A, B, C, D ou E","Une bactérie unique","Un excès de fibres","Un parasite intestinal"],"explication":"L'hépatite virale est une inflammation du foie due à un virus A, B, C, D ou E.","niveau":1,"bonne":0,"mnemo":"Hépatites virales = lettres A à E."},{"q":"Quel signe clinique évoque une hépatite ?","options":["Selles décolorées et urines foncées","Selles claires et urines claires","Hypertension brutale","Prurit anal nocturne"],"explication":"La fiche cite ictère, urines foncées et selles décolorées.","niveau":2,"bonne":0,"mnemo":"Foie atteint : urines foncées, selles décolorées."},{"q":"Quel pilier alimentaire est recommandé pour alléger le foie en cas d'hépatite ?","options":["Régime riche en graisses","Bouillon/jus de légumes, riz, pauvre en graisses et sucres","Jeûne hydrique total prolongé","Alimentation très protéinée"],"explication":"Le pilier alimentation décrit un régime strict pour alléger le foie : bouillon de légumes, jus de légumes, riz, aliments non transformés, pauvre en graisses et sucres.","niveau":1,"bonne":1,"mnemo":"Foie fatigué → on l'allège : légumes, riz, peu de gras/sucre."},{"q":"Quelle plante est citée à la fois comme immunostimulante et antivirale dans l'hépatite ?","options":["Le chardon-marie","L'astragale","L'artichaut","Le pissenlit"],"explication":"La fiche cite l'astragale comme immunostimulant et antiviral.","niveau":2,"bonne":1,"mnemo":"Astragale = bouclier immunitaire antiviral."},{"q":"Pour quels virus de l'hépatite la vaccination existe-t-elle selon la fiche ?","options":["A et B","C et D","B et E","Tous les types"],"explication":"La rubrique « ne pas confondre » précise que la vaccination ne concerne que A et B.","niveau":3,"bonne":0,"mnemo":"On vaccine contre A et B uniquement."}],"dys-insuffisance-hepatobiliaire":[{"q":"Quels organes sont concernés par l'insuffisance hépato-biliaire ?","options":["L'estomac et l'œsophage","Le foie et la vésicule biliaire","Le pancréas et la rate","Les intestins et le côlon"],"explication":"Il s'agit d'une paresse du foie et de la vésicule biliaire, avec une bile insuffisamment sécrétée ou évacuée.","niveau":1,"bonne":1,"mnemo":"Hépato = foie, biliaire = vésicule."},{"q":"Quel symptôme évoque une insuffisance hépato-biliaire ?","options":["Difficulté à digérer les lipides","Difficulté à digérer les protéines uniquement","Hypertension","Prurit anal"],"explication":"La fiche cite la difficulté à digérer les lipides et la lenteur du transit.","niveau":1,"bonne":0,"mnemo":"Pas assez de bile → les graisses passent mal."},{"q":"Une plante cholagogue agit comment sur la bile ?","options":["Elle augmente sa production","Elle facilite sa libération/évacuation","Elle bloque le foie","Elle dissout les calculs"],"explication":"La fiche distingue cholérétique (augmente la production) et cholagogue (facilite la libération/évacuation : artichaut, radis noir, huile d'olive).","niveau":2,"bonne":1,"mnemo":"CholaGOGUE = on guide la bile dehors."},{"q":"Quel minéral est cité car il favorise les contractions de la vésicule ?","options":["Le fer","Le magnésium","Le zinc","Le calcium"],"explication":"En micronutrition, la fiche cite le magnésium, qui favorise les contractions de la vésicule.","niveau":2,"bonne":1,"mnemo":"Magnésium = la vésicule se contracte."},{"q":"Dans quel cas les plantes cholagogues/cholérétiques sont-elles contre-indiquées ?","options":["En cas de stress","En cas d'obstruction des voies biliaires","En cas de fatigue","En cas de repas léger"],"explication":"La fiche indique que ces plantes sont contre-indiquées en cas d'obstruction des voies biliaires.","niveau":3,"bonne":1,"mnemo":"Voie bouchée → ne pas forcer la bile (contre-indication)."}],"dys-ulcere":[{"q":"Qu'est-ce qu'un ulcère gastro-duodénal selon la fiche ?","options":["Une simple irritation de surface","Une plaie profonde de la paroi de l'estomac ou du duodénum","Un reflux d'acide vers l'œsophage","Une hernie du diaphragme"],"explication":"L'ulcère est une plaie profonde dans la paroi de l'estomac (gastrique) ou du duodénum (duodénal).","niveau":1,"bonne":1,"mnemo":"Ulcère = plaie profonde, pas une simple irritation."},{"q":"Quel déséquilibre est à l'origine de l'ulcère ?","options":["Agression/défense, avec hypersécrétion d'acide chlorhydrique","Excès de bile","Déficit en enzymes pancréatiques","Manque de fibres"],"explication":"L'ulcère résulte d'un déséquilibre agression/défense et d'une hypersécrétion d'acide chlorhydrique.","niveau":2,"bonne":0,"mnemo":"Trop d'agression (acide) + défense qui cède = plaie."},{"q":"Quelle complication grave est citée pour l'ulcère ?","options":["Œdème de Quincke","Perforation et péritonite","Lithiase biliaire","Stéatorrhée"],"explication":"La fiche cite les complications : hémorragie digestive et perforation (péritonite).","niveau":2,"bonne":1,"mnemo":"Ulcère qui perce → péritonite (urgence)."},{"q":"Quel pilier est qualifié de majeur dans la prise en charge de l'ulcère ?","options":["L'alimentation seule","La gestion du stress","Le sommeil","L'hydratation"],"explication":"Le pilier émotionnel précise que la gestion du stress est majeure (Fleurs de Bach), avec arrêt du tabac.","niveau":1,"bonne":1,"mnemo":"Ulcère = ventre + stress : gérer le stress en priorité."},{"q":"La douleur de l'ulcère gastrique se distingue de celle du duodénal par quel comportement face à la nourriture ?","options":["Le gastrique est apaisé par le repas, le duodénal aggravé","Le gastrique est aggravé par la nourriture, le duodénal apaisé par le repas","Les deux sont apaisés par le repas","Aucun lien avec les repas"],"explication":"La fiche distingue : ulcère gastrique = douleur aggravée par la nourriture ; duodénal = douleur 3h après, apaisée par le repas et aggravée à jeun.","niveau":3,"bonne":1,"mnemo":"Gastrique : manger fait mal ; duodénal : manger soulage."}],"dys-intolerance":[{"q":"Comment apparaît une intolérance alimentaire selon la fiche ?","options":["De façon brutale","De façon progressive","Uniquement la nuit","Seulement chez l'enfant"],"explication":"L'intolérance est une réaction d'apparition progressive à des substances normalement tolérées.","niveau":1,"bonne":1,"mnemo":"Intolérance = lente et progressive."},{"q":"Quelle réaction brutale et grave caractérise l'allergie alimentaire ?","options":["Œdème de Quincke / choc anaphylactique","Stéatorrhée","Ictère","Prurit anal"],"explication":"L'allergie est une réaction brutale type œdème de Quincke ou choc anaphylactique, à distinguer de l'intolérance.","niveau":2,"bonne":0,"mnemo":"Allergie = brutale et dangereuse (Quincke, anaphylaxie)."},{"q":"Quelle substance pharmacologiquement active est citée pour les tomates, fromages et vin rouge ?","options":["La tyramine","L'histamine","La sérotonine","La caféine"],"explication":"La fiche cite l'histamine (tomates, fromages, vin rouge) parmi les substances pharmacologiquement actives.","niveau":2,"bonne":1,"mnemo":"Histamine : tomate, fromage, vin rouge."},{"q":"En quoi consiste le régime de rotation conseillé dans les intolérances ?","options":["Manger l'aliment pas plus de 2 fois par semaine","Manger l'aliment tous les jours","Supprimer toutes les fibres","Alterner cru et cuit chaque repas"],"explication":"La fiche décrit le régime de rotation : pas plus de 2 fois par semaine.","niveau":1,"bonne":0,"mnemo":"Rotation = max 2 fois/semaine."},{"q":"Quel bourgeon (gemmothérapie) est cité dans les intolérances, décrit comme « protège le territoire » ?","options":["Le figuier","Le noyer","Le romarin","Le cassis"],"explication":"La fiche cite le noyer en gemmothérapie, qui « protège le territoire ».","niveau":3,"bonne":1,"mnemo":"Noyer = gardien du territoire intestinal."}],"dys-parasitose":[{"q":"Quel parasite est responsable de l'oxyurose ?","options":["Enterobius vermicularis (oxyure)","Helicobacter pylori","Le ténia","Le candida"],"explication":"L'oxyurose est une parasitose par oxyures (Enterobius vermicularis, 5-10 mm).","niveau":1,"bonne":0,"mnemo":"Oxyure = Enterobius vermicularis."},{"q":"Chez quelle population l'oxyurose est-elle fréquente ?","options":["Les personnes âgées","Les enfants","Les sportifs","Les femmes enceintes"],"explication":"La fiche précise que l'oxyurose est fréquente chez les enfants.","niveau":1,"bonne":1,"mnemo":"Oxyure = parasite des enfants."},{"q":"Quel conseil d'hygiène est donné pour limiter l'auto-contamination par les oxyures ?","options":["Couper les ongles courts et changer le linge","Augmenter le sucre","Rester allongé","Éviter de se laver les mains"],"explication":"La fiche conseille de couper les ongles courts, brosser, changer le linge, laver doudous/jouets, fruits/crudités.","niveau":2,"bonne":0,"mnemo":"Ongles courts + linge propre = stop à l'auto-contamination."},{"q":"Quelle famille de plantes est citée comme antiparasitaire dans l'oxyurose ?","options":["Ail, gingembre, thym, cannelle, sarriette","Mauve, guimauve, plantain","Myrtille, busserole, chêne","Gentiane, centaurée, quinquina"],"explication":"La fiche cite parmi les antiparasitaires : ail, gingembre, thym, cannelle, sarriette.","niveau":2,"bonne":0,"mnemo":"Antiparasitaires : ail, thym, cannelle, sarriette."},{"q":"Pourquoi le scotch test est-il préféré à une simple coproculture pour l'oxyure ?","options":["Parce qu'il récolte les œufs déposés en péri-anal","Parce qu'il mesure l'acidité","Parce qu'il détecte l'histamine","Parce qu'il dose les enzymes"],"explication":"La fiche précise que l'oxyure se diagnostique par le scotch test (récolte des œufs péri-anaux), pas par une coproculture.","niveau":3,"bonne":0,"mnemo":"Œufs en péri-anal → scotch test."}],"dys-hernie-hiatale":[{"q":"Qu'est-ce qu'une hernie hiatale ?","options":["Le passage d'une partie de l'estomac dans le thorax à travers le hiatus du diaphragme","Une inflammation du côlon","Une plaie du duodénum","Un excès de bile"],"explication":"C'est le passage d'une partie de l'estomac dans le thorax à travers le hiatus œsophagien du diaphragme.","niveau":1,"bonne":0,"mnemo":"L'estomac « grimpe » par le diaphragme."},{"q":"La hernie hiatale est souvent…","options":["Toujours douloureuse","Souvent asymptomatique","Toujours accompagnée de fièvre","Liée à un parasite"],"explication":"La fiche indique qu'elle est souvent asymptomatique.","niveau":1,"bonne":1,"mnemo":"Hernie hiatale : souvent muette."},{"q":"Quel conseil supplémentaire, propre à la hernie hiatale, est cité dans les « autres » mesures ?","options":["Surélever la tête du lit","Boire des sodas","Manger très épicé","Faire du sport intense après manger"],"explication":"La fiche cite, parmi les autres mesures, surélever la tête du lit et protéger la muqueuse œsophagienne.","niveau":2,"bonne":0,"mnemo":"Tête du lit surélevée = moins de reflux la nuit."},{"q":"Quel facteur favorise la hernie hiatale via une hyperpression abdominale ?","options":["L'obésité, la grossesse, la toux","Une carence en fer","Un excès de fibres","Le froid"],"explication":"L'étiologie cite l'hyperpression abdominale (obésité, grossesse, toux, efforts).","niveau":2,"bonne":0,"mnemo":"Pression sur le ventre → l'estomac remonte."},{"q":"Selon la fiche, quel est le rapport entre hernie hiatale et RGO ?","options":["La hernie hiatale est une cause anatomique du RGO","Le RGO cause la hernie hiatale","Ce sont des maladies sans lien","La hernie hiatale empêche le RGO"],"explication":"La fiche précise que la hernie hiatale est une cause anatomique du RGO, le RGO étant le symptôme (remontée acide).","niveau":3,"bonne":0,"mnemo":"Hernie = cause ; RGO = conséquence."}],"dys-insuffisance-pancreatique":[{"q":"Que sécrète le pancréas exocrine ?","options":["De l'insuline","Des enzymes digestives (lipase, amylase, protéases)","De la bile","De l'acide chlorhydrique"],"explication":"Le pancréas exocrine sécrète les enzymes digestives (lipase, amylase, protéases) déversées dans le duodénum.","niveau":1,"bonne":1,"mnemo":"Exocrine = usine à enzymes."},{"q":"Quel symptôme caractéristique évoque une insuffisance pancréatique exocrine ?","options":["La stéatorrhée (selles grasses)","Un ictère","Un prurit anal","Une hypertension"],"explication":"La fiche cite la stéatorrhée (selles grasses, abondantes, malodorantes) et la diarrhée chronique.","niveau":1,"bonne":0,"mnemo":"Enzymes en panne → selles grasses (stéatorrhée)."},{"q":"Quelles carences vitaminiques peut entraîner l'insuffisance pancréatique exocrine ?","options":["Vitamines liposolubles A, D, E, K","Vitamine C uniquement","Vitamines du groupe B uniquement","Aucune carence"],"explication":"La malabsorption des graisses provoque des carences en vitamines liposolubles A, D, E, K.","niveau":2,"bonne":0,"mnemo":"Pas de gras digéré → manque d'A, D, E, K."},{"q":"Quel conseil de complément est cité pour pallier le déficit enzymatique ?","options":["Des enzymes digestives","Des laxatifs stimulants","De la réglisse","Des astringents"],"explication":"La fiche cite en micronutrition les enzymes digestives, les vitamines liposolubles si carence et les pré/probiotiques.","niveau":2,"bonne":0,"mnemo":"Enzymes manquantes → on les apporte."},{"q":"Quelle distinction la fiche demande-t-elle de faire concernant le pancréas ?","options":["Pancréas exocrine (enzymes, stéatorrhée) ≠ endocrine (insuline, diabète)","Pancréas droit ≠ pancréas gauche","Pancréas et foie sont identiques","Pancréas exocrine = production de bile"],"explication":"La fiche distingue l'insuffisance pancréatique exocrine (enzymes → digestion, stéatorrhée) de l'insuffisance endocrine (insuline → glycémie, diabète).","niveau":3,"bonne":0,"mnemo":"Exocrine = enzymes ; endocrine = insuline."}],"dys-hypothyroidie":[{"q":"Quel ensemble de signes est cohérent avec une hypothyroïdie ?","options":["Frilosité, constipation et bradycardie","Thermophobie, diarrhée et tachycardie","Perte de poids malgré l'appétit","Exophtalmie et mains moites"],"explication":"L'hypothyroïdie ralentit tout : frilosité, constipation et bradycardie sont typiques.","niveau":1,"bonne":0,"mnemo":"HYPO = froid, lent, lourd."},{"q":"Dans l'hypothyroïdie, quel aliment est conseillé d'apporter pour soutenir la fonction thyroïdienne ?","options":["Les produits de la mer et le sel iodé","Les choux en grande quantité","Le café","Les aliments raffinés"],"explication":"On apporte de l'iode via les produits de la mer et le sel iodé ; les choux goitrogènes sont au contraire à limiter.","niveau":1,"bonne":0,"mnemo":"Carburant = IODE + TYROSINE + SÉLÉNIUM."},{"q":"Pourquoi conseille-t-on de limiter les choux en cas d'hypothyroïdie ?","options":["Ils sont goitrogènes","Ils sont riches en iode","Ils stimulent les surrénales","Ils contiennent de la tyrosine"],"explication":"Les choux sont goitrogènes : consommés en excès, ils gênent le fonctionnement de la thyroïde déjà ralentie.","niveau":2,"bonne":0,"mnemo":"Choux = frein à la thyroïde."},{"q":"Quelle plante est citée pour stimuler le métabolisme thyroïdien dans l'hypothyroïdie ?","options":["L'ortie","Le lycope","La mélisse","L'agripaume"],"explication":"L'ortie stimule le métabolisme thyroïdien ; lycope, mélisse et agripaume servent au contraire à freiner (hyperthyroïdie).","niveau":2,"bonne":0,"mnemo":"Ortie + fucus pour relancer."},{"q":"Une patiente présente fatigue, prise de poids, frilosité, constipation et un tiers externe des sourcils dégarni, sur un terrain auto-immun. Quelle prise en charge naturo est la plus cohérente ?","options":["Apport iode/tyrosine/sélénium + soutien de l'intestin","Lycope et crucifères pour freiner la thyroïde","Suppression de l'iode et des algues","Repos strict sans aucune activité physique"],"explication":"Tableau d'hypothyroïdie (Hashimoto) : on apporte iode/tyrosine/sélénium et on soigne l'intestin, terrain de l'auto-immunité ; l'exercice relance le métabolisme.","niveau":3,"bonne":0,"mnemo":"Hashimoto → soigner l'INTESTIN + carburants."}],"dys-hyperthyroidie":[{"q":"Quel signe est caractéristique de l'hyperthyroïdie ?","options":["Perte de poids malgré l'appétit","Prise de poids","Frilosité","Bradycardie"],"explication":"L'hyperthyroïdie accélère le métabolisme : amaigrissement malgré un bon appétit.","niveau":1,"bonne":0,"mnemo":"HYPER = en feu, maigrit."},{"q":"Quel type d'exercice est recommandé en cas d'hyperthyroïdie ?","options":["Exercice modéré","Exercice très intense","Aucune activité physique","Sport de compétition"],"explication":"On conseille un exercice modéré pour ne pas surstimuler un corps déjà emballé.","niveau":1,"bonne":0,"mnemo":"Corps emballé = on lève le pied."},{"q":"Quels aliments sont conseillés pour modérer la thyroïde en hyperthyroïdie ?","options":["Les crucifères","Le sel iodé et les algues","Les produits laitiers","Le gluten"],"explication":"Les crucifères modèrent la thyroïde ; on limite au contraire sel iodé/algues et on supprime laitages et gluten.","niveau":2,"bonne":0,"mnemo":"Crucifères + lycope = freins."},{"q":"Pourquoi calmer le cœur et le système nerveux fait-il partie de la prise en charge de l'hyperthyroïdie ?","options":["À cause des palpitations et de l'irritabilité liées à l'emballement","Parce que la fréquence cardiaque est ralentie","Pour corriger une bradycardie","Pour traiter l'œdème"],"explication":"L'emballement provoque tachycardie/palpitations, tremblements et irritabilité : on calme cœur et système nerveux (agripaume, houblon, valériane, passiflore, aubépine).","niveau":2,"bonne":0,"mnemo":"Emballement → calmer cœur + nerfs."},{"q":"Quelle complication NON articulaire peut résulter d'une hyperthyroïdie non maîtrisée ?","options":["L'ostéoporose et les troubles du rythme cardiaque","La constipation chronique","La bradycardie","L'hypercholestérolémie"],"explication":"Parmi les complications citées : arythmie, fibrillation, insuffisance cardiaque et ostéoporose ; constipation et bradycardie relèvent au contraire de l'hypothyroïdie.","niveau":3,"bonne":0,"mnemo":"Hyper non traité = cœur + os fragilisés."}],"dys-menopause":[{"q":"Vers quel âge survient généralement la ménopause ?","options":["Vers 50 ans","Vers 30 ans","Vers 65 ans","Vers 40 ans"],"explication":"La ménopause survient typiquement vers 50 ans, avec arrêt des règles depuis au moins 12 mois.","niveau":1,"bonne":0,"mnemo":"≥12 mois sans règles, ~50 ans."},{"q":"Quel symptôme est typiquement associé à la ménopause ?","options":["Bouffées de chaleur et sueurs","Prise de poids avec frilosité","Tachycardie permanente","Exophtalmie"],"explication":"Bouffées de chaleur, sueurs, insomnie et sécheresse cutanée/vaginale sont caractéristiques.","niveau":1,"bonne":0,"mnemo":"Ménopause = bouffées de chaleur."},{"q":"Quelle plante est citée comme progestérone-like dans l'accompagnement de la ménopause ?","options":["Le gattilier","Le soja","Le houblon","Le ginseng"],"explication":"Alchémille, achillée, gattilier et yam sont progestérone-like ; soja et houblon sont au contraire œstrogène-like.","niveau":2,"bonne":0,"mnemo":"Gattilier/yam = progestérone-like."},{"q":"Pourquoi l'exercice physique est-il particulièrement recommandé à la ménopause ?","options":["Pour prévenir l'ostéoporose","Pour relancer l'ovulation","Pour augmenter les œstrogènes hépatiques","Pour stimuler la thyroïde"],"explication":"L'effondrement hormonal favorise l'ostéoporose ; l'exercice (et le lithothamme, la prêle, la vitamine D) la prévient.","niveau":2,"bonne":0,"mnemo":"Bouger = os solides."},{"q":"Au tout début du passage à la ménopause, quelle situation hormonale précède l'hypoœstrogénie ?","options":["Une hyperœstrogénie relative par chute de la progestérone","Une chute brutale et isolée des œstrogènes","Une hausse de la progestérone","Une hypersécrétion thyroïdienne"],"explication":"Ce n'est pas une chute des œstrogènes d'emblée : d'abord une hyperœstrogénie relative (la progestérone chute la première), puis une hypoœstrogénie.","niveau":3,"bonne":0,"mnemo":"D'abord hyper-relative, puis hypo."}],"dys-fibrome":[{"q":"Quelle est la nature d'un fibrome utérin ?","options":["Une tumeur bénigne du muscle utérin","Une tumeur cancéreuse de l'ovaire","Une infection vaginale","Un kyste rénal"],"explication":"Le fibrome est une tumeur bénigne (non cancéreuse) du muscle de la paroi utérine.","niveau":1,"bonne":0,"mnemo":"Fibrome = bénin, muscle utérin."},{"q":"Quelle est la taille possible d'un fibrome utérin selon le cours ?","options":["Du pois au pamplemousse","Toujours microscopique","Jamais palpable","Identique chez toutes les femmes"],"explication":"La taille est variable, du pois au pamplemousse, chez la femme de plus de 30 ans.","niveau":1,"bonne":0,"mnemo":"Pois → pamplemousse."},{"q":"Quelle plante progestérone-like est conseillée dans le fibrome utérin ?","options":["Le gattilier","La sauge","Le soja","Le houblon"],"explication":"On mise sur des plantes progestérone-like (gattilier, alchémille, achillée) ; sauge, soja et bière apportent des œstrogènes à éviter.","niveau":2,"bonne":0,"mnemo":"Progestérone-like contre l'effet œstrogène."},{"q":"Pourquoi soutient-on le foie dans la prise en charge du fibrome ?","options":["Pour aider à éliminer les œstrogènes qui nourrissent le fibrome","Pour augmenter la production d'œstrogènes","Pour stimuler la thyroïde","Pour traiter l'anémie directement"],"explication":"La croissance dépend des œstrogènes ; soutenir le foie (romarin, pissenlit, chardon-marie) aide leur métabolisme/élimination.","niveau":2,"bonne":0,"mnemo":"Foie = épure les œstrogènes."},{"q":"Un fibrome volumineux est découvert chez une femme. Quel signe ci-dessous est cohérent avec le cours ?","options":["Ménorragies avec anémie et envies urinaires fréquentes","Bouffées de chaleur et arrêt des règles","Perte de poids malgré l'appétit","Crise nocturne du gros orteil"],"explication":"Le fibrome peut donner ménorragies/métrorragies avec anémie, envies urinaires fréquentes et constipation ; il est souvent asymptomatique (>50%).","niveau":3,"bonne":0,"mnemo":"Gros fibrome = saignements + compression."}],"dys-spm":[{"q":"Quand surviennent les symptômes du syndrome prémenstruel ?","options":["2 à 7 jours avant les règles","Pendant toute la durée des règles","Après la fin des règles","Uniquement à l'ovulation"],"explication":"Le SPM survient 2 à 7 jours avant les règles et se termine à leur arrivée.","niveau":1,"bonne":0,"mnemo":"AVANT les règles, cesse à leur arrivée."},{"q":"Quelle part de l'origine du SPM est attribuée au facteur génétique selon le cours ?","options":["Environ 70%","Environ 10%","Environ 100%","Environ 30%"],"explication":"Le facteur génétique compte pour environ 70% dans le SPM.","niveau":1,"bonne":0,"mnemo":"SPM = 70% génétique."},{"q":"Quel apport alimentaire est conseillé dans le syndrome prémenstruel ?","options":["Diminuer le sel, le sucre et la caféine","Augmenter le sel et la caféine","Supprimer tout potassium","Privilégier les sucres rapides"],"explication":"On diminue sel, sucre et caféine et on favorise potassium, vitamine E, vitamines B et poisson gras.","niveau":2,"bonne":0,"mnemo":"Moins de sel/sucre/café."},{"q":"Quel complément riche en oméga 6 est cité dans le SPM ?","options":["L'huile d'onagre","Le chrome","Le fucus","La berbérine"],"explication":"L'huile d'onagre (oméga 6) est citée, avec les oméga 3, vitamines B, vitamine D, magnésium et zinc.","niveau":2,"bonne":0,"mnemo":"Onagre = oméga 6 du SPM."},{"q":"Quelle évolution des neurotransmetteurs est décrite en 2ème partie de cycle dans le SPM ?","options":["Augmentation de la dopamine et de la noradrénaline","Effondrement de la dopamine et de la sérotonine","Hausse isolée de l'insuline","Chute de la noradrénaline uniquement"],"explication":"Le cours mentionne une augmentation de la dopamine et de la noradrénaline en 2ème partie de cycle, sur fond d'hyperœstrogénie relative et de sensibilité accrue aux hormones.","niveau":3,"bonne":0,"mnemo":"2ème partie : dopamine + noradrénaline ↑."}],"dys-diabete":[{"q":"Qu'est-ce qui caractérise le diabète de type I ?","options":["Auto-immun, plus de production d'insuline, sujets jeunes","Insulinorésistance chez le sujet âgé en surpoids","Excès d'acide urique","Hyperœstrogénie relative"],"explication":"Le type I est auto-immun : les cellules bêta ne produisent plus d'insuline, chez des sujets jeunes (insuline obligatoire).","niveau":1,"bonne":0,"mnemo":"Type 1 = pancréas en grève."},{"q":"Quelle plante est citée pour couper l'attirance pour le sucre dans le diabète ?","options":["Le gymnéma","La cannelle","L'ail","La myrtille"],"explication":"Le gymnéma coupe l'attirance pour le sucre ; cannelle, gingembre, berbérine et ail sont hypoglycémiants.","niveau":1,"bonne":0,"mnemo":"Gymnéma = tue-sucre."},{"q":"Pourquoi l'activité physique réduit-elle l'insulinorésistance dans le diabète de type II ?","options":["Parce que les muscles consomment le glucose","Parce qu'elle augmente la sécrétion d'insuline","Parce qu'elle élève le cortisol","Parce qu'elle augmente l'acide urique"],"explication":"Les muscles à l'effort consomment le glucose, ce qui abaisse l'insulinorésistance.","niveau":2,"bonne":0,"mnemo":"Muscle = consomme le glucose."},{"q":"Pourquoi la gestion du stress fait-elle partie de la prise en charge du diabète ?","options":["Parce que le cortisol élève la glycémie","Parce que le stress baisse la glycémie","Parce que le stress augmente l'insuline","Parce que le stress abaisse l'acide urique"],"explication":"Le cortisol, hormone du stress, élève la glycémie : la gérer fait partie des piliers.","niveau":2,"bonne":0,"mnemo":"Cortisol ↑ → glycémie ↑."},{"q":"Quel ensemble de facteurs abaisse l'index glycémique d'un repas ?","options":["Fibres, cuisson al dente, protéines/graisses, moins de sel","Sucres rapides et cuisson prolongée","Jeûne prolongé avant le repas","Édulcorants et céréales raffinées"],"explication":"L'IG est abaissé par les fibres, la cuisson al dente, l'ajout de protéines/graisses et moins de sel ; on supprime sucre, édulcorants et raffinés.","niveau":3,"bonne":0,"mnemo":"Fibres + al dente + protéines/gras + moins de sel."}],"dys-goutte":[{"q":"Quelle substance est en excès dans la goutte ?","options":["L'acide urique","Le cholestérol LDL","Le glucose","Les œstrogènes"],"explication":"La goutte est liée à une hyperuricémie : excès d'acide urique issu de la dégradation des purines.","niveau":1,"bonne":0,"mnemo":"Goutte = acide urique (purines)."},{"q":"Quel est le profil de personne le plus touché par la goutte selon le cours ?","options":["Les hommes (10x plus) et les « bons vivants »","Les femmes après la ménopause","Les enfants","Les sujets maigres et jeunes"],"explication":"La goutte touche surtout les « bons vivants » et les hommes (10 fois plus que les femmes).","niveau":1,"bonne":0,"mnemo":"Maladie du bon vivant, surtout l'homme."},{"q":"Quelle vitamine est citée pour aider à éliminer l'acide urique ?","options":["La vitamine C","La vitamine D","La vitamine B12","La vitamine K"],"explication":"La vitamine C aide à éliminer l'acide urique, avec les citrates alcalinisants et le bicarbonate de soude.","niveau":2,"bonne":0,"mnemo":"Vitamine C = élimine l'acide urique."},{"q":"Quel conseil d'hydratation est adapté à la goutte ?","options":["Cures d'eau bicarbonatée (Badoit, Vichy Saint-Yorre)","Boire surtout du vin blanc","Boire des jus industriels sucrés","Boire beaucoup de thé et de café"],"explication":"On conseille une hydratation régulière avec eau faiblement minéralisée et des cures d'eau bicarbonatée ; vin blanc, thé, café et jus industriels sont à limiter.","niveau":2,"bonne":0,"mnemo":"Alcaliniser : eau bicarbonatée."},{"q":"Lors d'une crise de goutte, quel médicament faut-il particulièrement éviter ?","options":["L'aspirine","La colchicine en début de crise","Les AINS","L'allopurinol en prévention"],"explication":"On évite l'aspirine pendant la crise : l'aspirine à faible dose est même une cause médicamenteuse d'hyperuricémie. La colchicine (début), les AINS et l'allopurinol (prévention) sont eux mentionnés.","niveau":3,"bonne":0,"mnemo":"Crise = surtout PAS d'aspirine."}],"dys-obesite":[{"q":"À partir de quelle valeur d'IMC parle-t-on de surpoids ?","options":["IMC ≥ 25 kg/m²","IMC ≥ 30 kg/m²","IMC ≥ 18 kg/m²","IMC ≥ 40 kg/m²"],"explication":"Le surpoids correspond à un IMC ≥ 25 et l'obésité à un IMC ≥ 30 kg/m².","niveau":1,"bonne":0,"mnemo":"Surpoids ≥ 25, obésité ≥ 30."},{"q":"Comment nomme-t-on l'obésité abdominale, surtout retrouvée chez les hommes ?","options":["Obésité androïde","Obésité gynoïde","Obésité brune","Obésité lymphatique"],"explication":"L'obésité androïde est abdominale (surtout chez l'homme) ; la gynoïde touche hanches/cuisses (surtout chez la femme).","niveau":1,"bonne":0,"mnemo":"Androïde = ventre (homme)."},{"q":"Quel complément est cité pour diminuer l'absorption des graisses dans l'obésité ?","options":["Le chitosan","Le chrome","Le griffonia","Le psyllium"],"explication":"Le chitosan diminue l'absorption des graisses ; le chrome gère le sucre, le griffonia régule les fringales et le psyllium agit sur le transit.","niveau":2,"bonne":0,"mnemo":"Chitosan = piège à graisses."},{"q":"Quelle répartition d'assiette est conseillée dans l'obésité ?","options":["½ légumes, ¼ protéines, ¼ féculents","½ féculents, ¼ légumes, ¼ protéines","Uniquement des protéines","½ produits laitiers, ½ féculents"],"explication":"On conseille une assiette plus petite répartie en ½ légumes, ¼ protéines, ¼ féculents.","niveau":2,"bonne":0,"mnemo":"Moitié légumes, deux quarts protéines/féculents."},{"q":"Selon le cours, quelle cause émotionnelle est explicitement associée au surpoids ?","options":["Le manque d'amour (armure, réconfort)","L'excès d'amour-propre","La pratique excessive de sport","Le surplus de sommeil"],"explication":"Le cours indique que le manque d'amour est une cause de surpoids (armure, réconfort) : on guérit les blessures émotionnelles.","niveau":3,"bonne":0,"mnemo":"Manque d'amour = cause de surpoids."}],"dys-cholesterol":[{"q":"Quel rôle joue le HDL selon le cours ?","options":["Il ramène le cholestérol au foie (protecteur)","Il transporte le cholestérol vers les tissus","Il forme la plaque d'athérome","Il est le « mauvais » cholestérol"],"explication":"Le HDL est le « bon » cholestérol : il ramène le cholestérol au foie. Le LDL le transporte vers les tissus.","niveau":1,"bonne":0,"mnemo":"HDL = Home (ramène au foie)."},{"q":"Quel est le signe clinique habituel d'une dyslipidémie ?","options":["Le plus souvent asymptomatique","Douleur brutale du gros orteil","Bouffées de chaleur","Polyurie et polydipsie"],"explication":"La dyslipidémie est le plus souvent asymptomatique, découverte au bilan sanguin ; le risque est l'athérome à terme.","niveau":1,"bonne":0,"mnemo":"Silencieux jusqu'à l'athérome."},{"q":"Pourquoi l'exercice en plein air est-il conseillé dans la dyslipidémie ?","options":["Parce qu'il augmente le HDL","Parce qu'il augmente le LDL","Parce qu'il élève les triglycérides","Parce qu'il oxyde le LDL"],"explication":"L'exercice régulier en plein air augmente le HDL (le cholestérol protecteur).","niveau":2,"bonne":0,"mnemo":"Bouger dehors = HDL ↑."},{"q":"Quel rôle jouent les antioxydants dans la dyslipidémie ?","options":["Ils protègent le LDL de l'oxydation","Ils oxydent le LDL","Ils augmentent les triglycérides","Ils transforment le HDL en LDL"],"explication":"Les antioxydants protègent le LDL de l'oxydation, étape clé de la formation de la plaque d'athérome.","niveau":2,"bonne":0,"mnemo":"Antioxydants = bouclier anti-oxydation du LDL."},{"q":"Selon le cours, qu'est-ce qui rend réellement le cholestérol dangereux pour les artères ?","options":["Le LDL oxydé qui se dépose et forme la plaque d'athérome","Le HDL qui s'accumule dans les artères","Le cholestérol total, quel qu'il soit","Les triglycérides à eux seuls sans LDL"],"explication":"Ce n'est pas le cholestérol en soi mais le LDL oxydé qui se dépose dans l'intima et forme la plaque d'athérome ; on vise le LDL oxydé et les triglycérides, pas le cholestérol total seul.","niveau":3,"bonne":0,"mnemo":"Pas le cholestérol : le LDL OXYDÉ."}],"dys-syndrome-metabolique":[{"q":"Le syndrome métabolique est avant tout…","options":["Un faisceau de facteurs de risque associés","Une maladie infectieuse","Une tumeur bénigne","Une carence en iode"],"explication":"Ce n'est pas une maladie unique mais l'association de facteurs : obésité abdominale, HTA, hyperglycémie/insulinorésistance et dyslipidémie.","niveau":1,"bonne":0,"mnemo":"Faisceau : ventre + tension + sucre + lipides."},{"q":"Quelle est la racine commune du syndrome métabolique ?","options":["L'insulinorésistance","L'hyperuricémie","La carence en iode","L'hyperœstrogénie"],"explication":"L'insulinorésistance est la racine commune qui relie les différents facteurs.","niveau":1,"bonne":0,"mnemo":"Racine = insulinorésistance."},{"q":"Vers quelles pathologies le syndrome métabolique prédispose-t-il ?","options":["Le diabète de type II et les maladies cardiovasculaires","L'hyperthyroïdie et le goitre","La goutte et les calculs rénaux","L'hypothyroïdie auto-immune"],"explication":"Il prédispose au diabète de type II et aux maladies cardiovasculaires (athérome).","niveau":2,"bonne":0,"mnemo":"Antichambre du diabète II + cœur."},{"q":"Quels leviers naturo sont prioritaires dans le syndrome métabolique ?","options":["Alimentation à IG bas riche en fibres + activité physique régulière","Apport massif d'iode et de tyrosine","Suppression totale des fibres","Augmentation des sucres rapides"],"explication":"On vise un IG bas riche en fibres et bonnes graisses, plus une activité physique régulière (le muscle consomme le glucose).","niveau":2,"bonne":0,"mnemo":"IG bas + BOUGER."},{"q":"En quoi le syndrome métabolique se distingue-t-il du diabète de type II installé ?","options":["C'est un signal d'alerte réversible qui précède souvent le diabète","C'est une glycémie franchement et durablement élevée","Il ne concerne jamais la graisse abdominale","Il est toujours irréversible"],"explication":"Le syndrome métabolique précède souvent le diabète de type II : c'est un signal d'alerte réversible par l'hygiène de vie, à distinguer du diabète installé.","niveau":3,"bonne":0,"mnemo":"Alerte réversible, AVANT le diabète."}],"dys-hypoglycemie":[{"q":"Qu'est-ce qui déclenche l'hypoglycémie réactionnelle ?","options":["Un repas à index glycémique élevé","Un excès de protéines animales","Une carence en iode","Un excès d'acide urique"],"explication":"Un repas à IG élevé provoque un pic de glucose, puis une sécrétion excessive d'insuline qui fait chuter la glycémie.","niveau":1,"bonne":0,"mnemo":"Sucre rapide → pic → chute."},{"q":"Quel symptôme est typique de l'hypoglycémie réactionnelle ?","options":["Coup de fatigue après les repas avec fringales de sucre","Crise nocturne du gros orteil","Bouffées de chaleur","Goitre et exophtalmie"],"explication":"Coup de pompe/somnolence après le repas, fringales (surtout de sucre), tremblements et malaise soulagé par la prise de sucre.","niveau":1,"bonne":0,"mnemo":"Coup de pompe + fringale post-repas."},{"q":"Quel est le principal levier alimentaire contre l'hypoglycémie réactionnelle ?","options":["Un index glycémique bas/moyen avec protéines et bonnes graisses","Augmenter les sucres rapides","Sauter des repas","Multiplier les grignotages sucrés"],"explication":"On mange à IG bas/moyen avec fibres, protéines et bonnes graisses, sans sauter de repas ni grignoter sucré.","niveau":2,"bonne":0,"mnemo":"IG bas + ne pas sauter de repas."},{"q":"Quel oligo-élément aide à réduire les compulsions sucrées dans l'hypoglycémie réactionnelle ?","options":["Le chrome","L'iode","Le sélénium","Le cuivre"],"explication":"Le chrome aide à réduire les compulsions sucrées et améliore l'insulinosensibilité ; le magnésium est aussi cité.","niveau":2,"bonne":0,"mnemo":"Chrome = anti-fringale."},{"q":"Comment distinguer l'hypoglycémie réactionnelle de l'hypoglycémie du diabétique traité ?","options":["La réactionnelle survient après un repas sucré ; celle du diabétique est liée aux médicaments/insuline et est une urgence","Les deux sont strictement identiques","La réactionnelle est une urgence vitale, l'autre est bénigne","La réactionnelle est causée par l'insuline injectée"],"explication":"L'hypoglycémie réactionnelle est une chute après un repas sucré (fréquente, fonctionnellement l'inverse du diabète) ; celle du diabétique sous traitement est liée aux médicaments/insuline et constitue une urgence.","niveau":3,"bonne":0,"mnemo":"Réactionnelle = post-repas ; diabétique = médicaments/urgence."}],"dys-acido-basique":[{"q":"Quels organes assurent le nettoyage nocturne des acides ?","options":["Les poumons et les reins","Le foie et la rate","L'estomac et le pancréas","La peau et les os"],"explication":"Les acides produits par la digestion et le métabolisme sont nettoyés la nuit par les poumons et les reins.","niveau":1,"bonne":0,"mnemo":"Nuit = poumons + reins nettoient."},{"q":"Quelle forme d'acidose le cours décrit-il principalement ?","options":["Une acidose tissulaire de terrain (chronique)","Une alcalose respiratoire aiguë","Une acidose métabolique aiguë médicale","Une acidose gastrique passagère"],"explication":"Il s'agit d'une acidose tissulaire de terrain (chronique, naturopathique), à distinguer d'une acidose métabolique aiguë médicale.","niveau":1,"bonne":0,"mnemo":"Terrain qui s'acidifie, pas l'urgence."},{"q":"Quel apport alimentaire favorise l'excès d'acides ?","options":["L'excès de sucre et de protéines animales","Les fruits et légumes","Le jus de citron dans l'eau tiède","La cuisson vapeur"],"explication":"Suralimentation, sucre et protéines animales produisent trop d'acides ; fruits/légumes et citron aident au contraire à alcaliniser.","niveau":2,"bonne":0,"mnemo":"Sucre + protéines animales = acidifiants."},{"q":"Pourquoi l'exercice physique aide-t-il l'équilibre acido-basique ?","options":["Parce qu'il élimine les acides par la sudation","Parce qu'il augmente la production d'acides","Parce qu'il épuise les tampons","Parce qu'il acidifie les tissus"],"explication":"L'exercice élimine les acides par la sudation, contribuant à rétablir l'équilibre.","niveau":2,"bonne":0,"mnemo":"Suer = évacuer les acides."},{"q":"Quel ensemble de substances joue le rôle de tampons pour neutraliser l'excès d'acides ?","options":["Citrates, bicarbonate, potassium, magnésium, enzymes et vitamines","Acide urique et purines","LDL et triglycérides","Iode et tyrosine"],"explication":"Les tampons cités sont les citrates, le bicarbonate, le potassium, le magnésium, les enzymes et les vitamines ; leur insuffisance favorise l'acidose.","niveau":3,"bonne":0,"mnemo":"Tampons : citrates/bicarbonate + K/Mg + enzymes/vitamines."}],"dys-insomnie":[{"q":"Selon la fiche, une insomnie est considérée comme chronique quand elle survient :","options":["Au moins 3 nuits par semaine pendant au moins 1 mois","Toutes les nuits pendant 1 semaine","Au moins 1 nuit par semaine pendant 6 mois","Dès la première mauvaise nuit"],"explication":"La fiche définit l'insomnie chronique comme présente au moins 3 nuits par semaine pendant au moins 1 mois.","niveau":1,"bonne":0,"mnemo":"Chronique = 3 nuits/semaine x 1 mois."},{"q":"Quelle huile essentielle la fiche propose-t-elle en diffusion pour favoriser le sommeil ?","options":["Lavande vraie","Menthe poivrée","Pin sylvestre","Origan"],"explication":"La fiche cite en diffusion : bergamote, mandarine, petit grain bigarade, lavande vraie, ylang-ylang.","niveau":1,"bonne":0,"mnemo":"Diffusion sommeil = agrumes doux + lavande + ylang-ylang."},{"q":"Pour l'alimentation du soir, la fiche recommande :","options":["Des repas légers, sans sucre, graisses saturées, laitages ni café","Un repas riche et copieux pour bien dormir","Beaucoup de produits laitiers","Un café léger après le dîner"],"explication":"La fiche conseille des repas légers le soir, sans sucre, graisses saturées, produits laitiers ni café, et de favoriser les précurseurs de la sérotonine/mélatonine.","niveau":2,"bonne":0,"mnemo":"Soir = léger, et on coupe sucre/laitages/café."},{"q":"Sur quel axe biochimique la fiche propose-t-elle d'agir en priorité dans l'insomnie ?","options":["L'axe sérotonine → mélatonine","L'axe insuline → glucagon","L'axe rénine → angiotensine","L'axe TSH → T4"],"explication":"La fiche recommande de soutenir l'axe sérotonine → mélatonine (précurseurs, griffonia/5-HTP).","niveau":2,"bonne":0,"mnemo":"Sérotonine d'abord, mélatonine ensuite."},{"q":"Pourquoi la fiche signale-t-elle une précaution particulière avec le millepertuis dans l'insomnie à versant dépressif ?","options":["Il est photosensibilisant et inducteur enzymatique (interactions médicamenteuses)","Il est gabaergique et provoque une dépendance","Il abaisse fortement la calcémie","Il est uniquement réservé aux enfants"],"explication":"La fiche précise que le millepertuis est photosensibilisant et inducteur enzymatique, d'où des interactions médicamenteuses.","niveau":3,"bonne":0,"mnemo":"Millepertuis = soleil + interactions médocs."}],"dys-stress":[{"q":"Quel oligo-élément la fiche cite-t-elle dans la micronutrition du stress/dépression ?","options":["Le lithium","Le fluor","L'iode","Le silicium"],"explication":"La fiche mentionne le lithium (oligo-élément) parmi les compléments du stress et de la dépression.","niveau":1,"bonne":0,"mnemo":"Stress = lithium en oligo."},{"q":"Quel bourgeon (gemmothérapie) la fiche associe-t-elle au soutien des surrénales en phase d'épuisement ?","options":["Cassis","Figuier","Tilleul","Aubépine"],"explication":"La fiche cite le cassis pour soutenir les surrénales (et le framboisier comme régulateur hormonal).","niveau":1,"bonne":0,"mnemo":"Surrénales épuisées = cassis."},{"q":"Pour le mouvement, la fiche insiste sur une activité physique :","options":["En plein air, qui décharge le stress et relance la dopamine","Intense et le soir tard","En salle uniquement, sans lumière","Limitée à des étirements passifs"],"explication":"La fiche recommande une activité physique en plein air, qui décharge le stress et relance la dopamine.","niveau":2,"bonne":0,"mnemo":"Dehors = dopamine, stress déchargé."},{"q":"Quelle plante la fiche associe-t-elle spécifiquement aux palpitations dans le contexte du stress ?","options":["Aubépine","Mélisse","Ginseng","Valériane"],"explication":"La fiche relie l'aubépine aux palpitations et la mélisse aux spasmes digestifs.","niveau":2,"bonne":0,"mnemo":"Coeur qui s'emballe = aubépine."},{"q":"Quelle différence d'action la fiche établit-elle entre adaptogènes et gabaergiques ?","options":["Les adaptogènes aident à s'adapter au stress / soutiennent les surrénales, les gabaergiques calment l'instant","Les adaptogènes calment l'instant, les gabaergiques soutiennent les surrénales","Les deux agissent uniquement sur la calcémie","Les deux sont des photosensibilisants"],"explication":"La fiche distingue les adaptogènes (ginseng, rhodiola, ashwagandha : adaptation au stress, soutien surrénalien) des gabaergiques (valériane, passiflore : apaisent l'instant).","niveau":3,"bonne":0,"mnemo":"Adaptogène = fond ; gabaergique = instant."}],"dys-acouphenes":[{"q":"Comment la fiche décrit-elle un acouphène ?","options":["Une sensation auditive (sifflements, bourdonnements) sans source extérieure","Une douleur de l'oreille avec écoulement","Une perte totale et brutale de l'audition","Une infection bactérienne du tympan"],"explication":"La fiche définit l'acouphène comme une sensation auditive anormale (sifflements, bourdonnements) sans source extérieure.","niveau":1,"bonne":0,"mnemo":"Son fantôme = acouphène."},{"q":"Quelle vitamine la fiche cite-t-elle dans la micronutrition des acouphènes ?","options":["Vitamine B12","Vitamine K","Vitamine A","Vitamine E"],"explication":"La micronutrition de la fiche comprend la vitamine B12, les oméga 3, le zinc, le magnésium et la N-acétyl-cystéine.","niveau":1,"bonne":0,"mnemo":"Acouphène = B12 + zinc + Mg + NAC + oméga 3."},{"q":"Parmi ces métaux, lequel la fiche conseille-t-elle d'éliminer dans l'accompagnement des acouphènes ?","options":["Le mercure","Le calcium","Le potassium","Le sodium"],"explication":"Dans les \"autres\" approches, la fiche mentionne d'éliminer le mercure.","niveau":2,"bonne":0,"mnemo":"Acouphènes = chasser le mercure."},{"q":"Quelle approche non médicamenteuse la fiche cite-t-elle pour les acouphènes ?","options":["La méthode Tomatis / le masquage sonore","La photothérapie dynamique","La dialyse","La chirurgie bariatrique"],"explication":"La fiche liste notamment TRT, masquage sonore, neurofeedback, acupuncture, méthode Tomatis et tambour céleste.","niveau":2,"bonne":0,"mnemo":"Apaiser l'oreille = TRT, masquage, Tomatis."},{"q":"Pourquoi la fiche insiste-t-elle sur l'identification de la cause d'un acouphène ?","options":["Parce que les origines sont très variées, du bouchon de cérumen à la maladie de Ménière","Parce que la cause est toujours une infection virale","Parce que c'est toujours d'origine génétique","Parce que la cause est sans intérêt pour l'accompagnement"],"explication":"La fiche souligne des origines très variées (cérumen, médicaments, traumatisme sonore, Ménière, ATM...), d'où l'importance d'identifier la cause.","niveau":3,"bonne":0,"mnemo":"Acouphène = symptôme, on cherche la cause."}],"dys-fatigue-chronique":[{"q":"Quelle tranche d'âge est principalement touchée par le syndrome de fatigue chronique selon la fiche ?","options":["Les adultes jeunes de 20-40 ans","Les enfants de moins de 10 ans","Les nourrissons","Les personnes de plus de 80 ans exclusivement"],"explication":"La fiche indique que le SFC touche les adultes jeunes (20-40 ans).","niveau":1,"bonne":0,"mnemo":"SFC = jeunes adultes 20-40 ans."},{"q":"Quelle plante détox du foie la fiche cite-t-elle pour le SFC ?","options":["Chardon-marie","Valériane","Ginkgo biloba","Bacopa"],"explication":"La fiche liste chardon-marie, desmodium, boldo, artichaut, ail et radis noir pour le foie.","niveau":1,"bonne":0,"mnemo":"Foie encrassé = chardon-marie & co."},{"q":"Quel régime alimentaire la fiche mentionne-t-elle nommément pour le SFC ?","options":["Le régime Seignalet","Le régime cétogène strict","Le régime Dukan","Le jeûne sec prolongé"],"explication":"La fiche cite le régime Seignalet, ainsi que le test des intolérances (gluten, laitages, œufs).","niveau":2,"bonne":0,"mnemo":"SFC = Seignalet + tester les intolérances."},{"q":"Quelle durée de rétablissement la fiche évoque-t-elle pour le SFC ?","options":["Une prise en charge longue, rétablissement d'environ 5 ans","Une guérison en quelques jours","Environ 6 semaines","Aucune amélioration possible"],"explication":"La fiche parle d'une prise en charge longue, avec un rétablissement d'environ 5 ans.","niveau":2,"bonne":0,"mnemo":"SFC = patience, ~5 ans."},{"q":"Sur quel point la fiche insiste-t-elle pour distinguer le SFC d'une dépression ?","options":["Il apparaît soudainement chez une personne non dépressive (diagnostic d'exclusion)","Il s'installe toujours très progressivement chez une personne déprimée","Il disparaît avec un simple repos","Il ne touche jamais le sommeil"],"explication":"La fiche précise que le SFC survient soudainement chez une personne non dépressive et qu'il s'agit d'un diagnostic d'exclusion.","niveau":3,"bonne":0,"mnemo":"SFC = soudain + non dépressif."}],"dys-burnout":[{"q":"À quelle phase du syndrome général d'adaptation le burn-out correspond-il selon la fiche ?","options":["La phase d'épuisement","La phase d'alarme","La phase de résistance","Une phase d'euphorie"],"explication":"La fiche rattache le burn-out à la phase d'épuisement du syndrome général d'adaptation.","niveau":1,"bonne":0,"mnemo":"Burn-out = bout de la course = épuisement."},{"q":"Quel bourgeon (gemmothérapie) la fiche cite-t-elle pour le burn-out ?","options":["Cassis","Figuier","Noisetier","Tilleul"],"explication":"La gemmothérapie de la fiche burn-out se résume au cassis (soutien surrénalien).","niveau":1,"bonne":0,"mnemo":"Épuisement = cassis pour les surrénales."},{"q":"Quel micronutriment anti-inflammatoire, en plus des classiques, la fiche ajoute-t-elle dans le burn-out ?","options":["Le curcuma","Le fluor","Le sodium","L'iode"],"explication":"La fiche burn-out ajoute le curcuma à magnésium+B6, vitamines B/D, fer, zinc, oméga 3, glutamine et lithium.","niveau":2,"bonne":0,"mnemo":"Burn-out = +curcuma anti-inflammatoire."},{"q":"Quels déséquilibres biochimiques la fiche met-elle en jeu dans le burn-out ?","options":["Un déséquilibre des neuromédiateurs (sérotonine, dopamine, adrénaline, cortisol)","Une carence isolée en vitamine C","Un excès de calcium sanguin","Une surproduction d'insuline uniquement"],"explication":"La fiche évoque un déséquilibre des neuromédiateurs (sérotonine, dopamine, adrénaline, cortisol) et un terrain d'encrassage.","niveau":2,"bonne":0,"mnemo":"Burn-out = neuromédiateurs en vrac + encrassage."},{"q":"Selon la fiche, qu'est-ce qui distingue le burn-out (proche du SFC) d'une dépression simple ?","options":["Le SFC/épuisement apparaît chez une personne non dépressive","Le burn-out ne touche jamais le moral","La dépression dure forcément plus de 6 mois","Le burn-out se soigne en une semaine"],"explication":"La fiche rappelle que le burn-out recoupe la fatigue chronique, laquelle survient chez une personne non dépressive, à distinguer de la dépression simple.","niveau":3,"bonne":0,"mnemo":"Épuisement n'est pas dépression."}],"dys-memoire":[{"q":"Quelle plante la fiche cite-t-elle pour la mémoire et l'apprentissage (en plus du ginkgo) ?","options":["Bacopa monnieri","Valériane","Passiflore","Chardon-marie"],"explication":"La fiche cite le bacopa monnieri pour la mémoire et l'apprentissage.","niveau":1,"bonne":0,"mnemo":"Mémoire = ginkgo + bacopa."},{"q":"Quel oligo-élément ou cofacteur énergétique la fiche cite-t-elle pour la mémoire ?","options":["Coenzyme Q10","Lithium","Iode","Calcium"],"explication":"La micronutrition de la fiche comprend zinc, magnésium, coenzyme Q10, fer et acide folique.","niveau":1,"bonne":0,"mnemo":"Mémoire = zinc, Mg, CoQ10, fer, folates."},{"q":"Quelle plante la fiche associe-t-elle spécifiquement à la circulation cérébrale ?","options":["La petite pervenche","La mélisse","L'aubépine","Le tilleul"],"explication":"La fiche cite la petite pervenche pour la circulation cérébrale, à côté du ginkgo et du bacopa.","niveau":2,"bonne":0,"mnemo":"Pervenche = circulation du cerveau."},{"q":"Comment la fiche utilise-t-elle les huiles essentielles (citron, menthe poivrée, basilic, pin sylvestre) pour la mémoire ?","options":["Par olfaction","En injection","En cataplasme sur la nuque","En tisane bouillante"],"explication":"La fiche propose ces huiles essentielles par olfaction.","niveau":2,"bonne":0,"mnemo":"Mémoire & HE = on respire (olfaction)."},{"q":"Pourquoi la fiche insiste-t-elle sur la recherche de la cause d'un trouble de la mémoire ?","options":["Parce que c'est un symptôme aux causes variées (du surmenage à Alzheimer/Parkinson), pas une maladie","Parce que la cause est toujours une carence en fer","Parce que c'est toujours dû au vieillissement seul","Parce qu'il n'existe aucune cause identifiable"],"explication":"La fiche rappelle que les troubles de mémoire sont un symptôme à causes variées (surmenage, stress, Alzheimer, Parkinson, médicaments...), d'où l'importance de chercher la cause.","niveau":3,"bonne":0,"mnemo":"Mémoire = symptôme, on traque la cause."}],"dys-spasmophilie":[{"q":"La spasmophilie est définie par la fiche comme une hyperexcitabilité neuromusculaire :","options":["Sans anomalie calcique, dans un contexte d'anxiété","Avec hypercalcémie majeure","Liée à une carence en fer isolée","Due à un excès de magnésium"],"explication":"La fiche définit la spasmophilie comme une hyperexcitabilité neuromusculaire chronique, sans anomalie calcique, sur fond d'anxiété.","niveau":1,"bonne":0,"mnemo":"Spasmo = excitable, calcium normal, anxiété."},{"q":"Quel bourgeon (gemmothérapie) la fiche cite-t-elle pour la spasmophilie ?","options":["Figuier","Cassis","Tilleul","Noisetier"],"explication":"La fiche cite le bourgeon de figuier en gemmothérapie pour la spasmophilie.","niveau":1,"bonne":0,"mnemo":"Spasmo = figuier (bourgeon)."},{"q":"Quels aliments la fiche recommande-t-elle comme source de magnésium dans la spasmophilie ?","options":["Fruits secs et oléagineux","Charcuteries et fritures","Sodas et confiseries","Café et thé fort"],"explication":"La fiche conseille une alimentation riche en fruits et légumes, fruits secs et oléagineux (source de magnésium), en évitant les excitants.","niveau":2,"bonne":0,"mnemo":"Magnésium = oléagineux et fruits secs."},{"q":"Quelle fleur de Bach figure dans le complexe proposé par la fiche pour la spasmophilie ?","options":["Rescue / Rock Rose","Échinacée","Millepertuis","Spiruline"],"explication":"La fiche propose les Fleurs de Bach : Rescue, Rock Rose, White Chestnut, Star of Bethlehem.","niveau":2,"bonne":0,"mnemo":"Spasmo + Bach = Rescue & Rock Rose."},{"q":"Pourquoi, en cas de tétanie, la fiche conseille-t-elle de respirer dans un sac plastique ?","options":["Parce que l'acidose ainsi créée remonte la calcémie","Parce que cela augmente l'oxygène disponible","Parce que cela abaisse le magnésium","Parce que cela fait baisser la glycémie"],"explication":"La fiche explique que respirer dans un sac provoque une acidose qui remonte la calcémie (geste de crise de tétanie).","niveau":3,"bonne":0,"mnemo":"Sac = acidose = calcémie qui remonte."}],"dys-algodystrophie":[{"q":"Quel mécanisme vasculaire est en jeu dans l'algodystrophie ?","options":["Une vasodilatation permanente des artères","Une vasoconstriction chronique liée à l'emballement du sympathique","Une obstruction des veines par des caillots","Une absence totale de circulation"],"explication":"L'hyper-sollicitation du système sympathique entraîne une vasoconstriction chronique, à l'origine du défaut de vascularisation locale.","niveau":1,"bonne":1,"mnemo":"Sympathique en feu = vaisseaux serrés."},{"q":"Quel aspect cutané est typique de l'algodystrophie ?","options":["Peau épaisse et rugueuse","Peau mince, brillante et sèche","Peau jaune et squameuse","Peau froide et bleue sans modification"],"explication":"Les troubles trophiques et vasomoteurs donnent une peau mince, brillante, sèche, avec sudation accrue.","niveau":1,"bonne":1,"mnemo":"Peau qui brille = trophique perturbée."},{"q":"Parmi ces causes, laquelle est citée comme étiologie médicamenteuse de l'algodystrophie ?","options":["Les antibiotiques fluoroquinolones","Les barbituriques, l'iode radioactive et le rimifon","Les anti-inflammatoires classiques","Les statines"],"explication":"Le cours cite barbituriques, iode radioactive et rimifon comme causes médicamenteuses de l'algodystrophie.","niveau":2,"bonne":1,"mnemo":"Barbituriques + iode radioactive + rimifon."},{"q":"Quelle plante est conseillée dans l'algodystrophie pour lutter contre la déminéralisation ?","options":["Le saule","La prêle","La reine des prés","L'harpagophytum"],"explication":"La prêle est indiquée contre la déminéralisation, ce qui est cohérent avec le risque d'ostéoporose mouchetée.","niveau":2,"bonne":1,"mnemo":"Prêle = reminéralise (silice)."},{"q":"En quoi l'algodystrophie se distingue-t-elle d'une simple suite de traumatisme ?","options":["La douleur est proportionnée et guérit normalement","La douleur est disproportionnée et d'origine neurovégétative, pas une simple lésion locale","Il n'y a jamais eu de traumatisme déclencheur","Elle ne touche que les enfants"],"explication":"Ce n'est pas une lésion locale qui guérit normalement : la douleur est disproportionnée et liée à l'emballement du sympathique.","niveau":3,"bonne":1,"mnemo":"Douleur qui s'EMBALLE, pas proportionnée."}],"dys-arthrose":[{"q":"L'arthrose correspond à une dégénérescence de quelle structure ?","options":["Du ligament","Du cartilage, sans inflammation","De la membrane synoviale par auto-anticorps","Du tendon"],"explication":"L'arthrose est une affection mécanique avec dégénérescence du cartilage sans inflammation.","niveau":1,"bonne":1,"mnemo":"ArthrOse = cartilage qui s'usE."},{"q":"Quelle excroissance osseuse est caractéristique de l'arthrose ?","options":["Les nodules rhumatoïdes","Les ostéophytes","Les calculs","Les kystes synoviaux"],"explication":"L'arthrose entraîne décalcification et formation d'ostéophytes.","niveau":1,"bonne":1,"mnemo":"Arthrose → ostéophytes (bec osseux)."},{"q":"Quels micronutriments sont cités pour soutenir le cartilage dans l'arthrose ?","options":["Glucosamine et chondroïtine","Fer et cuivre","Iode et sélénium seuls","Calcium et phosphore uniquement"],"explication":"La glucosamine et la chondroïtine figurent parmi les micronutriments conseillés pour le cartilage.","niveau":2,"bonne":0,"mnemo":"Glucosamine + chondroïtine = cartilage."},{"q":"Pourquoi l'organisme déclenche-t-il l'inflammation dans l'arthrite selon le cours ?","options":["Pour détruire le cartilage volontairement","Pour éviter la calcification des déchets","Pour réchauffer l'articulation","Sans aucune raison physiologique"],"explication":"Le cours présente l'inflammation comme un phénomène naturel pour éviter la calcification des déchets.","niveau":2,"bonne":1,"mnemo":"Inflammation = éviter de calcifier les déchets."},{"q":"Une douleur articulaire nocturne, non calmée par le repos, oriente plutôt vers :","options":["Une arthrose","Une arthrite","Une entorse","Une fibromyalgie isolée"],"explication":"L'arthrite est inflammatoire : douleur la nuit, non calmée par le repos, à l'inverse de l'arthrose (douleur diurne soulagée au repos).","niveau":3,"bonne":1,"mnemo":"Nuit + repos inutile = arthrIte."}],"dys-entorse":[{"q":"Quelle articulation est la plus souvent touchée par une entorse ?","options":["L'épaule","La cheville","Le poignet","La hanche"],"explication":"L'entorse touche souvent la cheville, par mobilisation excessive de l'articulation.","niveau":1,"bonne":1,"mnemo":"Entorse = cheville (le grand classique)."},{"q":"Quelle complication peut suivre une entorse ?","options":["Une ostéoporose mouchetée","Une rupture ligamentaire et de l'arthrose","Une polyarthrite rhumatoïde","Une fibromyalgie"],"explication":"Les complications citées sont la rupture ligamentaire et l'arthrose.","niveau":1,"bonne":1,"mnemo":"Entorse mal soignée → rupture / arthrose."},{"q":"Quel micronutriment est conseillé dans l'entorse pour désenfler ?","options":["La bromélaïne","Le silicium","La vitamine D","Le magnésium"],"explication":"La bromélaïne est citée pour désenfler, avec le MSM et le cataplasme d'argile verte.","niveau":2,"bonne":0,"mnemo":"Bromélaïne = dégonfle."},{"q":"Quels facteurs favorisent l'apparition d'une entorse ?","options":["Un bon échauffement et un équipement adapté","Un mauvais échauffement, la fatigue musculaire et un équipement inadapté","Une activité physique modérée régulière","Une alimentation alcalinisante"],"explication":"Mauvais échauffement, fatigue musculaire et équipement inadapté sont les facteurs cités.","niveau":2,"bonne":1,"mnemo":"Pas d'échauffement + fatigue = entorse."},{"q":"En aigu sur une entorse, quelle conduite est correcte ?","options":["Masser et chauffer la zone","Ne pas masser et ne pas chauffer, appliquer le protocole RGCE","Forcer le mouvement pour assouplir","Appliquer une chaleur intense"],"explication":"Contrairement à d'autres douleurs ostéo-articulaires, en aigu on ne masse pas et on ne chauffe pas : on applique RGCE (Repos, Glace, Compression, Élévation).","niveau":3,"bonne":1,"mnemo":"Entorse aiguë = glace, pas de chaleur ni massage."}],"dys-fibromyalgie":[{"q":"Quelles structures sont principalement douloureuses dans la fibromyalgie ?","options":["Les os et les disques","Les tendons et les muscles","Les ligaments uniquement","La membrane synoviale"],"explication":"La fibromyalgie est un syndrome polyalgique diffus touchant les tendons et les muscles.","niveau":1,"bonne":1,"mnemo":"Fibro = tendons + muscles, partout."},{"q":"Quelle caractéristique du sommeil est associée à la fibromyalgie ?","options":["Un sommeil profond et réparateur","Un sommeil non réparateur","Une absence totale de sommeil","Un excès de sommeil sans fatigue"],"explication":"La fibromyalgie associe douleurs diffuses, symptômes psychiques et sommeil non réparateur.","niveau":1,"bonne":1,"mnemo":"Sommeil cassé = signe fibro."},{"q":"Parmi ces déclencheurs, lequel est cité dans l'étiologie de la fibromyalgie ?","options":["Une fracture isolée","Un choc émotionnel comme un deuil","Une carence en fer simple","Un excès d'exercice physique sain"],"explication":"Un choc émotionnel (stress, deuil) ou physique (accident) figure parmi les causes.","niveau":2,"bonne":1,"mnemo":"Choc émotionnel = porte d'entrée fibro."},{"q":"Quelle posologie de zinc est proposée dans la fibromyalgie ?","options":["2000 UI/j","10 mg/j","100 mg/j","1 g/j"],"explication":"Le cours propose le zinc à 10 mg/j (la vitamine D étant à 2000 UI/j).","niveau":2,"bonne":1,"mnemo":"Zinc 10 mg, vit D 2000 UI."},{"q":"Pourquoi la fibromyalgie est-elle qualifiée d'idiopathique ?","options":["Parce qu'elle a une cause inflammatoire articulaire évidente","Parce qu'aucune cause organique n'est identifiée","Parce qu'elle est toujours d'origine génétique connue","Parce qu'elle guérit spontanément"],"explication":"Idiopathique signifie sans cause organique identifiée ; à ne pas confondre avec une maladie inflammatoire articulaire ou un simple surmenage.","niveau":3,"bonne":1,"mnemo":"Idiopathique = sans cause organique trouvée."}],"dys-hernie-discale":[{"q":"Une hernie discale correspond à :","options":["Une inflammation de la synoviale","Une saillie anormale d'un disque intervertébral dans le canal rachidien","Une rupture d'un tendon","Une fracture de vertèbre"],"explication":"C'est la saillie anormale d'un disque intervertébral dans le canal rachidien, comprimant une racine nerveuse.","niveau":1,"bonne":1,"mnemo":"Disque qui déborde → pince la racine."},{"q":"Quelles racines nerveuses correspondent au nerf sciatique ?","options":["C1-C4","L4-S3","T1-T6","S4-S5"],"explication":"La sciatique est une névralgie du nerf sciatique, racines L4-S3.","niveau":1,"bonne":1,"mnemo":"Sciatique = L4-S3."},{"q":"Quel trajet suit classiquement la douleur sciatique ?","options":["De la nuque vers le bras","De la fesse à l'arrière de la cuisse, mollet et orteils","Du thorax vers l'abdomen","Autour de la taille en ceinture"],"explication":"Le nerf sciatique traverse fesse, arrière de la cuisse, mollet et orteils.","niveau":2,"bonne":1,"mnemo":"Fesse-cuisse-mollet-orteils."},{"q":"Pour soulever une charge en prévention des problèmes de dos, le cours recommande de :","options":["Garder les jambes tendues et arrondir le dos","Plier les genoux et éviter la torsion","Soulever en tournant le tronc","Porter une ceinture lombaire en permanence"],"explication":"Il faut plier les genoux et éviter la torsion ; la ceinture lombaire, elle, affaiblit les muscles.","niveau":2,"bonne":1,"mnemo":"Plie les genoux, pas le dos."},{"q":"Quelle différence le cours fait-il entre hernie discale et sciatique ?","options":["Ce sont deux mots synonymes","La hernie est la lésion (disque qui sort), la sciatique en est la conséquence nerveuse (névralgie)","La hernie touche le nerf, la sciatique touche le disque","La sciatique cause la hernie dans 90 % des cas"],"explication":"La hernie discale est la lésion ; la sciatique est la conséquence nerveuse, la hernie en étant la cause dans 90 % des cas. Ce ne sont pas des synonymes.","niveau":3,"bonne":1,"mnemo":"Hernie = cause, sciatique = conséquence."}],"dys-polyarthrite":[{"q":"La polyarthrite rhumatoïde est une maladie :","options":["Mécanique non inflammatoire","Inflammatoire chronique auto-immune","Purement traumatique","Infectieuse aiguë"],"explication":"C'est un rhumatisme inflammatoire chronique auto-immun avec destruction du cartilage et des os.","niveau":1,"bonne":1,"mnemo":"PR = auto-immune + inflammatoire."},{"q":"Vers quelle structure les auto-anticorps de la PR sont-ils dirigés ?","options":["Le cartilage seul","La membrane synoviale","Le tendon","Le disque intervertébral"],"explication":"Les auto-anticorps sont dirigés vers la membrane synoviale.","niveau":1,"bonne":1,"mnemo":"PR attaque la synoviale."},{"q":"Quelle population est la plus touchée par la polyarthrite rhumatoïde ?","options":["Les hommes de 20-30 ans","Les femmes de 40-60 ans","Les enfants","Les sportifs de haut niveau uniquement"],"explication":"La PR touche surtout les femmes de 40 à 60 ans.","niveau":2,"bonne":1,"mnemo":"Femmes 40-60 ans."},{"q":"Quelle est la part de la prédisposition génétique citée dans la PR ?","options":["Environ 10 %","Environ 30 %","Environ 50 %","Environ 90 %"],"explication":"Le cours indique une prédisposition génétique de l'ordre de 30 %.","niveau":2,"bonne":1,"mnemo":"Génétique PR ≈ 30 %."},{"q":"Qu'est-ce qui distingue la PR de l'arthrose ?","options":["La PR est mécanique avec douleur diurne soulagée par le repos","La PR est auto-immune, symétrique, avec dérouillage matinal, alors que l'arthrose est mécanique et non auto-immune","L'arthrose est auto-immune et la PR est mécanique","Les deux donnent un dérouillage matinal identique"],"explication":"La PR est auto-immune, inflammatoire, symétrique avec dérouillage matinal ; l'arthrose est mécanique, non auto-immune, avec douleur diurne soulagée par le repos.","niveau":3,"bonne":1,"mnemo":"PR = auto-immune + symétrique + matin."}],"dys-tendinite":[{"q":"Une tendinite correspond à l'inflammation :","options":["D'un ligament","D'un tendon ou de sa gaine","D'un disque","De la membrane synoviale"],"explication":"La tendinite est l'inflammation d'un tendon ou de sa gaine.","niveau":1,"bonne":1,"mnemo":"TENDinite = TENDon."},{"q":"Comment évolue la douleur d'une tendinite avec le repos ?","options":["Elle s'aggrave au repos","Elle est atténuée par le repos","Elle est nocturne et non calmée par le repos","Elle reste identique jour et nuit"],"explication":"La douleur de la tendinite survient à la mobilisation et est atténuée par le repos.","niveau":1,"bonne":1,"mnemo":"Mal au mouvement, repos soulage."},{"q":"Quelle infection est citée comme pouvant favoriser une tendinite ?","options":["La grippe","La maladie de Lyme et ses coinfections","La gastro-entérite","La varicelle"],"explication":"La maladie de Lyme et ses coinfections, ainsi que des infections non traitées, sont citées dans l'étiologie.","niveau":2,"bonne":1,"mnemo":"Tendinite rebelle ? Pense à Lyme."},{"q":"Quel micronutriment reminéralisant est conseillé dans la tendinite ?","options":["Le lithothamne","La bromélaïne","La papaïne","La vitamine C"],"explication":"Le lithothamne est cité comme reminéralisant (la bromélaïne et la papaïne sont enzymatiques).","niveau":2,"bonne":0,"mnemo":"Lithothamne = reminéralise."},{"q":"Qu'est-ce qui distingue une tendinite d'une entorse ?","options":["La tendinite touche le ligament, l'entorse le tendon","La tendinite touche le tendon par surmenage, l'entorse le ligament à la suite d'un traumatisme","Les deux touchent le tendon","L'entorse est une inflammation chronique sans traumatisme"],"explication":"La tendinite touche le tendon (douleur au mouvement, soulagée par le repos) ; l'entorse touche le ligament à la suite d'un traumatisme.","niveau":3,"bonne":1,"mnemo":"Tendinite = tendon ; entorse = ligament."}],"dys-angine":[{"q":"L'angine correspond à l'inflammation de quelle structure ?","options":["Des amygdales","Du larynx","Des bronches","Des sinus"],"explication":"L'angine est une inflammation des amygdales ; on parle de pharyngite si le pharynx est atteint.","niveau":1,"bonne":0,"mnemo":"Angine = Amygdales."},{"q":"Quel signe oriente vers une angine bactérienne plutôt que virale ?","options":["Langue framboisée et exsudat","Voix enrouée","Fatigue","Ganglions cervicaux"],"explication":"La forme bactérienne se manifeste par un érythème pétéchial, une langue framboisée et un exsudat.","niveau":2,"bonne":0,"mnemo":"Framboise + exsudat = bactérie."},{"q":"Quel antibiotique est cité en cas d'angine bactérienne ?","options":["Amoxicilline","Doxycycline","Métoclopramide","Vérapamil"],"explication":"On cite l'amoxicilline et la phénoxyméthylpénicilline pour la forme bactérienne.","niveau":2,"bonne":0,"mnemo":"Bactérie = amoxicilline/pénicilline."},{"q":"Quelle plante est conseillée spécifiquement contre les streptocoques dans l'angine ?","options":["La ronce","Le plantain","La mauve","L'érysimum"],"explication":"La ronce est citée pour les streptocoques ; le plantain est décongestionnant, la mauve un mucilage, l'érysimum si aphone.","niveau":3,"bonne":0,"mnemo":"Ronce contre strepto."},{"q":"Que conseille-t-on après une cure d'antibiotiques dans l'angine ?","options":["Des probiotiques","Des antalgiques","Des gargarismes au citron","Des antiseptiques locaux"],"explication":"Les probiotiques sont recommandés après antibiotiques pour restaurer la flore.","niveau":1,"bonne":0,"mnemo":"Après antibio = probiotiques."}],"dys-asthme":[{"q":"L'asthme est une affection chronique de quelle structure ?","options":["Des bronches","Des amygdales","Du larynx","Des sinus"],"explication":"L'asthme est une affection chronique des bronches : hyperréactivité, inflammation, bronchoconstriction et mucus.","niveau":1,"bonne":0,"mnemo":"Asthme = bronches hyperréactives."},{"q":"Lequel de ces facteurs alimentaires est cité comme déclencheur de l'asthme ?","options":["Une alimentation riche en histamine","Une alimentation pauvre en sel","Un excès de fibres","Une carence en eau"],"explication":"L'alimentation riche en histamine (fromages, charcuterie, poissons, chocolat...) ainsi que les sulfites sont des déclencheurs.","niveau":2,"bonne":0,"mnemo":"Histamine + sulfites = crise."},{"q":"Quelle population est principalement touchée par l'asthme selon la fiche ?","options":["Les enfants et adolescents","Les personnes âgées","Les femmes enceintes","Les fumeurs uniquement"],"explication":"L'asthme touche les enfants et adolescents, sur un terrain d'atopie et génétique.","niveau":1,"bonne":0,"mnemo":"Asthme = jeunes + atopie."},{"q":"Quelle pratique est conseillée dans le pilier émotionnel de l'asthme ?","options":["La cohérence cardiaque","La course de vitesse","Le jeûne sec","Le sauna"],"explication":"Le pilier émotionnel propose cohérence cardiaque, relaxation, yoga et qi gong pour gérer le stress.","niveau":2,"bonne":0,"mnemo":"Stress = cohérence cardiaque."},{"q":"Parmi ces micronutriments, lequel est cité pour son rôle dans le glutathion dans l'asthme ?","options":["La cystéine","Le magnésium","Le zinc","La vitamine D"],"explication":"La cystéine est citée pour le glutathion ; le magnésium bloque l'histamine, distinct de ce rôle.","niveau":3,"bonne":0,"mnemo":"Cystéine = glutathion."}],"dys-bronchite":[{"q":"La bronchite est une inflammation de quelle structure ?","options":["Des bronches","Du larynx","Des sinus","Des amygdales"],"explication":"La bronchite est une inflammation des bronches avec production de mucus.","niveau":1,"bonne":0,"mnemo":"Bronchite = bronches."},{"q":"Quelle peut être l'origine d'une bronchite ?","options":["Virale ou bactérienne","Allergique uniquement","Toujours fongique","Toujours traumatique"],"explication":"La bronchite peut être d'origine virale ou bactérienne.","niveau":1,"bonne":0,"mnemo":"Virus ou bactérie."},{"q":"Avec quoi ne faut-il pas confondre la bronchite ?","options":["La bronchiolite du nourrisson","L'angine","La sinusite","L'otite séreuse"],"explication":"Ne pas confondre avec la bronchiolite du nourrisson, qui touche les bronchioles chez l'enfant de moins de 2 ans.","niveau":2,"bonne":0,"mnemo":"Bronchiole + <2 ans = bronchiolite."},{"q":"Quelle HE est conseillée pour soutenir les surrénales dans la bronchite ?","options":["Le cassis (gemmo) et les conifères","Le romarin","Le radis noir","La ronce"],"explication":"Le cassis et les conifères soutiennent les surrénales ; le romarin et le radis noir visent le foie, la ronce le pancréas.","niveau":3,"bonne":0,"mnemo":"Surrénales = cassis + conifères."},{"q":"Quel plante de la tisane pectorale est citée comme antitussive mais entraîne de la somnolence ?","options":["La violette","La guimauve","Le plantain","Le thym"],"explication":"La violette est antitussive et peut donner de la somnolence dans la tisane pectorale.","niveau":2,"bonne":0,"mnemo":"Violette = antitussive, somnolence."}],"dys-grippe":[{"q":"La grippe est due à quel type d'agent ?","options":["Un virus respiratoire","Une bactérie","Un champignon","Un parasite"],"explication":"La grippe est une maladie infectieuse contagieuse due à un virus respiratoire, à répercussions générales.","niveau":1,"bonne":0,"mnemo":"Grippe = virus respiratoire."},{"q":"À quel type de virus grippal correspond le rhume ?","options":["Le type C","Le type A","Le type B","Aucun type"],"explication":"Le type A donne les pandémies, le B des épidémies localisées, le C le rhume.","niveau":2,"bonne":0,"mnemo":"C comme... rhume (A pandémie, B épidémie)."},{"q":"Quelle plante adaptogène est citée pour la grippe ?","options":["L'éleuthérocoque","Le sureau","La mauve","Le plantain"],"explication":"Les plantes adaptogènes citées sont le ginseng et l'éleuthérocoque ; le sureau est antiviral/fébrifuge.","niveau":2,"bonne":0,"mnemo":"Adaptogènes = ginseng + éleuthérocoque."},{"q":"Quelle préparation homéopathique est citée en prévention de la grippe ?","options":["Influenzinum","Infludo®","L52","Tamiflu"],"explication":"En préventif : Influenzinum et Sérum de Yersin ; en curatif : Infludo® et L52. Le Tamiflu est l'antiviral médical.","niveau":3,"bonne":0,"mnemo":"Préventif = Influenzinum."},{"q":"Sur le plan émotionnel, quelle gestion est conseillée dans la grippe ?","options":["La gestion des émotions (colère, conflit)","La stimulation","L'exposition aux allergènes","Le jeûne prolongé"],"explication":"Le pilier émotionnel cible la gestion des émotions comme la colère et le conflit.","niveau":1,"bonne":0,"mnemo":"Émotionnel = colère/conflit."}],"dys-laryngite":[{"q":"Quelle structure est touchée par la laryngite ?","options":["Le larynx et les cordes vocales","Les bronches","Les sinus","Les amygdales"],"explication":"La laryngite est une inflammation du larynx, qui contient les cordes vocales.","niveau":1,"bonne":0,"mnemo":"Larynx = cordes vocales."},{"q":"Chez quel public la laryngite aiguë est-elle une urgence ?","options":["L'enfant","Le fumeur","La personne âgée","La femme enceinte"],"explication":"La forme aiguë est une urgence chez l'enfant ; la forme chronique concerne les fumeurs.","niveau":2,"bonne":0,"mnemo":"Aiguë = enfant (urgence), chronique = fumeur."},{"q":"Quelle plante est citée comme antispasmodique respiratoire dans la laryngite ?","options":["L'aunée","Le thym","Le plantain","L'ail"],"explication":"L'aunée est l'antispasmodique respiratoire ; le thym agit sur l'inflammation, l'ail est antiviral/antibactérien.","niveau":3,"bonne":0,"mnemo":"Aunée = antispasmodique."},{"q":"Quelle approche émotionnelle est associée à la laryngite ?","options":["Gestion du stress lié à la communication","Gestion de la colère digestive","Gestion de la peur du vide","Aucune"],"explication":"La laryngite est reliée à la souffrance liée à la communication, d'où la gestion de ce stress.","niveau":2,"bonne":0,"mnemo":"Voix = communication."},{"q":"Quel facteur favorisant de la laryngite est cité parmi les suivants ?","options":["Le RGO","Une carence en fer","Un excès de sommeil","La sédentarité"],"explication":"Parmi les facteurs : alcool, tabac, RGO et poussière.","niveau":1,"bonne":0,"mnemo":"Alcool, tabac, RGO, poussière."}],"dys-otite":[{"q":"Quelle forme d'otite n'est PAS douloureuse ?","options":["L'otite séreuse","L'otite externe","L'otite moyenne aiguë","L'otite interne"],"explication":"L'otite séreuse (liquide chronique derrière le tympan, perte d'audition) n'est pas douloureuse, contrairement à l'otite moyenne aiguë.","niveau":2,"bonne":0,"mnemo":"Séreuse = pas douloureuse."},{"q":"Quels symptômes caractérisent l'otite interne (labyrinthite) ?","options":["Vertiges, nausées, acouphènes","Douleur au pavillon","Écoulement de pus","Perte d'odorat"],"explication":"L'otite interne donne vertiges, flottement, nausées, surdité et acouphènes.","niveau":2,"bonne":0,"mnemo":"Interne = labyrinthe = vertiges."},{"q":"Dans quelle proportion l'otite moyenne est-elle d'origine bactérienne ?","options":["70%","10%","90%","30%"],"explication":"L'otite moyenne est d'origine bactérienne dans 70% des cas (le reste viral).","niveau":3,"bonne":0,"mnemo":"Moyenne = 70% bactérie."},{"q":"Quel geste de réflexologie est conseillé dans l'otite ?","options":["Masser entre les 2 derniers orteils","Masser la voûte plantaire","Masser le talon","Masser le pouce"],"explication":"On masse entre les 2 derniers orteils et la zone des sinus.","niveau":2,"bonne":0,"mnemo":"Derniers orteils = oreilles."},{"q":"Quel conseil de mode de vie est donné en cas d'otite ?","options":["Éviter de dormir sur l'oreille infectée","Dormir sur l'oreille infectée","Nager en eau froide","Prendre l'avion"],"explication":"On conseille d'éviter l'eau froide, l'avion et de dormir sur l'oreille infectée.","niveau":1,"bonne":0,"mnemo":"Pas d'eau froide, pas d'avion, pas sur l'oreille."}],"dys-rhinite":[{"q":"La rhinite allergique est-elle une infection ?","options":["Non, c'est une réaction immunitaire à un allergène","Oui, virale","Oui, bactérienne","Oui, fongique"],"explication":"Ce n'est pas une infection : c'est une réaction immunitaire excessive à un allergène avec libération d'histamine.","niveau":2,"bonne":0,"mnemo":"Allergie ≠ infection."},{"q":"Quel terrain digestif participe à la rhinite allergique ?","options":["La perméabilité intestinale","L'achlorhydrie","La lithiase biliaire","Le RGO"],"explication":"La perméabilité intestinale et une flore perturbée participent au terrain allergique.","niveau":1,"bonne":0,"mnemo":"Allergie = intestin perméable."},{"q":"Quel principe favorise paradoxalement les allergies selon la fiche ?","options":["L'excès d'hygiène","Le manque de sommeil","L'excès de sport","La carence en eau"],"explication":"Un excès d'hygiène et une flore déséquilibrée favorisent les allergies : il ne faut pas tomber dans l'excès d'hygiène.","niveau":3,"bonne":0,"mnemo":"Trop propre = plus d'allergies."},{"q":"Quelle molécule végétale est citée avec le curcuma dans la rhinite allergique ?","options":["La quercétine","La théophylline","La khella","La droséra"],"explication":"Les plantes citées sont le curcuma et la quercétine.","niveau":1,"bonne":0,"mnemo":"Curcuma + quercétine."},{"q":"Quel type de régime alimentaire est recommandé dans la rhinite allergique ?","options":["Anti-inflammatoire et méditerranéen","Hyperprotéiné","Riche en laitages","Riche en gluten"],"explication":"On recommande un régime anti-inflammatoire et méditerranéen, en évitant gluten et laitages.","niveau":2,"bonne":0,"mnemo":"Méditerranéen, sans gluten ni laitages."}],"dys-rhinopharyngite":[{"q":"Quelle zone anatomique est concernée par la rhino-pharyngite ?","options":["De la cavité nasale au pharynx","Les bronches","Les sinus uniquement","Le larynx uniquement"],"explication":"C'est une inflammation des voies aériennes supérieures, de la cavité nasale au pharynx.","niveau":1,"bonne":0,"mnemo":"Nez → pharynx."},{"q":"Pourquoi n'utilise-t-on pas d'antibiotique d'emblée dans la rhino-pharyngite ?","options":["Parce qu'elle est virale dans la grande majorité des cas","Parce qu'elle est fongique","Parce qu'elle est allergique","Parce qu'elle est bénigne et sans germe"],"explication":"Elle est virale dans la grande majorité (plus de 100 virus) : pas d'antibiotique d'emblée, traitement symptomatique.","niveau":2,"bonne":0,"mnemo":"Virus = pas d'antibio d'emblée."},{"q":"Quelle plante est citée comme sudorifique dans la rhino-pharyngite ?","options":["Le sureau","Le thym","La menthe","La sauge"],"explication":"Le sureau est sudorifique ; le thym diminue les sécrétions, la menthe est antalgique, la sauge agit sur la gorge.","niveau":3,"bonne":0,"mnemo":"Sureau = sudorifique."},{"q":"Quel organe est drainé avec pissenlit, radis noir, fumeterre et artichaut ?","options":["Le foie/vésicule","Le pancréas","La rate","L'intestin"],"explication":"Foie/vésicule : pissenlit, radis noir, fumeterre, artichaut ; pancréas : ronce, noyer ; rate : camomille, cresson.","niveau":2,"bonne":0,"mnemo":"Pissenlit/radis noir = foie."},{"q":"Quelle précaution est donnée pour les inhalations de menthe poivrée ?","options":["Pas chez les jeunes enfants","Uniquement le soir","Toujours diluée à l'eau froide","Pas chez l'adulte"],"explication":"En inhalation, la menthe poivrée est déconseillée chez les jeunes enfants.","niveau":1,"bonne":0,"mnemo":"Menthe poivrée : pas les petits."}],"dys-toux":[{"q":"Quelle structure est enflammée dans la trachéite ?","options":["La muqueuse de la trachée","Les sinus","Les amygdales","Le larynx"],"explication":"La trachéite est une inflammation de la muqueuse de la trachée.","niveau":1,"bonne":0,"mnemo":"Trachéite = trachée."},{"q":"En combien de temps régresse spontanément une trachéite aiguë ?","options":["Environ 3 semaines","Environ 3 jours","Environ 3 mois","Elle ne régresse jamais seule"],"explication":"La forme aiguë est bénigne et régresse spontanément en environ 3 semaines.","niveau":2,"bonne":0,"mnemo":"Aiguë = 3 semaines."},{"q":"Quelle précaution accompagne l'usage du cyprès dans la trachéite ?","options":["À éviter en cas de cancer hormono-dépendant","À éviter chez le sportif","À éviter le matin","À éviter en cas de fièvre"],"explication":"Le cyprès est anti-inflammatoire mais à éviter en cas de cancer hormono-dépendant.","niveau":3,"bonne":0,"mnemo":"Cyprès = pas si cancer hormono-dépendant."},{"q":"Quel geste pratique est conseillé car la toux s'aggrave en position allongée ?","options":["Rehausser les oreillers","Dormir à plat","Dormir sur le ventre","Supprimer l'oreiller"],"explication":"On rehausse les oreillers car la toux est aggravée en position allongée.","niveau":1,"bonne":0,"mnemo":"Allongé = pire → rehausser."},{"q":"Quelle HE de la trachéite est antispasmodique, mucolytique et décongestionnante ?","options":["La myrte rouge","L'eucalyptus radié","Le ravintsara","Le cyprès"],"explication":"La myrte rouge est antispasmodique, mucolytique et décongestionnante ; eucalyptus radié et ravintsara sont antiviraux.","niveau":2,"bonne":0,"mnemo":"Myrte rouge = spasme + mucus."}],"dys-sinusite":[{"q":"Au-delà de combien de semaines parle-t-on de sinusite chronique ?","options":["4 semaines","2 semaines","8 semaines","3 jours"],"explication":"La sinusite chronique se développe après une sinusite aiguë persistant plus de 4 semaines, plusieurs fois par an.","niveau":2,"bonne":0,"mnemo":"Chronique = > 4 semaines."},{"q":"Pourquoi les micro-organismes se développent-ils vite dans la sinusite ?","options":["Parce que le mucus n'est plus drainé","Parce que les sinus sont surventilés","Parce que le pH augmente","Parce que la fièvre les nourrit"],"explication":"L'inflammation rétrécit/obstrue les sinus : le mucus n'est plus drainé, ce qui favorise la prolifération microbienne.","niveau":2,"bonne":0,"mnemo":"Pas de drainage = prolifération."},{"q":"Que signifient souvent des sécrétions jaunes/verdâtres épaisses et purulentes ?","options":["Une infection bactérienne","Une allergie","Une guérison","Une rhinite virale bénigne"],"explication":"Des sécrétions purulentes jaunes/verdâtres sont souvent signe d'infection bactérienne, orientant vers le médecin.","niveau":3,"bonne":0,"mnemo":"Purulent = bactérie → médecin."},{"q":"À quelle fréquence conseille-t-on au minimum les lavages au sérum physiologique ?","options":["Au moins 2 fois par jour","1 fois par semaine","1 fois par jour","Toutes les heures"],"explication":"On recommande mouchages doux et lavages au sérum physiologique au minimum 2x/jour.","niveau":1,"bonne":0,"mnemo":"Lavage 2x/j minimum."},{"q":"Quelle pratique respiratoire est proposée pour la sinusite ?","options":["Les respirations alternées (narines droite/gauche)","L'apnée prolongée","La respiration buccale forcée","L'hyperventilation rapide"],"explication":"La yogathérapie propose respirations complètes régulières et respirations alternées des narines droite/gauche.","niveau":1,"bonne":0,"mnemo":"Narines alternées = yoga."}],"temp-colerique":[{"q":"Quel élément et quelle qualité caractérisent le Bilieux (colérique) ?","options":["Eau, froid et humide","Feu, chaud et sec","Air, chaud et humide","Terre, froid et sec"],"explication":"Le colérique correspond à l'élément Feu, avec les qualités chaud et sec.","niveau":1,"bonne":1,"mnemo":"Colérique = Feu qui brûle SEC : chaud-sec."},{"q":"D'après ce portrait — âme de chef autoritaire, entreprenant, organisé, qui se met en colère facilement, longiligne et musclé —, quel tempérament ?","options":["Le Sanguin","Le Lymphatique","Le Bilieux (colérique)","Le Nerveux (mélancolique)"],"explication":"L'âme de chef autoritaire qui s'enflamme, le physique musclé et longiligne, désignent le colérique.","niveau":1,"bonne":2,"mnemo":"Le chef qui s'enflamme."},{"q":"Quel régime alimentaire est préféré pour le colérique ?","options":["Chaud et sec","Froid et humide","Chaud et humide","Froid et sec"],"explication":"On conseille un régime froid et humide pour tempérer sa qualité dominante chaud-sec.","niveau":2,"bonne":1,"mnemo":"On compense : chaud-sec → froid-humide."},{"q":"Quelles sont les caractéristiques du pouls du colérique ?","options":["Lent (60-70/mn), petit volume","Lent (60-70/mn), volume normal","Rapide (80-100/mn), volume normal","Normal (70-80/mn), grand volume"],"explication":"Le colérique a un pouls rapide (80-100/mn) de volume normal, en lien avec sa nature chaude et son SNA sympathique en hyper.","niveau":2,"bonne":2,"mnemo":"Feu = pouls rapide."},{"q":"Un sujet a une poignée de main tonique, ferme et musculeuse (contact chaud et sec), une peau pâle jaunâtre sèche et chaude : à quel tempérament le rattacher, et de quel autre type faut-il le distinguer ?","options":["Au Sanguin, à distinguer du colérique","Au colérique, à distinguer du Sanguin (chaud mais humide, poignée puissante et chaleureuse)","Au Lymphatique, à distinguer du mélancolique","Au mélancolique, à distinguer du Lymphatique"],"explication":"Poignée tonique/sèche et peau sèche et chaude = colérique (chaud ET sec). On le distingue du Sanguin, chaud mais HUMIDE, à la poignée puissante et chaleureuse (contact chaud et doux).","niveau":3,"bonne":1,"mnemo":"Colérique = chaud SEC ; Sanguin = chaud HUMIDE."}],"temp-flegmatique":[{"q":"À quelle saison et à quel âge de la vie associe-t-on le Lymphatique (flegmatique) ?","options":["Été, jeunesse","Hiver, vieillesse","Printemps, enfance","Automne, âge mûr"],"explication":"Le flegmatique est associé à l'hiver et à la vieillesse, cohérent avec son élément Eau, froid et humide.","niveau":2,"bonne":1,"mnemo":"Eau froide = hiver, lenteur de la vieillesse."},{"q":"D'après ce portrait — calme, imperturbable, nonchalant, lent, peu émotif, en surpoids, démarche lente —, quel tempérament ?","options":["Le Bilieux (colérique)","Le Sanguin","Le Lymphatique (flegmatique)","Le Nerveux (mélancolique)"],"explication":"Le calme imperturbable, la lenteur, la nonchalance et le surpoids mou décrivent le lymphatique.","niveau":1,"bonne":2,"mnemo":"Lent comme l'eau stagnante."},{"q":"Quelle caractéristique de sommeil est typique du flegmatique ?","options":["Insomnie / troubles de l'endormissement","Sommeil excessif","Sommeil inadéquat par rapport aux besoins","Sommeil normal (6 à 8h)"],"explication":"Le lymphatique a un sommeil excessif, en cohérence avec sa nature lente et froid-humide.","niveau":2,"bonne":1,"mnemo":"Eau qui dort beaucoup."},{"q":"Quelle est la couleur de peau caractéristique du lymphatique ?","options":["Rouge congestive","Pourpre noire/grise","Pâle jaunâtre","Blanchâtre crayeuse"],"explication":"La peau du flegmatique est blanchâtre crayeuse (sa couleur est sans couleur / blanc).","niveau":1,"bonne":3,"mnemo":"Lymphe blanche, peau crayeuse."},{"q":"Une personne a une poignée de main molle et glissante, une peau crayeuse froide : on hésite entre lymphatique et nerveux (mélancolique). Qu'est-ce qui tranche pour le lymphatique ?","options":["Il est froid et HUMIDE (Eau, phlegme), peau crayeuse, alors que le mélancolique est froid et SEC (Terre, bile noire, peau sèche)","Il est chaud et sec, élément Feu","Il a un pouls rapide à grand volume","Il a une démarche rapide à petits pas"],"explication":"Tous deux sont froids, mais le flegmatique est HUMIDE (Eau, phlegme, peau crayeuse, poignée molle/glissante) tandis que le mélancolique est SEC (Terre, bile noire, peau sèche, poignée courte/agitée).","niveau":3,"bonne":0,"mnemo":"Froid humide = Eau ; froid sec = Terre."}],"temp-melancolique":[{"q":"Quel élément et quelle humeur correspondent au Nerveux (mélancolique) ?","options":["Feu, bile jaune","Air, sang","Terre, bile noire (atrabile)","Eau, phlegme"],"explication":"Le mélancolique correspond à l'élément Terre et à l'humeur bile noire (atrabile).","niveau":1,"bonne":2,"mnemo":"Terre sombre, bile NOIRE."},{"q":"D'après ce portrait — petit, mince, visage triangulaire, frileux, anxieux, perfectionniste, introverti, démarche rapide à petits pas —, quel tempérament ?","options":["Le Sanguin","Le Nerveux (mélancolique)","Le Bilieux (colérique)","Le Lymphatique"],"explication":"Le physique petit/mince/frileux, l'anxiété réfléchie et le perfectionnisme introverti caractérisent le mélancolique.","niveau":1,"bonne":1,"mnemo":"Sombre, sec, perfectionniste inquiet."},{"q":"Quel régime alimentaire est préféré pour le mélancolique ?","options":["Froid et humide","Froid et sec","Chaud et humide","Chaud et sec"],"explication":"On conseille un régime chaud et humide pour contrebalancer sa qualité dominante froid-sec.","niveau":2,"bonne":2,"mnemo":"Froid-sec → on compense par chaud-humide."},{"q":"Quel système et quel trouble du sommeil sont les points faibles tendanciels du nerveux (mélancolique) ?","options":["Système digestif et sommeil excessif","Foie et sommeil inadéquat","Système nerveux et insomnie / troubles de l'endormissement","Appareil circulatoire et sommeil normal"],"explication":"Le mélancolique a pour points faibles le système nerveux, avec insomnie / troubles de l'endormissement et tendance à la dépression.","niveau":2,"bonne":2,"mnemo":"Nerfs à vif = insomnie."},{"q":"À quelle saison, quelle couleur et quel organe (Steiner) le mélancolique est-il associé ?","options":["Automne, noir, poumon","Hiver, blanc, foie","Été, jaune, cœur","Printemps, rouge, rein"],"explication":"Le mélancolique est associé à l'automne, à la couleur noire et à l'organe poumon (Steiner).","niveau":3,"bonne":0,"mnemo":"Automne sombre, bile noire, poumon."}],"temp-sanguin-hippo":[{"q":"D'après ce portrait — gai, jovial, chaleureux, bon vivant, expansif, recherche du plaisir, marche rapide —, quel tempérament hippocratique ?","options":["Le Bilieux (colérique)","Le Sanguin","Le Nerveux (mélancolique)","Le Lymphatique"],"explication":"La gaieté chaleureuse, l'expansivité de bon vivant désignent le sanguin.","niveau":1,"bonne":1,"mnemo":"Le bon vivant qui rit."},{"q":"Quelle humeur correspond au sanguin ?","options":["Le sang (mélange des 4 humeurs)","La bile jaune","La bile noire","Le phlegme / lymphe"],"explication":"Le sanguin correspond à l'humeur sang, considérée comme un excès de sang et un mélange des quatre humeurs.","niveau":1,"bonne":0,"mnemo":"Sang ROUGE."},{"q":"Quel régime alimentaire est préféré pour le sanguin ?","options":["Chaud et humide","Froid et humide","Froid et sec","Chaud et sec"],"explication":"On conseille un régime froid et sec pour contrebalancer sa qualité dominante chaud-humide.","niveau":2,"bonne":2,"mnemo":"Chaud-humide → on compense par froid-sec."},{"q":"Quelles sont les caractéristiques du pouls du sanguin ?","options":["Rapide (80-100/mn), volume normal","Lent (60-70/mn), petit volume","Normal (70-80/mn), grand volume","Lent (60-70/mn), volume normal"],"explication":"Le sanguin a un pouls normal (70-80/mn) mais de grand volume, en cohérence avec son excès de sang.","niveau":3,"bonne":2,"mnemo":"Grand volume = beaucoup de sang."},{"q":"Une personne a une poignée de main puissante, longue et chaleureuse (contact chaud et doux), une peau chaude rouge et congestive : à quel type la rattacher et de quel type la distinguer ?","options":["Au colérique, à distinguer du sanguin","Au sanguin, à distinguer du colérique (chaud mais SEC, poignée tonique, peau sèche)","Au lymphatique, à distinguer du mélancolique","Au mélancolique, à distinguer du sanguin"],"explication":"Poignée puissante et chaleureuse (chaud et doux) + peau rouge congestive = sanguin (chaud et HUMIDE). On le distingue du colérique, chaud mais SEC, à la poignée tonique et la peau sèche.","niveau":3,"bonne":1,"mnemo":"Sanguin = chaud humide doux ; colérique = chaud sec tonique."}],"temp-musculaire":[{"q":"D'après cette description — visage carré/rectangulaire, teint coloré, non frileux, morphotype tonique et équilibré — de quel tempérament de Marchesseau s'agit-il ?","options":["Le Sanguin","Le Cérébral","Le Musculaire","Le Digestif"],"explication":"Le visage carré/rectangulaire au teint coloré, robuste et non frileux, décrit le Musculaire.","niveau":1,"bonne":2,"mnemo":"Visage carré d'athlète."},{"q":"À quel grand groupe morphologique appartient le Musculaire ?","options":["Dilatés (sanguino-pléthoriques)","Rétractés (neuro-arthritiques)","Obèses dilatés","Cérébraux purs"],"explication":"Le Musculaire fait partie des rétractés (neuro-arthritiques), groupe à fragilité nerveuse, déminéralisation et terrain arthrose/rhumatismes.","niveau":2,"bonne":1,"mnemo":"Musculaire = rétracté neuro-arthritique."},{"q":"Comment le Musculaire supporte-t-il la température de l'eau ?","options":["Il ne supporte que l'eau chaude (frileux)","Il ne supporte que l'eau froide","Il supporte indifféremment l'eau chaude ou froide (non frileux)","L'hydrothérapie lui est déconseillée"],"explication":"Le Musculaire n'est pas frileux et supporte l'eau chaude comme froide.","niveau":1,"bonne":2,"mnemo":"Robuste, indifférent au chaud comme au froid."},{"q":"Vers quels tempéraments le Musculaire peut-il basculer en cas de stress non géré ?","options":["Vers le sanguin","Vers respiratoire ou cérébral","Vers le digestif ou l'obèse rouge","Vers l'obèse blanc"],"explication":"En cas de stress non géré, le Musculaire risque de basculer vers le respiratoire ou le cérébral (l'excès alimentaire, lui, le fait évoluer vers le sanguin).","niveau":2,"bonne":1,"mnemo":"Stress → respiratoire/cérébral ; excès → sanguin."},{"q":"On voit un sujet robuste : faut-il le classer Musculaire ou Sanguin (de Marchesseau) ?","options":["Musculaire si visage carré, teint coloré, c'est un rétracté ; Sanguin si visage plein/puissant menton dominant, teint rosé, c'est un dilaté","Toujours Sanguin car les deux sont robustes","Toujours Musculaire car les deux ont un teint coloré","Impossible de les distinguer"],"explication":"Le Musculaire (visage carré, teint coloré) est un rétracté, alors que le Sanguin (visage plein/puissant, menton et bas dominants, teint rosé) est un dilaté.","niveau":3,"bonne":0,"mnemo":"Carré rétracté ≠ plein dilaté."}],"temp-respiratoire":[{"q":"D'après cette description — menton faible (volume inférieur diminué), teint légèrement coloré, très forte vitalité, élimination par la peau et les poumons — de quel tempérament s'agit-il ?","options":["Le Cérébral","Le Respiratoire","Le Digestif","Le Sanguin"],"explication":"Menton faible, très forte vitalité et élimination par peau/poumons caractérisent le Respiratoire.","niveau":1,"bonne":1,"mnemo":"Élimine par le souffle et la peau."},{"q":"Par quelles voies le Respiratoire élimine-t-il ses toxines, du fait de sa forte vitalité ?","options":["Par les reins et l'intestin","Par la peau (acné, eczéma) et les poumons (rhume, bronchite, sinusite)","Par le foie uniquement","Il n'élimine pas, il accumule"],"explication":"Sa très forte vitalité pousse l'élimination par la peau (acné, eczéma) et les poumons (rhume, bronchite, sinusite), avec parfois des crises curatives violentes.","niveau":2,"bonne":1,"mnemo":"Peau + poumons = ses émonctoires."},{"q":"Le Respiratoire est-il frileux ?","options":["Oui, frilosité extrême","Oui, surtout aux extrémités","Peu frileux : il se réchauffe dans l'action","Frileux uniquement l'hiver"],"explication":"Le Respiratoire est peu frileux et se réchauffe dans l'action.","niveau":1,"bonne":2,"mnemo":"Énergie haute = peu frileux."},{"q":"Quel type d'activité physique est indispensable au Respiratoire ?","options":["Aucun sport","Le sport d'endurance","Uniquement les exercices lents (yoga)","Les sports de force exclusivement"],"explication":"Le sport d'endurance est indispensable au Respiratoire.","niveau":2,"bonne":1,"mnemo":"Endurance pour le souffle."},{"q":"On hésite entre Respiratoire et Cérébral : qu'est-ce qui oriente vers le Respiratoire ?","options":["Vitalité moindre, frilosité importante, teint pâle grisâtre","Très forte vitalité, peu frileux, élimine par peau/poumons","Visage triangulaire pointe au menton","Digestion la plus faible de tous"],"explication":"Le Respiratoire a une très forte vitalité et est peu frileux (élimine par peau/poumons), alors que le Cérébral a une vitalité moindre, une frilosité importante, un teint pâle grisâtre et une digestion encore plus faible.","niveau":3,"bonne":1,"mnemo":"Respiratoire = vitalité haute ; Cérébral = vitalité basse et frileux."}],"temp-cerebral":[{"q":"D'après cette description — visage triangulaire à pointe au menton, haut dominant, teint pâle grisâtre, frilosité importante aux extrémités — de quel tempérament s'agit-il ?","options":["Le Respiratoire","Le Cérébral","Le Musculaire","Le Digestif"],"explication":"Le visage triangulaire pointe au menton (haut dominant), pâle grisâtre et frileux, décrit le Cérébral.","niveau":1,"bonne":1,"mnemo":"Triangle pointe en bas, gros front."},{"q":"Comment se compare la capacité digestive du Cérébral à celle du Respiratoire ?","options":["Identique","Encore plus faible que le respiratoire → limiter les quantités","Bien meilleure que le respiratoire","Excellente comme le sanguin"],"explication":"La capacité digestive du Cérébral est encore plus faible que celle du Respiratoire, d'où le conseil de limiter les quantités.","niveau":2,"bonne":1,"mnemo":"Cérébral = digestion plus faible encore."},{"q":"Quelles plantes sont conseillées au Cérébral ?","options":["Artichaut et chrysanthellum","Romarin et pissenlit","Mélisse, camomille, gentiane","Passiflore, aubépine, valériane"],"explication":"On conseille au Cérébral la mélisse, la camomille et la gentiane.","niveau":2,"bonne":2,"mnemo":"Mélisse-camomille-gentiane pour le cerveau."},{"q":"Quels apports en micronutrition sont notés comme des besoins du Cérébral ?","options":["Vitamine C et fer","Vitamines B et acides gras essentiels","Eau de mer et pollen","Magnésium et zinc"],"explication":"Le Cérébral a des besoins en vitamines B et en acides gras essentiels.","niveau":1,"bonne":1,"mnemo":"Vitamines B + AGE pour le système nerveux."},{"q":"Cérébral ou Nerveux ? Qu'est-ce qui distingue le Cérébral du Nerveux ?","options":["Le Cérébral a un visage triangulaire pointe au menton et un teint pâle grisâtre, vitalité un peu meilleure ; le Nerveux a un visage vertical/osseux/longiligne, teint verdâtre, vitalité plus faible (aggravation du Cérébral)","Le Cérébral n'est jamais frileux contrairement au Nerveux","Le Cérébral est un dilaté, le Nerveux un rétracté","Ils sont identiques"],"explication":"Le Nerveux est une aggravation du Cérébral : visage vertical/osseux/longiligne, teint verdâtre, frilosité plus extrême et vitalité plus faible, tandis que le Cérébral a un visage triangulaire pointe au menton, un teint pâle grisâtre et une vitalité un peu meilleure.","niveau":3,"bonne":0,"mnemo":"Nerveux = Cérébral aggravé (plus maigre, plus froid, plus faible)."},{"q":"D'après ce portrait — haut du visage dominant, milieu et bas rétractés, pointe au menton — quel tempérament de Marchesseau ?","options":["Le Cérébral","Le Sanguin","Le Digestif","Le Musculaire"],"explication":"Le Cérébral a un visage triangulaire avec pointe au menton, haut dominant et milieu/bas rétractés (aptitude cérébrale prononcée).","niveau":1,"bonne":0,"mnemo":"Triangle pointe en bas = gros front, petit menton = Cérébral."},{"q":"À quel grand groupe morphologique le Cérébral appartient-il ?","options":["Les rétractés (neuro-arthritiques)","Les dilatés (sanguino-pléthoriques)","Les sanguino-pléthoriques","Aucun groupe"],"explication":"Le Cérébral est un rétracté (neuro-arthritique), comme le musculaire, le respiratoire, le nerveux et le grand nerveux.","niveau":1,"bonne":0,"mnemo":"Rétracté = mince, pâle, terrain acide."},{"q":"Quelle hydrothérapie est bénéfique au Cérébral ?","options":["Les bains chauds","Les bains froids","Les douches glacées","Aucune hydrothérapie"],"explication":"Le Cérébral étant très frileux (surtout aux extrémités), les bains chauds lui sont bénéfiques.","niveau":2,"bonne":0,"mnemo":"Frileux = chaleur = bains chauds."},{"q":"Quel conseil alimentaire correspond au Cérébral ?","options":["Limiter laitages, protéines, viande rouge, sucres et agrumes","Augmenter fortement les protéines","Manger beaucoup d'agrumes le matin","Régime riche en viande rouge"],"explication":"Le Cérébral, à digestion faible et terrain acide, doit limiter laitages, protéines, viande rouge, sucres et agrumes (même le citron) et pas trop de féculents.","niveau":2,"bonne":0,"mnemo":"Digestion faible = on allège et on désacidifie."},{"q":"Pourquoi le Nerveux est-il considéré comme une aggravation du Cérébral, et non l'inverse ?","options":["Le Nerveux a une vitalité plus faible, est plus maigre et plus frileux que le Cérébral","Le Nerveux a une meilleure digestion que le Cérébral","Le Nerveux est un dilaté plus marqué","Le Nerveux a un teint plus rosé"],"explication":"Le Nerveux (visage vertical/osseux, teint verdâtre, frilosité extrême, vitalité très faible) pousse à l'extrême les fragilités du Cérébral ; plus on va vers le Nerveux, plus la personne est maigre et fragile.","niveau":3,"bonne":0,"mnemo":"Cérébral poussé à l'extrême = Nerveux."}],"temp-nerveux":[{"q":"D'après ce portrait — visage vertical, osseux, longiligne, parmi les plus maigres, teint verdâtre — quel tempérament de Marchesseau ?","options":["Le Nerveux","Le Cérébral","Le Sanguin","L'Obèse Blanc"],"explication":"Le Nerveux a un visage vertical, osseux, longiligne, rétracté du haut en bas, teint très pâle verdâtre, parmi les morphotypes les plus maigres.","niveau":1,"bonne":0,"mnemo":"Visage en barre verticale, glacial = Nerveux."},{"q":"Quelle alimentation convient au Nerveux ?","options":["Manger chaud et cuit, limiter aliments froids et crus et fruits acides","Manger surtout cru et froid","Beaucoup de fruits acides le matin en hiver","Régime hyperprotéiné froid"],"explication":"Le Nerveux doit manger chaud et cuit, limiter les aliments froids et crus, et limiter les fruits acides (surtout le matin en hiver).","niveau":1,"bonne":0,"mnemo":"Toujours froid = on mange chaud et cuit."},{"q":"Quelle hydrothérapie convient au Nerveux ?","options":["Hydrothérapie chaude (bains hyperthermiques, sauna, hammam)","Bains glacés","Douches froides quotidiennes","Aucune chaleur"],"explication":"Le Nerveux ayant toujours froid bénéficie d'une hydrothérapie chaude : bains hyperthermiques, sauna, hammam.","niveau":2,"bonne":0,"mnemo":"Glacial = chaleur intense."},{"q":"Quelles plantes sont conseillées au Nerveux ?","options":["Les mêmes que le Cérébral (mélisse, camomille, gentiane)","Artichaut et chrysanthellum","Aubier de tilleul et radis noir","Plantes diurétiques et circulatoires"],"explication":"Le Nerveux étant une aggravation du Cérébral, il reçoit les mêmes plantes : mélisse, camomille, gentiane.","niveau":2,"bonne":0,"mnemo":"Nerveux = Cérébral aggravé → mêmes plantes."},{"q":"Le Nerveux et le Grand Nerveux partagent leur faiblesse digestive ; comment se situent leurs capacités par rapport au Cérébral ?","options":["Encore moindres que celles du Cérébral","Meilleures que celles du Cérébral","Identiques à celles du Sanguin","Excellentes comme chez les dilatés"],"explication":"Les capacités digestives et respiratoires du Nerveux sont encore moindres que celles du Cérébral, avec acidose excessive et grande oxydation.","niveau":3,"bonne":0,"mnemo":"Plus on va vers le Nerveux, plus la digestion s'effondre."}],"temp-grand-nerveux":[{"q":"D'après ce portrait — visage émacié type saturnien, le plus rétracté de tous, teint plombé — quel tempérament ?","options":["Le Grand Nerveux","Le Nerveux","Le Cérébral","L'Obèse Blanc"],"explication":"Le Grand Nerveux a un visage émacié de type saturnien, c'est la forme la plus extrême/rétractée des neuro-arthritiques, teint verdâtre plombé.","niveau":1,"bonne":0,"mnemo":"Saturnien émacié = Grand Nerveux."},{"q":"Quel type d'alimentation est recommandé au Grand Nerveux ?","options":["Petits repas chauds et réguliers, sans régime restrictif","Régime restrictif strict","Jeûnes prolongés réguliers","Repas froids et crus"],"explication":"On recommande des petits repas chauds et réguliers et on évite absolument les régimes restrictifs (risque de déminéralisation).","niveau":1,"bonne":0,"mnemo":"Vital au plus bas = jamais restreindre, petits repas chauds."},{"q":"Quels reminéralisants sont conseillés au Grand Nerveux ?","options":["Ortie et prêle","Artichaut et chrysanthellum","Radis noir et aubier de tilleul","Plantes diurétiques"],"explication":"Face aux carences minérales très importantes, on conseille ortie et prêle (reminéralisants), ainsi qu'eau de mer, vitamines B et pollen.","niveau":2,"bonne":0,"mnemo":"Carences majeures = ortie + prêle reminéralisants."},{"q":"Quelles plantes calmantes sont conseillées au Grand Nerveux ?","options":["Passiflore, aubépine, valériane","Mélisse, camomille, gentiane","Artichaut, chrysanthellum","Romarin et pissenlit"],"explication":"Face à la nervosité extrême, on conseille passiflore, aubépine et valériane (calmantes), en plus des reminéralisants.","niveau":2,"bonne":0,"mnemo":"Nervosité extrême = passiflore + aubépine + valériane."},{"q":"Pourquoi faut-il éviter absolument les régimes restrictifs chez le Grand Nerveux ?","options":["À cause du risque de déminéralisation (carences déjà majeures)","Parce qu'il a une digestion excellente","Parce qu'il n'a jamais froid","Parce qu'il fait de la rétention d'eau"],"explication":"Le Grand Nerveux présente des carences minérales très importantes et un potentiel digestif épuisé : un régime restrictif aggraverait la déminéralisation. La reminéralisation est indispensable.","niveau":3,"bonne":0,"mnemo":"Carences majeures + digestion épuisée = reminéraliser, pas restreindre."}],"temp-sanguin":[{"q":"D'après ce portrait — visage plein/puissant/tonique, menton et bas dominants, teint rosé coloré, n'a jamais froid — quel tempérament de Marchesseau ?","options":["Le Sanguin","Le Cérébral","Le Nerveux","L'Obèse Blanc"],"explication":"Le Sanguin a un visage plein, puissant, tonique, menton et bas dominants, teint rosé (richesse capillaire), n'a jamais froid.","niveau":1,"bonne":0,"mnemo":"Visage plein et rosé qui n'a jamais froid = Sanguin."},{"q":"À quel grand groupe morphologique le Sanguin appartient-il ?","options":["Les dilatés (sanguino-pléthoriques)","Les rétractés (neuro-arthritiques)","Les neuro-arthritiques","Aucun groupe"],"explication":"Le Sanguin est un dilaté (sanguino-pléthorique), avec des aptitudes digestives et émonctorielles puissantes.","niveau":1,"bonne":0,"mnemo":"Visage dilaté, coloré = sanguino-pléthorique."},{"q":"Quelle est la faiblesse organique principale du Sanguin ?","options":["Le système cardio-vasculaire","Le système nerveux","La digestion","L'élimination par les émonctoires"],"explication":"Le Sanguin digère et élimine très bien, mais son sang trop chargé de toxines fatigue les vaisseaux : faiblesse cardio-vasculaire (varices, cholestérol, infarctus, athérosclérose).","niveau":2,"bonne":0,"mnemo":"Tout digère bien, mais le cœur et les vaisseaux fatiguent."},{"q":"Quelle approche est privilégiée en première intention chez le Sanguin ?","options":["La réforme alimentaire","Le jeûne strict","La psychothérapie","L'hydrothérapie chaude"],"explication":"Chez le Sanguin, on pose une réforme alimentaire en première intention (limiter alcool et graisses saturées, alimentation cardioprotectrice).","niveau":2,"bonne":0,"mnemo":"Sanguin = réforme alimentaire d'abord."},{"q":"Qu'indique la dominance du bas du visage chez le Sanguin ?","options":["Une forte aptitude digestive","Une forte aptitude cérébrale","Une faiblesse digestive","Une frilosité importante"],"explication":"Dans la lecture du visage, le bas (menton) traduit l'aptitude digestive : le Sanguin, à menton et bas dominants, a une digestion excellente.","niveau":3,"bonne":0,"mnemo":"Bas du visage = digestion ; haut = cerveau."}],"temp-digestif":[{"q":"D'après ce portrait — visage rond/ovale congestif, double menton, teint cramoisi couperosé, a toujours chaud, obésité du ventre — quel tempérament ?","options":["Le Digestif","Le Sanguin","L'Obèse Blanc","Le Cérébral"],"explication":"Le Digestif a un visage rond/ovale congestif avec double menton, teint cramoisi/couperosé, a toujours chaud, avec tendance à l'obésité du ventre (jambes fines).","niveau":1,"bonne":0,"mnemo":"Visage rond congestif, double menton, gros ventre = Digestif."},{"q":"Quel drainage est régulièrement conseillé au Digestif ?","options":["Le drainage hépatique","Le drainage rénal seul","Le drainage pulmonaire","Aucun drainage"],"explication":"Le Digestif nécessite un drainage hépatique régulier (aubier de tilleul, radis noir, artichaut).","niveau":1,"bonne":0,"mnemo":"Digestif congestif = on draine le foie."},{"q":"Comment se comparent les capacités digestives du Digestif à celles du Sanguin ?","options":["Plus faibles que celles du Sanguin","Meilleures que celles du Sanguin","Identiques à celles du Sanguin","Nulles"],"explication":"Le Digestif a des capacités glandulaires et digestives plus faibles que le Sanguin, et ses éliminations sont moins bonnes.","niveau":2,"bonne":0,"mnemo":"Digestif = un Sanguin à digestion et éliminations affaiblies."},{"q":"À quel grand groupe appartient le Digestif, et quel conseil de mouvement le concerne ?","options":["Dilatés ; exercice indispensable à intégrer dans l'emploi du temps","Rétractés ; activité douce seulement","Dilatés ; aucun exercice","Rétractés ; hydrothérapie froide"],"explication":"Le Digestif est un dilaté (sanguino-pléthorique) ; l'exercice lui est indispensable et doit être intégré dans son emploi du temps.","niveau":2,"bonne":0,"mnemo":"Dilaté gourmand = bouger absolument."},{"q":"Quel conseil alimentaire correspond au Digestif ?","options":["Réduire la charge globale et augmenter fruits et légumes crus","Augmenter fortement les protéines","Manger surtout chaud et cuit, éviter les crudités","Régime hypercalorique"],"explication":"Chez le Digestif (dilaté, tendance obésité), on réduit la charge alimentaire globale et on augmente les fruits et légumes crus.","niveau":3,"bonne":0,"mnemo":"Dilaté en surcharge = alléger + plus de cru."}],"temp-obese-rouge":[{"q":"D'après ce portrait — visage rond et jovial, teint rouge brillant, tissus dilatés, n'a jamais froid, rétention d'eau et cellulite — quel tempérament ?","options":["L'Obèse Rouge","L'Obèse Blanc","Le Digestif","Le Sanguin"],"explication":"L'Obèse Rouge a un visage rond jovial, teint rouge souvent brillant, tissus dilatés, n'a jamais froid, avec rétention d'eau et cellulite.","niveau":1,"bonne":0,"mnemo":"Rond et rouge, jamais froid = Obèse Rouge."},{"q":"Par quelle eau l'Obèse Rouge doit-il s'équilibrer ?","options":["L'eau froide (surtout pas chaude)","L'eau chaude","Les bains hyperthermiques","Indifféremment chaude ou froide"],"explication":"L'Obèse Rouge s'équilibre par l'eau froide (surtout pas chaude) ; l'hydrothérapie chaude est déconseillée en raison des risques cardiaques.","niveau":1,"bonne":0,"mnemo":"Rouge = chaud → on rafraîchit à l'eau froide."},{"q":"Quelles plantes sont conseillées à l'Obèse Rouge ?","options":["Plantes circulatoires, diurétiques et agrumes","Mélisse, camomille, gentiane","Ortie et prêle reminéralisantes","Romarin et pissenlit"],"explication":"On conseille à l'Obèse Rouge des plantes circulatoires, diurétiques et des agrumes (fruits acides).","niveau":2,"bonne":0,"mnemo":"Rétention d'eau = diurétiques + circulatoires."},{"q":"Pourquoi l'hydrothérapie chaude est-elle déconseillée à l'Obèse Rouge ?","options":["À cause des risques cardiaques","Parce qu'il a toujours froid","Parce qu'il manque de minéraux","Parce que sa digestion est excellente"],"explication":"L'hydrothérapie chaude est déconseillée à l'Obèse Rouge en raison des risques cardiaques (troubles cardio-vasculaires, cholestérol) : on privilégie l'eau froide.","niveau":2,"bonne":0,"mnemo":"Cœur fragile + déjà chaud = pas de chaud."},{"q":"Qu'est-ce qui distingue principalement l'Obèse Rouge de l'Obèse Blanc ?","options":["Le Rouge n'a jamais froid (eau froide), le Blanc a une frilosité extrême (eau chaude)","Le Rouge est un rétracté, le Blanc un dilaté","Le Rouge a une force vitale faible, le Blanc une forte vitalité","Le Rouge a un teint pâle, le Blanc un teint rouge"],"explication":"L'Obèse Rouge (teint rouge brillant, n'a jamais froid, eau froide) s'oppose à l'Obèse Blanc (teint pâle atone, frilosité extrême, eau chaude). Rouge = chaud ; Blanc = froid et épuisé.","niveau":3,"bonne":0,"mnemo":"Rouge = chaud/eau froide ; Blanc = froid/eau chaude."}],"temp-obese-blanc":[{"q":"D'après ce portrait — visage rond soufflé poupin, teint pâle atone, frilosité extrême, force vitale faible — quel tempérament ?","options":["L'Obèse Blanc","L'Obèse Rouge","Le Digestif","Le Grand Nerveux"],"explication":"L'Obèse Blanc a un visage rond soufflé poupin, teint pâle atone, frilosité extrême, force vitale faible et épuisement métabolique.","niveau":1,"bonne":0,"mnemo":"Rond soufflé et pâle, toujours gelé = Obèse Blanc."},{"q":"Par quelle eau l'Obèse Blanc doit-il s'équilibrer ?","options":["L'eau chaude (bains d'eau chaude)","L'eau froide","Les douches glacées","Aucune eau"],"explication":"L'Obèse Blanc, frileux à l'extrême, s'équilibre par l'eau chaude (bains d'eau chaude, mais attention aux risques cardiaques).","niveau":1,"bonne":0,"mnemo":"Blanc = froid → eau chaude."},{"q":"Quelle alimentation convient à l'Obèse Blanc ?","options":["Petits repas chauds, très digestes et réguliers","Repas froids et crus en abondance","Jeûnes prolongés","Régime hyperprotéiné froid"],"explication":"L'Obèse Blanc, à force vitale faible et épuisement métabolique, a besoin de petits repas chauds, très digestes et réguliers, avec un régime adapté.","niveau":2,"bonne":0,"mnemo":"Vitalité faible + frileux = petits repas chauds et digestes."},{"q":"À quel grand groupe l'Obèse Blanc appartient-il, malgré sa faiblesse vitale ?","options":["Les dilatés (sanguino-pléthoriques), mais épuisé","Les rétractés (neuro-arthritiques)","Les neuro-arthritiques épuisés","Aucun groupe"],"explication":"Malgré sa force vitale faible, l'Obèse Blanc reste un dilaté (sanguino-pléthorique), mais en version épuisée.","niveau":2,"bonne":0,"mnemo":"Visage rond dilaté = sanguino-pléthorique, ici épuisé."},{"q":"Pourquoi l'Obèse Blanc et l'Obèse Rouge, tous deux dilatés, reçoivent-ils des conseils d'hydrothérapie opposés ?","options":["Parce que le Blanc est froid/épuisé (eau chaude) et le Rouge chaud/pléthorique (eau froide)","Parce que le Blanc est un rétracté et le Rouge un dilaté","Parce que le Blanc digère mieux que le Rouge","Parce que le Rouge est frileux et le Blanc non"],"explication":"Bien que tous deux dilatés, l'Obèse Blanc est froid et épuisé (eau chaude bénéfique) tandis que l'Obèse Rouge est chaud et pléthorique (eau froide, hydrothérapie chaude déconseillée).","niveau":3,"bonne":0,"mnemo":"Même groupe, chaleur opposée : Blanc=chaud, Rouge=froid."}]};
